XRAY_URL="https://github.com/XTLS/Xray-core/releases/download/v${XRAY_VERSION}/Xray-linux-64.zip"
DATA_DIR="."
# --- h1cloud per-node xray core override --------------------------------
# Billing writes xray_version.txt to bump THIS node's xray core (e.g. when
# the client app updates its xray) WITHOUT editing this script or the fleet.
# Missing/blank/invalid keeps the pinned XRAY_VERSION default above.
if [ -f "$DATA_DIR/xray_version.txt" ]; then
    _H1_XVER="$(head -n1 "$DATA_DIR/xray_version.txt" 2>/dev/null | tr -cd '0-9.')"
    case "$_H1_XVER" in
        [0-9]*.[0-9]*.[0-9]*)
            XRAY_VERSION="$_H1_XVER"
            XRAY_URL="https://github.com/XTLS/Xray-core/releases/download/v${XRAY_VERSION}/Xray-linux-64.zip"
            ;;
    esac
fi
