print_line() {
    echo "========================================"
}

need_cmd() {
    if ! command -v "$1" >/dev/null 2>&1; then
        echo "$1 is required"
        return 1
    fi
    return 0
}

init_files() {
    need_cmd curl || return 1
    need_cmd python3 || return 1

    if [ ! -f "$USERS_FILE" ]; then
        echo "[]" > "$USERS_FILE"
    fi

    if [ ! -f "$NODES_FILE" ]; then
        echo "[]" > "$NODES_FILE"
    fi

    if [ ! -f "$DEVICES_FILE" ]; then
        echo "{}" > "$DEVICES_FILE"
    fi

    if [ ! -f "$TRAFFIC_FILE" ]; then
        echo "{}" > "$TRAFFIC_FILE"
    fi

    mkdir -p "$BACKUP_DIR" >/dev/null 2>&1

    if [ ! -f "$AUTO_UPDATE_FILE" ]; then
        echo "1" > "$AUTO_UPDATE_FILE"
    fi

    if [ ! -f "$TRANSPORT_FILE" ]; then
        echo "ws" > "$TRANSPORT_FILE"
    fi

    if [ ! -f "$XHTTP_PATH_FILE" ]; then
        echo "/api/v1/sync/" > "$XHTTP_PATH_FILE"
    fi

    if [ ! -f "$XHTTP_METHOD_FILE" ]; then
        echo "GET" > "$XHTTP_METHOD_FILE"
    fi

    if [ ! -f "$XHTTP_ALPN_FILE" ]; then
        echo "h2,http1" > "$XHTTP_ALPN_FILE"
    fi

    touch "$KEY_FILE" "$ACTION_LOG_FILE" >/dev/null 2>&1

    python3 - "$USERS_FILE" <<'PY' >/dev/null 2>&1
import json, sys, time
path = sys.argv[1]
try:
    with open(path, "r", encoding="utf-8") as f:
        raw = f.read()
    data = json.loads(raw)
    if not isinstance(data, list):
        raise ValueError("users.json is not list")
except Exception:
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            raw = f.read()
    except Exception:
        raw = ""
    backup = f"{path}.bad.{int(time.time())}"
    with open(backup, "w", encoding="utf-8") as f:
        f.write(raw or "broken users.json backup\n")
    with open(path, "w", encoding="utf-8") as f:
        json.dump([], f)
PY

    # Force the pinned version: if a binary exists but reports a different
    # version, drop it so the block below re-downloads v$XRAY_VERSION.
    if [ -f "$XRAY_BIN" ] && [ -n "$XRAY_VERSION" ]; then
        INSTALLED_XRAY_VERSION="$("$XRAY_BIN" version 2>/dev/null | head -n1 | awk '{print $2}')"
        if [ "$INSTALLED_XRAY_VERSION" != "$XRAY_VERSION" ]; then
            echo "xray $INSTALLED_XRAY_VERSION installed, pinned $XRAY_VERSION -> reinstalling"
            rm -f "$XRAY_BIN"
        fi
    fi

    if [ ! -f "$XRAY_BIN" ]; then
        echo "downloading xray v$XRAY_VERSION..."

        curl -fL -o xray.zip "$XRAY_URL"
        if [ "$?" -ne 0 ]; then
            echo "xray download failed"
            rm -f xray.zip
            return 1
        fi

        if command -v unzip >/dev/null 2>&1; then
            unzip -o -q xray.zip
            UNZIP_STATUS="$?"
        else
            python3 -m zipfile -e xray.zip .
            UNZIP_STATUS="$?"
        fi

        rm -f xray.zip

        if [ "$UNZIP_STATUS" -ne 0 ]; then
            echo "xray extract failed"
            return 1
        fi

        chmod +x "$XRAY_BIN"

        if [ ! -f "$XRAY_BIN" ]; then
            echo "xray binary not found after extract"
            return 1
        fi
    fi

    if is_reality_enabled; then
        ensure_reality_files || return 1
    fi

    return 0
}

normalize_domain() {
    DOMAIN_VALUE="$(printf '%s' "$1" | tr -d '[:space:]')"
    DOMAIN_VALUE="${DOMAIN_VALUE#http://}"
    DOMAIN_VALUE="${DOMAIN_VALUE#https://}"
    DOMAIN_VALUE="${DOMAIN_VALUE%%/*}"
    DOMAIN_VALUE="${DOMAIN_VALUE%%:*}"
    echo "$DOMAIN_VALUE"
}

ensure_domain() {
    if [ -f "$DOMAIN_FILE" ] && [ -s "$DOMAIN_FILE" ]; then
        return 0
    fi

    if [ -n "${DOMAIN:-}" ]; then
        INPUT_DOMAIN="$(normalize_domain "$DOMAIN")"
        if [ -n "$INPUT_DOMAIN" ]; then
            echo "$INPUT_DOMAIN" > "$DOMAIN_FILE"
            return 0
        fi
    fi

    # По умолчанию домен = публичный IP ноды. Панель НЕ должна интерактивно
    # просить домен на старте (это вешало загрузку контейнера). Свой домен
    # можно задать позже в панели или командой `vpn domain DOMAIN`.
    AUTO_DOMAIN="$(normalize_domain "$(read_public_ip 2>/dev/null)")"
    if [ -n "$AUTO_DOMAIN" ]; then
        echo "$AUTO_DOMAIN" > "$DOMAIN_FILE"
        echo "domain auto-set to $AUTO_DOMAIN (public IP)"
        return 0
    fi

    # IP не определился — не блокируем загрузку, ставим заглушку.
    echo "localhost" > "$DOMAIN_FILE"
    echo "domain not detected, using localhost (set later: vpn domain DOMAIN)"
    return 0
}

read_domain() {
    if [ -f "$DOMAIN_FILE" ] && [ -s "$DOMAIN_FILE" ]; then
        normalize_domain "$(head -n 1 "$DOMAIN_FILE")"
        return 0
    fi

    if [ -n "${DOMAIN:-}" ]; then
        normalize_domain "$DOMAIN"
        return 0
    fi

    echo "localhost"
    return 0
}

# Возвращает реальный IP сервера (а не домен Pterodactyl Domains).
# На Pterodactyl env SERVER_IP обычно содержит IP аллокации — но это часто
# 0.0.0.0 (внутри контейнера), поэтому пробуем по очереди:
#   1. env PUBLIC_IP / SERVER_IP (если он валидный, не 0.0.0.0/127.x)
#   2. кэш в public_ip.txt
#   3. curl на ifconfig.me / api.ipify.org (один раз, потом сохранить в кэш)
#   4. fallback — домен из domain.txt
read_public_ip() {
    local CANDIDATE=""

    if [ -n "${PUBLIC_IP:-}" ]; then
        CANDIDATE="$PUBLIC_IP"
    elif [ -n "${SERVER_IP:-}" ]; then
        CANDIDATE="$SERVER_IP"
    fi

    case "$CANDIDATE" in
        ""|0.0.0.0|127.*|::|::1) CANDIDATE="" ;;
    esac

    if [ -n "$CANDIDATE" ]; then
        echo "$CANDIDATE"
        return 0
    fi

    if [ -f "$PUBLIC_IP_FILE" ] && [ -s "$PUBLIC_IP_FILE" ]; then
        head -n 1 "$PUBLIC_IP_FILE"
        return 0
    fi

    for URL in "https://api.ipify.org" "https://ifconfig.me/ip" "https://ipv4.icanhazip.com"; do
        CANDIDATE="$(curl -fsS --max-time 4 "$URL" 2>/dev/null | tr -d '[:space:]')"
        if [ -n "$CANDIDATE" ]; then
            echo "$CANDIDATE" > "$PUBLIC_IP_FILE"
            echo "$CANDIDATE"
            return 0
        fi
    done

    DOMAIN_VALUE="$(read_domain)"
    if command -v getent >/dev/null 2>&1; then
        CANDIDATE="$(getent ahostsv4 "$DOMAIN_VALUE" 2>/dev/null | awk '{print $1; exit}' | tr -d '[:space:]')"
        if [ -n "$CANDIDATE" ]; then
            echo "$CANDIDATE" > "$PUBLIC_IP_FILE"
            echo "$CANDIDATE"
            return 0
        fi
    fi

    CANDIDATE="$(python3 - "$DOMAIN_VALUE" <<'PY' 2>/dev/null
import socket
import sys
try:
    print(socket.gethostbyname(sys.argv[1]))
except Exception:
    pass
PY
)"
    CANDIDATE="$(printf '%s' "$CANDIDATE" | head -n 1 | tr -d '[:space:]')"
    if [ -n "$CANDIDATE" ]; then
        echo "$CANDIDATE" > "$PUBLIC_IP_FILE"
        echo "$CANDIDATE"
        return 0
    fi

    read_domain
    return 0
}

read_subscription_host() {
    local HOST_VALUE

    HOST_VALUE="$(read_public_ip | head -n 1 | tr -d '[:space:]')"
    if [ -z "$HOST_VALUE" ]; then
        HOST_VALUE="$(read_domain)"
    fi

    case "$HOST_VALUE" in
        *:*)
            if printf '%s' "$HOST_VALUE" | grep -Eq '^[0-9A-Fa-f:]+$'; then
                echo "[$HOST_VALUE]"
                return 0
            fi
            ;;
    esac

    echo "$HOST_VALUE"
    return 0
}

read_reality_host() {
    local HOST_VALUE

    HOST_VALUE="$(read_domain | head -n 1 | tr -d '[:space:]')"
    if [ -z "$HOST_VALUE" ]; then
        HOST_VALUE="$(read_subscription_host)"
    fi

    echo "$HOST_VALUE"
    return 0
}

# --- Central router (router.h1cloud.su) -------------------------------------
# Optional: a node can register its subscription/API ports with a central
# nginx+TLS router so clients get one trusted-https URL per node, while the
# node itself stays on plain http. See router/ for the server side.
read_router_base() {
    if [ -f "$ROUTER_BASE_FILE" ] && [ -s "$ROUTER_BASE_FILE" ]; then
        head -n 1 "$ROUTER_BASE_FILE" | tr -d '[:space:]'
    fi
}

read_router_slug() {
    if [ -f "$ROUTER_SLUG_FILE" ] && [ -s "$ROUTER_SLUG_FILE" ]; then
        head -n 1 "$ROUTER_SLUG_FILE" | tr -d '[:space:]'
    fi
}

is_router_enabled() {
    [ -n "$(read_router_base)" ] && [ -n "$(read_router_slug)" ]
}

# Public router URL for this node's subscription, e.g.
#   https://router.h1cloud.su/de/sub/UUID   (UUID optional)
router_sub_url() {
    local BASE SLUG UUID
    BASE="$(read_router_base)"
    SLUG="$(read_router_slug)"
    UUID="${1:-}"
    [ -n "$BASE" ] && [ -n "$SLUG" ] || return 1
    if [ -n "$UUID" ]; then
        echo "${BASE%/}/$SLUG/sub/$UUID"
    else
        echo "${BASE%/}/$SLUG/sub"
    fi
}

router_api_url() {
    local BASE SLUG
    BASE="$(read_router_base)"
    SLUG="$(read_router_slug)"
    [ -n "$BASE" ] && [ -n "$SLUG" ] || return 1
    echo "${BASE%/}/$SLUG/api"
}

# Auto-registration is on by default unless the operator ran `vpn router off`.
is_router_disabled() {
    [ -f "$ROUTER_DISABLED_FILE" ]
}

# Register (or refresh) this node's sub/api targets with the router.
# Args: BASE TOKEN [SLUG]. On success writes router_base/slug/token files and
# echoes "OK <slug> <sub_url> <api_url>"; on failure echoes "ERR ...".
router_register_now() {
    local BASE="$1" TOKEN="$2" SLUG_ARG="${3:-}"
    local HOST_VALUE SUB_PORT_VALUE API_PORT_VALUE SUB_TARGET API_TARGET RESP NEW_SLUG

    [ -n "$BASE" ] && [ -n "$TOKEN" ] || { echo "ERR missing base/token"; return 1; }
    BASE="${BASE%/}"
    HOST_VALUE="$(read_subscription_host)"
    SUB_PORT_VALUE="$(saved_sub_port)"
    API_PORT_VALUE="$(saved_api_port)"
    SUB_TARGET=""
    API_TARGET=""
    [ -n "$SUB_PORT_VALUE" ] && SUB_TARGET="$HOST_VALUE:$SUB_PORT_VALUE"
    [ -n "$API_PORT_VALUE" ] && API_TARGET="$HOST_VALUE:$API_PORT_VALUE"
    if [ -z "$SUB_TARGET" ] && [ -z "$API_TARGET" ]; then
        echo "ERR no running sub/api to publish"
        return 1
    fi

    RESP="$(H1_ROUTER_URL="$BASE" H1_ROUTER_TOKEN="$TOKEN" \
        H1_NODE_ID="$(get_node_name)" H1_SLUG="$SLUG_ARG" \
        H1_SUB_TARGET="$SUB_TARGET" H1_API_TARGET="$API_TARGET" \
        python3 - <<'PY'
import json, os, sys, urllib.request, urllib.error
base = os.environ["H1_ROUTER_URL"].rstrip("/")
payload = {
    "node_id": os.environ.get("H1_NODE_ID", ""),
    "slug": os.environ.get("H1_SLUG", ""),
    "sub_target": os.environ.get("H1_SUB_TARGET", ""),
    "api_target": os.environ.get("H1_API_TARGET", ""),
}
data = json.dumps(payload).encode("utf-8")
req = urllib.request.Request(base + "/__register", data=data, method="POST", headers={
    "Content-Type": "application/json",
    "Authorization": "Bearer " + os.environ.get("H1_ROUTER_TOKEN", ""),
    "User-Agent": "H1CloudVPNRouter/1.0",
})
try:
    with urllib.request.urlopen(req, timeout=12) as resp:
        body = json.loads(resp.read().decode("utf-8"))
except urllib.error.HTTPError as exc:
    print("ERR " + str(exc.code) + " " + exc.read().decode("utf-8", "replace"))
    sys.exit(0)
except Exception as exc:
    print("ERR " + str(exc))
    sys.exit(0)
if body.get("ok"):
    print("OK " + body.get("slug", "") + " " + body.get("sub_url", "") + " " + body.get("api_url", ""))
else:
    print("ERR " + json.dumps(body))
PY
)"

    case "$RESP" in
        OK\ *)
            NEW_SLUG="$(echo "$RESP" | awk '{print $2}')"
            echo "$BASE" > "$ROUTER_BASE_FILE"
            echo "$NEW_SLUG" > "$ROUTER_SLUG_FILE"
            echo "$TOKEN" > "$ROUTER_TOKEN_FILE"
            chmod 600 "$ROUTER_TOKEN_FILE" >/dev/null 2>&1
            echo "$RESP"
            return 0
            ;;
        *)
            echo "$RESP"
            return 1
            ;;
    esac
}

# Called on api/sub start. Silently (re)registers with the built-in default
# router unless the operator disabled it or no default token is configured.
auto_router_register() {
    is_router_disabled && return 0
    local BASE TOKEN SLUG
    if [ -f "$ROUTER_MANUAL_FILE" ]; then
        # operator pinned a specific router via `vpn router register URL TOKEN`
        BASE="$(read_router_base)"
        TOKEN="$(head -n 1 "$ROUTER_TOKEN_FILE" 2>/dev/null)"
    else
        # auto mode always follows the built-in defaults, so changing
        # DEFAULT_ROUTER_BASE in main.sh re-points every node on next start
        BASE="$DEFAULT_ROUTER_BASE"
        TOKEN="$DEFAULT_ROUTER_TOKEN"
    fi
    [ -n "$BASE" ] && [ -n "$TOKEN" ] || return 0
    SLUG="$(read_router_slug)"
    if router_register_now "$BASE" "$TOKEN" "$SLUG" >/dev/null 2>&1; then
        log_action "router" "auto-registered slug=$(read_router_slug) base=$BASE"
        sync_keys_file >/dev/null 2>&1
    fi
    return 0
}

get_node_name() {
    if [ -n "${NODE_NAME:-${VPN_NODE_NAME:-}}" ]; then
        printf '%s\n' "${NODE_NAME:-${VPN_NODE_NAME:-}}"
        return 0
    fi

    if [ -f "$NODE_NAME_FILE" ] && [ -s "$NODE_NAME_FILE" ]; then
        head -n 1 "$NODE_NAME_FILE"
        return 0
    fi

    read_domain
    return 0
}

tag_file_for() {
    case "$1" in
        ws) echo "$TAG_WS_FILE" ;;
        xhttp) echo "$TAG_XHTTP_FILE" ;;
        reality) echo "$TAG_REALITY_FILE" ;;
        cdn-ws|ws-cdn) echo "$CDN_WS_TAG_FILE" ;;
        cdn-xhttp|xhttp-cdn|cdn) echo "$CDN_XHTTP_TAG_FILE" ;;
        *) echo "" ;;
    esac
}

default_tag_for() {
    case "$1" in
        ws) echo "WS" ;;
        xhttp) echo "XHTTP" ;;
        reality) echo "Reality" ;;
        cdn-ws|ws-cdn|cdn-xhttp|xhttp-cdn|cdn) echo "CDN" ;;
        *) echo "" ;;
    esac
}

get_link_tag() {
    local KIND="$1"
    local FILE DEFAULT_VALUE

    FILE="$(tag_file_for "$KIND")"
    DEFAULT_VALUE="$(default_tag_for "$KIND")"
    if [ -n "$FILE" ] && [ -f "$FILE" ] && [ -s "$FILE" ]; then
        head -n 1 "$FILE"
        return 0
    fi

    echo "$DEFAULT_VALUE"
    return 0
}

set_link_tag() {
    local KIND="$1"
    local VALUE="$2"
    local FILE

    FILE="$(tag_file_for "$KIND")"
    if [ -z "$FILE" ]; then
        return 1
    fi

    printf '%s\n' "$VALUE" > "$FILE"
    return 0
}

get_port() {
    local PORT_VALUE
    PORT_VALUE="${SERVER_PORT:-25565}"
    if validate_port "$PORT_VALUE"; then
        echo "$PORT_VALUE"
    else
        echo "25565"
    fi
}

get_public_port() {
    local PORT_VALUE
    PORT_VALUE="${PUBLIC_PORT:-${WS_PUBLIC_PORT:-}}"
    if [ -z "$PORT_VALUE" ]; then
        PORT_VALUE="$(get_port)"
    fi
    if validate_port "$PORT_VALUE"; then
        echo "$PORT_VALUE"
    else
        get_port
    fi
}

get_reality_port() {
    if [ -n "${REALITY_PORT:-}" ]; then
        echo "$REALITY_PORT"
        return 0
    fi

    if [ -f "$REALITY_PORT_FILE" ] && [ -s "$REALITY_PORT_FILE" ]; then
        head -n 1 "$REALITY_PORT_FILE"
        return 0
    fi

    candidate_port_after_base 1
    return $?
}

get_public_reality_port() {
    if [ -n "${PUBLIC_REALITY_PORT:-}" ]; then
        echo "$PUBLIC_REALITY_PORT"
        return 0
    fi

    if [ -f "$REALITY_PUBLIC_PORT_FILE" ] && [ -s "$REALITY_PUBLIC_PORT_FILE" ]; then
        head -n 1 "$REALITY_PUBLIC_PORT_FILE"
        return 0
    fi

    get_reality_port
    return $?
}

get_reality_sni() {
    if [ -n "${REALITY_SNI:-}" ]; then
        echo "$REALITY_SNI"
        return 0
    fi

    if [ -f "$REALITY_SNI_FILE" ] && [ -s "$REALITY_SNI_FILE" ]; then
        head -n 1 "$REALITY_SNI_FILE"
        return 0
    fi

    echo "proxy11.h1guro.ovh"
    return 0
}

get_reality_dest() {
    if [ -n "${REALITY_DEST:-}" ]; then
        echo "$REALITY_DEST"
        return 0
    fi

    if [ -f "$REALITY_DEST_FILE" ] && [ -s "$REALITY_DEST_FILE" ]; then
        head -n 1 "$REALITY_DEST_FILE"
        return 0
    fi

    echo "$(get_reality_sni):443"
    return 0
}

# Reality uTLS fingerprint shown in client links (fp= param). Default: chrome.
# Valid xray uTLS values: chrome firefox safari ios android edge 360 qq random randomized
normalize_reality_fp() {
    local FP_VALUE
    FP_VALUE="$(printf '%s' "${1:-}" | tr '[:upper:]' '[:lower:]' | tr -d '[:space:]')"
    case "$FP_VALUE" in
        chrome|firefox|safari|ios|android|edge|360|qq|random|randomized)
            echo "$FP_VALUE"; return 0 ;;
        *)
            return 1 ;;
    esac
}

get_reality_fp() {
    local FP_VALUE
    if [ -n "${REALITY_FP:-}" ]; then
        FP_VALUE="$(normalize_reality_fp "$REALITY_FP")" && { echo "$FP_VALUE"; return 0; }
    fi
    if [ -f "$REALITY_FP_FILE" ] && [ -s "$REALITY_FP_FILE" ]; then
        FP_VALUE="$(normalize_reality_fp "$(head -n 1 "$REALITY_FP_FILE")")" && { echo "$FP_VALUE"; return 0; }
    fi
    echo "chrome"
    return 0
}

# Reality flow shown in client links (flow= param) and on the xray inbound clients.
# "on" -> xtls-rprx-vision (default), "off" -> empty (plain reality TCP).
# When off, links omit &flow= and the inbound clients carry no "flow" field.
normalize_reality_flow() {
    local FLOW_VALUE
    FLOW_VALUE="$(printf '%s' "${1:-}" | tr '[:upper:]' '[:lower:]' | tr -d '[:space:]')"
    case "$FLOW_VALUE" in
        on|vision|xtls-rprx-vision)
            echo "xtls-rprx-vision"; return 0 ;;
        off|none|disable|disabled|0|"")
            echo ""; return 0 ;;
        *)
            return 1 ;;
    esac
}

get_reality_flow() {
    local FLOW_VALUE
    if [ -n "${REALITY_FLOW+x}" ]; then
        FLOW_VALUE="$(normalize_reality_flow "$REALITY_FLOW")" && { echo "$FLOW_VALUE"; return 0; }
    fi
    if [ -f "$REALITY_FLOW_FILE" ]; then
        FLOW_VALUE="$(normalize_reality_flow "$(head -n 1 "$REALITY_FLOW_FILE" 2>/dev/null)")" && { echo "$FLOW_VALUE"; return 0; }
    fi
    echo "xtls-rprx-vision"
    return 0
}

# Reality spiderX path shown in client links (spx= param). Client-side decoy only.
normalize_reality_spx() {
    local SPX_VALUE
    SPX_VALUE="$(printf '%s' "${1:-}" | tr -d '[:space:]')"
    if [ "$SPX_VALUE" = "random" ]; then
        SPX_VALUE="/$(make_short_id | head -n 1 | tr -d '[:space:]')"
    fi
    [ -z "$SPX_VALUE" ] && SPX_VALUE="/"
    case "$SPX_VALUE" in
        /*) ;;
        *) SPX_VALUE="/$SPX_VALUE" ;;
    esac
    echo "$SPX_VALUE"
    return 0
}

get_reality_spx() {
    local SPX_VALUE
    if [ -n "${REALITY_SPX:-}" ]; then
        SPX_VALUE="$(normalize_reality_spx "$REALITY_SPX")" && { echo "$SPX_VALUE"; return 0; }
    fi
    if [ -f "$REALITY_SPX_FILE" ] && [ -s "$REALITY_SPX_FILE" ]; then
        SPX_VALUE="$(normalize_reality_spx "$(head -n 1 "$REALITY_SPX_FILE")")" && { echo "$SPX_VALUE"; return 0; }
    fi
    echo "/"
    return 0
}

get_sub_port() {
    if [ -n "${SUB_PORT:-}" ]; then
        echo "$SUB_PORT"
