# --- Subscription page customization (title/description/support/accent) -------
read_sub_setting() {
    # $1 = file path, $2 = fallback
    if [ -f "$1" ] && [ -s "$1" ]; then
        head -n 1 "$1"
        return 0
    fi
    printf '%s\n' "${2:-}"
}

get_sub_title() {
    local VALUE
    VALUE="$(read_sub_setting "$SUB_TITLE_FILE" "")"
    if [ -z "$VALUE" ]; then
        VALUE="$(get_sub_name)"
    fi
    [ -n "$VALUE" ] || VALUE="H1Cloud Client"
    printf '%s\n' "$VALUE"
}

get_sub_desc() {
    read_sub_setting "$SUB_DESC_FILE" ""
}

get_sub_support_url() {
    read_sub_setting "$SUB_SUPPORT_URL_FILE" ""
}

get_sub_support_text() {
    read_sub_setting "$SUB_SUPPORT_TEXT_FILE" "Поддержка"
}

get_sub_accent() {
    read_sub_setting "$SUB_ACCENT_FILE" ""
}

append_sub_name_fragment() {
    local URL_VALUE="$1"
    local NAME_VALUE="$2"

    if [ -z "$URL_VALUE" ] || [ -z "$NAME_VALUE" ]; then
        echo "$URL_VALUE"
        return 0
    fi

    python3 - "$URL_VALUE" "$NAME_VALUE" <<'PY'
import sys
import urllib.parse

url = sys.argv[1]
name = sys.argv[2]
print(url.split("#", 1)[0] + "#" + urllib.parse.quote(name, safe=""))
PY
}

