make_uuid() {
    if [ -f /proc/sys/kernel/random/uuid ]; then
        cat /proc/sys/kernel/random/uuid
    else
        python3 -c "import uuid; print(uuid.uuid4())" 2>/dev/null
    fi
}

validate_name() {
    NAME="$1"

    if [ -z "$NAME" ]; then
        return 1
    fi

    case "$NAME" in
        *[!a-zA-Z0-9._-]*)
            return 1
            ;;
    esac

    return 0
}

strip_outer_quotes() {
    local VALUE="$*"

    VALUE="${VALUE#"${VALUE%%[![:space:]]*}"}"
    VALUE="${VALUE%"${VALUE##*[![:space:]]}"}"

    case "$VALUE" in
        \'*\')
            VALUE="${VALUE#\'}"
            VALUE="${VALUE%\'}"
            ;;
        \"*\")
            VALUE="${VALUE#\"}"
            VALUE="${VALUE%\"}"
            ;;
    esac

    printf '%s' "$VALUE"
}

validate_days() {
    DAYS="$1"

    if ! echo "$DAYS" | grep -Eq '^[0-9]+$'; then
        return 1
    fi

    if [ "$DAYS" -le 0 ]; then
        return 1
    fi

    return 0
}

validate_port() {
    local PORT_VALUE="$1"

    if ! echo "$PORT_VALUE" | grep -Eq '^[0-9]+$'; then
        return 1
    fi

    if [ "$PORT_VALUE" -lt 1 ] || [ "$PORT_VALUE" -gt 65535 ]; then
        return 1
    fi

    return 0
}

is_enabled_value() {
    case "$1" in
        1|yes|YES|true|TRUE|on|ON|enable|enabled)
            return 0
            ;;
    esac
    return 1
}

is_disabled_value() {
    case "$1" in
        0|no|NO|false|FALSE|off|OFF|disable|disabled)
            return 0
            ;;
    esac
    return 1
}

is_reality_enabled() {
    local VALUE PORT_VALUE

    VALUE="${REALITY_ENABLED:-${VPN_REALITY:-}}"
    if [ -n "$VALUE" ]; then
        if is_enabled_value "$VALUE"; then
            return 0
        fi
        if is_disabled_value "$VALUE"; then
            return 1
        fi
    fi

    if [ -n "${REALITY_PORT:-}" ] && validate_port "$REALITY_PORT"; then
        return 0
    fi

    if [ -f "$REALITY_ENABLED_FILE" ] && [ -s "$REALITY_ENABLED_FILE" ]; then
        VALUE="$(head -n 1 "$REALITY_ENABLED_FILE" 2>/dev/null)"
        if is_enabled_value "$VALUE"; then
            return 0
        fi
        if is_disabled_value "$VALUE"; then
            return 1
        fi
    fi

    return 0
}

set_reality_enabled() {
    if [ "$1" = "1" ]; then
        echo "1" > "$REALITY_ENABLED_FILE"
    else
        echo "0" > "$REALITY_ENABLED_FILE"
    fi
    return 0
}

saved_api_port() {
    if [ -f "$API_PORT_FILE" ] && [ -s "$API_PORT_FILE" ]; then
        head -n 1 "$API_PORT_FILE"
    fi
}

saved_sub_port() {
    if [ -f "$SUB_PORT_FILE" ] && [ -s "$SUB_PORT_FILE" ]; then
        head -n 1 "$SUB_PORT_FILE"
    fi
}

candidate_port_after_base() {
    local OFFSET="$1"
    local BASE_PORT CANDIDATE

    BASE_PORT="$(get_port)"
    if validate_port "$BASE_PORT"; then
        CANDIDATE=$((BASE_PORT + OFFSET))
        if [ "$CANDIDATE" -le 65535 ]; then
            echo "$CANDIDATE"
            return 0
        fi
    fi

    CANDIDATE=$((30000 + OFFSET))
    if [ "$CANDIDATE" -le 65535 ]; then
        echo "$CANDIDATE"
        return 0
    fi

    return 1
}

# Порты, реально выделенные этому ptero-серверу (billing пишет allocations.json).
# Пусто = данных нет (не мешаем старой логике base+offset).
node_owned_ports() {
    [ -f "$ALLOCATIONS_FILE" ] || return 0
    python3 - "$ALLOCATIONS_FILE" <<'PY' 2>/dev/null
import json, sys
try:
    data = json.load(open(sys.argv[1], encoding="utf-8"))
except Exception:
    raise SystemExit(0)
if isinstance(data, dict):
    data = data.get("ports") or data.get("allocations") or []
out = []
for it in (data or []):
    p = it.get("port") if isinstance(it, dict) else it
    try:
        p = int(p)
    except Exception:
        continue
    if 0 < p <= 65535 and p not in out:
        out.append(p)
print(" ".join(str(p) for p in out))
PY
}

# 0, если порт реально выделен серверу (или данных об аллокациях нет — тогда не мешаем).
port_is_owned() {
    local P="$1" OWNED X
    OWNED="$(node_owned_ports)"
    [ -z "$OWNED" ] && return 0
    for X in $OWNED; do
        [ "$X" = "$P" ] && return 0
    done
    return 1
}

auto_offset_port() {
    local SERVICE="$1"
    local START_OFFSET="$2"
    local OFFSET CANDIDATE OWNED WS_PORT

    # Если известны реально выделенные порты (allocations.json) — выбираем СВОБОДНЫЙ
    # ИЗ НИХ (не ws/reality/api/sub). base+offset может быть чужим портом ноды:
    # ensure_min_allocations выдаёт НЕсоседние порты (напр. primary 25614, а свободные
    # 25620..25623) → base+2=25616 принадлежит чужому контейнеру (nginx/TLS).
    OWNED="$(node_owned_ports)"
    if [ -n "$OWNED" ]; then
        WS_PORT="$(get_port)"
        for CANDIDATE in $OWNED; do
            [ "$CANDIDATE" = "$WS_PORT" ] && continue
            if validate_port "$CANDIDATE" && check_port_conflict "$CANDIDATE" "$SERVICE" >/dev/null 2>&1; then
                echo "$CANDIDATE"
                return 0
            fi
        done
    fi

    OFFSET="$START_OFFSET"
    while [ "$OFFSET" -le 20 ]; do
        CANDIDATE="$(candidate_port_after_base "$OFFSET")"
        if validate_port "$CANDIDATE" && check_port_conflict "$CANDIDATE" "$SERVICE" >/dev/null 2>&1; then
            echo "$CANDIDATE"
            return 0
        fi
        OFFSET=$((OFFSET + 1))
    done

    candidate_port_after_base "$START_OFFSET"
}

auto_api_port() {
    local PORT_VALUE

    # Панель-режим: панель ВСЕГДА на первичном порту контейнера (SERVER_PORT) —
    # тот же порт, на котором ptero «создаёт» сервер, чтобы адрес панели совпадал
    # с портом сервера. Обход-инбаунд (если есть) уезжает на другой выделенный порт.
    if is_panel_mode; then
        PORT_VALUE="$(get_port)"
        if validate_port "$PORT_VALUE"; then
            echo "$PORT_VALUE"
            return 0
        fi
    fi

    # Сохранённый/env порт принимаем ТОЛЬКО если он реально выделен серверу —
    # иначе (напр. ранее сохранён чужой base+2) пересчитываем из allocations.json.
    PORT_VALUE="$(saved_api_port)"
    if validate_port "$PORT_VALUE" && port_is_owned "$PORT_VALUE"; then
        echo "$PORT_VALUE"
        return 0
    fi

    PORT_VALUE="${API_PORT:-${VPN_API_PORT:-}}"
    if validate_port "$PORT_VALUE" && port_is_owned "$PORT_VALUE"; then
        echo "$PORT_VALUE"
        return 0
    fi

    auto_offset_port api 2
}

auto_sub_port() {
    local PORT_VALUE

    PORT_VALUE="$(saved_sub_port)"
    if validate_port "$PORT_VALUE" && port_is_owned "$PORT_VALUE"; then
        echo "$PORT_VALUE"
        return 0
    fi

    PORT_VALUE="${SUB_PORT:-${VPN_SUB_PORT:-}}"
    if validate_port "$PORT_VALUE" && port_is_owned "$PORT_VALUE"; then
        echo "$PORT_VALUE"
        return 0
    fi

    auto_offset_port sub 3
}

check_port_conflict() {
    local PORT_VALUE="$1"
    local SERVICE="$2"
    local WS_PORT REALITY_PORT_VALUE API_PORT_VALUE SUB_PORT_VALUE

    # В панель-режиме первичный порт (SERVER_PORT) НЕ занят ws/xray (главного
    # inbound на нём нет — он либо отсутствует, либо уехал на _bs_port), его
    # слушает САМА панель (api). Поэтому не блокируем его. Аналогично reality-inbound
    # в панель-режиме не строится (гейт not _panel_mode в build_config).
    WS_PORT="$(get_port)"
    if [ "$SERVICE" != "ws" ] && [ "$PORT_VALUE" = "$WS_PORT" ] && ! is_panel_mode; then
        echo "port $PORT_VALUE is already used by ws/xray"
        return 1
    fi

    if [ "$SERVICE" != "reality" ] && is_reality_enabled && ! is_panel_mode; then
        REALITY_PORT_VALUE="$(get_reality_port)"
        if [ -n "$REALITY_PORT_VALUE" ] && [ "$PORT_VALUE" = "$REALITY_PORT_VALUE" ]; then
            echo "port $PORT_VALUE is already used by reality"
            return 1
        fi
    fi

    API_PORT_VALUE="$(saved_api_port)"
    if ! validate_port "$API_PORT_VALUE"; then
        API_PORT_VALUE="${API_PORT:-${VPN_API_PORT:-}}"
    fi
    if [ "$SERVICE" != "api" ] && validate_port "$API_PORT_VALUE"; then
        if [ "$PORT_VALUE" = "$API_PORT_VALUE" ]; then
            echo "port $PORT_VALUE is already used by api"
            return 1
        fi
    fi

    SUB_PORT_VALUE="$(saved_sub_port)"
    if ! validate_port "$SUB_PORT_VALUE"; then
        SUB_PORT_VALUE="${SUB_PORT:-${VPN_SUB_PORT:-}}"
    fi
    if [ "$SERVICE" != "sub" ] && validate_port "$SUB_PORT_VALUE"; then
        if [ "$PORT_VALUE" = "$SUB_PORT_VALUE" ]; then
            echo "port $PORT_VALUE is already used by subscription"
            return 1
        fi
    fi

    return 0
}

# Снимок users.json без форка cat: $(<file) — это builtin-чтение,
# функция вызывается из горячего цикла дважды в секунду.
read_users_snapshot() {
    if [ -f "$USERS_FILE" ] && [ -r "$USERS_FILE" ]; then
        USERS_SNAPSHOT="$(<"$USERS_FILE")"
    else
        USERS_SNAPSHOT="[]"
    fi
    return 0
}

remember_users_state() {
    read_users_snapshot
    USERS_STATE="$USERS_SNAPSHOT"
    return 0
}

log_action() {
    ACTION="$1"
    DETAIL="$2"
    TS="$(date '+%Y-%m-%d %H:%M:%S' 2>/dev/null || date)"
    echo "$TS | $ACTION | $DETAIL" >> "$ACTION_LOG_FILE" 2>/dev/null
    return 0
}

get_api_token() {
    if [ -f "$API_TOKEN_FILE" ] && [ -s "$API_TOKEN_FILE" ]; then
        head -n 1 "$API_TOKEN_FILE"
        return 0
    fi

    TOKEN="$(make_uuid)$(make_uuid)"
    # ВАЖНО: `-` должен быть в КОНЦЕ списка, иначе GNU tr примет его за флаг
    # и упадёт с "tr: invalid option -- '['" — токен станет пустым,
    # и в файле окажется обычный unix timestamp вместо нормального ключа.
    TOKEN="$(printf '%s' "$TOKEN" | tr -d '[:space:]-')"

    if [ -z "$TOKEN" ]; then
        TOKEN="$(date +%s)"
    fi

    echo "$TOKEN" > "$API_TOKEN_FILE"
    chmod 600 "$API_TOKEN_FILE" >/dev/null 2>&1
    echo "$TOKEN"
    return 0
}

