    fi

    REALITY_FP="$(get_reality_fp)" REALITY_FLOW="$(get_reality_flow)" REALITY_SPX="$(get_reality_spx)" python3 - "$USERS_FILE" "$KEY_FILE" "$PUBLIC_DOMAIN" "$WS_PUBLIC_PORT_VALUE" "$NODE_NAME_VALUE" "$REALITY_ENABLED_VALUE" "$REALITY_PUBLIC_PORT_VALUE" "$REALITY_PUBLIC_HOST_VALUE" "$REALITY_SNI_VALUE" "$REALITY_PUBLIC_KEY_VALUE" "$REALITY_SHORT_ID_VALUE" "$SUB_PORT_VALUE" "$SUB_TOKEN_VALUE" "$SUB_PUBLIC_HOST_VALUE" "$SUB_NAME_VALUE" "$CDN_WS_ENABLED_VALUE" "$CDN_WS_HOST_VALUE" "$CDN_WS_SNI_VALUE" "$CDN_WS_PORT_VALUE" "$CDN_WS_TAG_VALUE" "$CDN_WS_PATH_VALUE" "$TRAFFIC_FILE" "$TRANSPORT_VALUE" "$XHTTP_PATH_VALUE" "$XHTTP_METHOD_VALUE" "$CDN_XHTTP_ENABLED_VALUE" "$CDN_XHTTP_HOST_VALUE" "$CDN_XHTTP_SNI_VALUE" "$CDN_XHTTP_PORT_VALUE" "$CDN_XHTTP_TAG_VALUE" "$CDN_XHTTP_PUBLIC_PATH_VALUE" "$EGRESS_XRAY_LINK_VALUE" <<'PY'
import datetime
import json
import os
import sys
import time
import urllib.parse

def read_tag_suffix(name, default):
    try:
        with open(name, "r", encoding="utf-8") as f:
            return f.readline().strip()
    except Exception:
        return default


def link_tag(base, suffix):
    base = str(base or "").strip()
    suffix = str(suffix or "").strip()
    if not suffix:
        return base
    if suffix[:1] in ("-", "_", "/", "#", "(", "["):
        return base + suffix
    return (base + " " + suffix).strip()

def xhttp_client_extra(method):
    method = (method or "GET").upper()
    if method not in ("GET", "POST", "PUT"):
        method = "GET"
    return {
        "xmux": {
            "cMaxLifetimeMs": 0,
            "cMaxReuseTimes": "36-96",
            "maxConcurrency": "8-32",
            "maxConnections": 0,
            "hMaxRequestTimes": "320-640",
            "hMaxReusableSecs": "720-1800",
        },
        "seqKey": "part_index",
        "sessionKey": "stream_auth",
        "xPaddingKey": "_t",
        "seqPlacement": "cookie",
        "sessionIDKey": "viewer_session",
        "xPaddingBytes": "96-1040",
        "xPaddingHeader": "X-Media-Token",
        "xPaddingMethod": "tokenish",
        "uplinkChunkSize": 0,
        "sessionPlacement": "cookie",
        "uplinkHTTPMethod": "GET",
        "xPaddingObfsMode": True,
        "xPaddingPlacement": "queryInHeader",
        "scMaxEachPostBytes": 976846,
        "sessionIDPlacement": "cookie",
        "uplinkDataPlacement": "body",
        "scMinPostsIntervalMs": 70,
    }


def xhttp_extra_param(method):
    extra = json.dumps(xhttp_client_extra(method), ensure_ascii=False, separators=(",", ":"))
    return urllib.parse.quote(extra, safe="")


def read_xhttp_alpn(default="h2,http1"):
    try:
        with open("xhttp_alpn.txt", "r", encoding="utf-8") as f:
            value = f.readline().strip().lower()
    except Exception:
        value = default
    aliases = {
        "h2,http1": "h2,http1",
        "h2,http/1.1": "h2,http1",
        "h2,http1.1": "h2,http1",
        "h2,http2": "h2,http1",
        "h2,1.1": "h2,http1",
        "h2": "h2",
        "http2": "h2",
        "2": "h2",
        "none": "none",
        "off": "none",
        "disabled": "none",
        "auto": "none",
        "default": "none",
        "http1": "http1",
        "http1.1": "http1",
        "http/1.1": "http1",
        "1": "http1",
        "1.1": "http1",
        "": default,
    }
    return aliases.get(value, default)


def xhttp_alpn_query():
    value = read_xhttp_alpn()
    if value == "h2,http1":
        return "&alpn=h2%2Chttp%2F1.1"
    if value == "h2":
        return "&alpn=h2"
    if value == "none":
        return ""
    return "&alpn=http%2F1.1"


def read_mws_enabled():
    try:
        with open("mws_enabled.txt", "r", encoding="utf-8") as f:
            value = f.readline().strip().lower()
        return value in ("1", "true", "yes", "on", "enabled")
    except Exception:
        return False


def normalize_xhttp_path_py(path):
    path = str(path or "/api/v1/sync/").strip()
    if not path.startswith("/"):
        path = "/" + path
    if not path.endswith("/"):
        path += "/"
    return path


def build_xhttp_vless(client_id, address, port, path, host_header, tag, security="none", sni="", method="GET"):
    path = urllib.parse.quote(normalize_xhttp_path_py(path), safe="")
    tag = urllib.parse.quote(tag, safe="")
    if read_mws_enabled():
        url = f"vless://{client_id}@{address}:{port}?encryption=none&type=xhttp&path={path}&host={host_header}&mode=auto"
    else:
        extra = xhttp_extra_param(method)
        url = f"vless://{client_id}@{address}:{port}?encryption=none&type=xhttp&path={path}&host={host_header}&mode=packet-up&extra={extra}"
    if security == "tls":
        url += f"&security=tls&sni={sni or host_header}&fp=chrome{xhttp_alpn_query()}"
    else:
        url += "&security=none"
    return url + f"#{tag}"

