def render_custom_inbound(spec):
    # Turn a stored custom-inbound spec (3x-ui-like) into an xray inbound object.
    # Supports vless/vmess/trojan/shadowsocks over tcp/ws/grpc/xhttp/httpupgrade
    # with security none/tls/reality. Returns None on an invalid/unsupported spec.
    proto = str(spec.get("protocol", "")).strip().lower()
    try:
        iport = int(spec.get("port"))
    except Exception:
        return None
    if iport < 1 or iport > 65535 or proto not in ("vless", "vmess", "trojan", "shadowsocks", "socks", "http", "dokodemo-door"):
        return None
    tag = str(spec.get("tag") or f"custom-{proto}-{iport}")
    listen = str(spec.get("listen") or "0.0.0.0")
    raw_clients = spec.get("clients") if isinstance(spec.get("clients"), list) else []

    if proto == "vless":
        clients = []
        for c in raw_clients:
            if not isinstance(c, dict) or not c.get("id"):
                continue
            entry = {"id": str(c["id"]), "email": str(c.get("email") or c["id"])}
            if c.get("flow"):
                entry["flow"] = str(c["flow"])
            clients.append(entry)
        settings = {"clients": clients, "decryption": "none"}
    elif proto == "vmess":
        clients = []
        for c in raw_clients:
            if not isinstance(c, dict) or not c.get("id"):
                continue
            clients.append({"id": str(c["id"]), "email": str(c.get("email") or c["id"]), "alterId": 0})
        settings = {"clients": clients}
    elif proto == "trojan":
        clients = []
        for c in raw_clients:
            if not isinstance(c, dict) or not c.get("password"):
                continue
            clients.append({"password": str(c["password"]), "email": str(c.get("email") or c["password"][:8])})
        settings = {"clients": clients}
    elif proto == "shadowsocks":
        method = str(spec.get("method") or (raw_clients[0].get("method") if raw_clients and isinstance(raw_clients[0], dict) else "") or "aes-256-gcm")
        password = str(spec.get("password") or (raw_clients[0].get("password") if raw_clients and isinstance(raw_clients[0], dict) else "") or "")
        if not password:
            return None
        settings = {"method": method, "password": password, "network": "tcp,udp"}
    elif proto in ("socks", "http"):
        # SOCKS5 / HTTP forward proxy — auth-аккаунты (user/pass) как в 3x-ui.
        accounts = []
        for c in raw_clients:
            if isinstance(c, dict) and c.get("user"):
                accounts.append({"user": str(c["user"]), "pass": str(c.get("pass") or c.get("password") or "")})
        if proto == "socks":
            settings = {"auth": "password" if accounts else "noauth", "udp": True}
            if accounts:
                settings["accounts"] = accounts
        else:  # http
            settings = {"allowTransparent": False}
            if accounts:
                settings["accounts"] = accounts
    else:  # dokodemo-door — проброс порта на заданный адрес (tunnel)
        settings = {
            "address": str(spec.get("target_address") or spec.get("address") or ""),
            "port": int(spec.get("target_port") or spec.get("target_port_value") or 0),
            "network": str(spec.get("target_network") or "tcp,udp"),
            "followRedirect": bool(spec.get("follow_redirect", False)),
        }
        if not settings["address"] or settings["port"] < 1:
            return None

    network = str(spec.get("network") or "tcp").strip().lower()
    security = str(spec.get("security") or "none").strip().lower()
    stream = spec.get("stream") if isinstance(spec.get("stream"), dict) else {}
    stream_settings = {"network": network, "security": security}

    if network == "ws":
        ws = {"path": str(stream.get("path") or "/")}
        if stream.get("host"):
            ws["headers"] = {"Host": str(stream["host"])}
        stream_settings["wsSettings"] = ws
    elif network == "grpc":
        stream_settings["grpcSettings"] = {"serviceName": str(stream.get("serviceName") or stream.get("service_name") or "")}
    elif network == "httpupgrade":
        hu = {"path": str(stream.get("path") or "/")}
        if stream.get("host"):
            hu["host"] = str(stream["host"])
        stream_settings["httpupgradeSettings"] = hu
    elif network == "xhttp":
        xs = {"path": str(stream.get("path") or "/"), "mode": str(stream.get("mode") or "auto")}
        if stream.get("host"):
            xs["host"] = str(stream["host"])
        stream_settings["xhttpSettings"] = xs

    if security == "tls":
        tls = {"serverName": str(stream.get("sni") or stream.get("serverName") or "")}
        cert_file = stream.get("cert_file") or stream.get("certificateFile")
        key_file = stream.get("key_file") or stream.get("keyFile")
        if cert_file and key_file:
            tls["certificates"] = [{"certificateFile": str(cert_file), "keyFile": str(key_file)}]
        alpn = _alpn_list(stream.get("alpn") or "")
        if alpn:
            tls["alpn"] = alpn
        stream_settings["tlsSettings"] = tls
    elif security == "reality":
        stream_settings["realitySettings"] = {
            "show": False,
            "dest": str(stream.get("dest") or f"{stream.get('sni') or 'www.microsoft.com'}:443"),
            "xver": 0,
            "serverNames": [str(stream.get("sni") or "")],
            "privateKey": str(stream.get("private_key") or stream.get("privateKey") or ""),
            "shortIds": [str(stream.get("short_id") or stream.get("shortId") or "")],
        }

    inbound = {
        "port": iport,
        "tag": tag,
        "listen": listen,
        "protocol": proto,
        "settings": settings,
        "streamSettings": stream_settings,
    }
    if spec.get("sniffing", True):
        inbound["sniffing"] = {"enabled": True, "destOverride": ["http", "tls", "quic"]}
    return inbound


