def _min_non_primary_owned_port(primary):
    try:
        _af = os.path.join(os.path.dirname(os.path.abspath(config_file)), "allocations.json")
        with open(_af, "r", encoding="utf-8") as _f:
            _data = json.load(_f)
        if isinstance(_data, dict):
