        _ports = []
        for _it in (_data or []):
            _p = _it.get("port") if isinstance(_it, dict) else _it
            try:
                _p = int(_p)
            except Exception:
                continue
            if 0 < _p <= 65535 and _p != int(primary):
                _ports.append(_p)
        return min(_ports) if _ports else None
    except Exception:
        return None

