    python3 - "$USERS_FILE" "$TRAFFIC_FILE" "$DEVICES_FILE" <<'PY'
import json, sys, time, datetime

path = sys.argv[1]
traffic_file = sys.argv[2]
devices_file = sys.argv[3]
