def fed_node_public(node):
    # Без токена — для отдачи в UI.
    return {"id": node.get("id"), "name": node.get("name"), "url": node.get("url")}


def _fed_base(node):
    return str(node.get("url") or "").strip().rstrip("/")


def fed_node_request(node, method, path, raw_body=None, timeout=12):
    """Прокси-запрос к API ноды. Возвращает (code, body_bytes, content_type)."""
    base = _fed_base(node)
    if not base:
        return 502, b'{"ok":false,"error":"bad_node_url"}', "application/json; charset=utf-8"
    if not path.startswith("/"):
        path = "/" + path
    url = base + "/api" + path
    headers = {"Authorization": "Bearer " + str(node.get("token") or ""),
               "User-Agent": "H1FedProxy/1.0"}
    if raw_body:
        headers["Content-Type"] = "application/json"
    req = urllib.request.Request(url, data=raw_body, method=method, headers=headers)
    try:
        with urllib.request.urlopen(req, timeout=timeout) as resp:
            return resp.getcode(), resp.read(4 * 1024 * 1024), resp.headers.get("Content-Type", "application/json; charset=utf-8")
    except urllib.error.HTTPError as exc:
        try:
            ct = exc.headers.get("Content-Type", "application/json; charset=utf-8")
        except Exception:
            ct = "application/json; charset=utf-8"
        return exc.code, exc.read(4 * 1024 * 1024), ct
    except Exception as exc:
        return 502, json.dumps({"ok": False, "error": "node_unreachable: " + str(exc)[:150]}).encode("utf-8"), "application/json; charset=utf-8"


def fed_node_json(node, method, path, payload=None, timeout=10):
    raw = json.dumps(payload, ensure_ascii=False).encode("utf-8") if payload is not None else None
    code, body, _ = fed_node_request(node, method, path, raw, timeout)
    try:
        return code, json.loads(body.decode("utf-8", "ignore") or "{}")
    except Exception:
        return code, {}


# ---- Связь с ЛК/биллингом: панель сама тянет все сервера владельца по авто-ключу ----
# billing_url.txt + billing_key.txt прописываются в ноду автоматически при провижене
# (юзер ничего не вводит). Панель ходит на {url}/api/v1/* Bearer-ключом владельца.
def billing_config():
    d = _node_data_dir()

    def _rd(fname):
        try:
            with open(os.path.join(d, fname), "r", encoding="utf-8") as fh:
                return fh.read().strip()
        except Exception:
            return ""
    return _rd("billing_url.txt").rstrip("/"), _rd("billing_key.txt")


def billing_request(method, path, payload=None, timeout=15):
    url, key = billing_config()
    if not url or not key:
        return 0, {"ok": False, "error": "billing_not_linked"}
    if not path.startswith("/"):
        path = "/" + path
    full = url + "/api/v1" + path
    headers = {"Authorization": "Bearer " + key, "User-Agent": "H1NodeConsole/1.0"}
    body = None
    if payload is not None:
        body = json.dumps(payload, ensure_ascii=False).encode("utf-8")
        headers["Content-Type"] = "application/json"
    req = urllib.request.Request(full, data=body, method=method, headers=headers)
    try:
        with urllib.request.urlopen(req, timeout=timeout) as resp:
            raw = resp.read(4 * 1024 * 1024)
            code = resp.getcode()
    except urllib.error.HTTPError as exc:
        raw = exc.read(4 * 1024 * 1024)
        code = exc.code
    except Exception as exc:
        return 502, {"ok": False, "error": "billing_unreachable: " + str(exc)[:150]}
    try:
        parsed = json.loads(raw.decode("utf-8", "ignore") or "{}")
        if not isinstance(parsed, (dict, list)):
            raise ValueError("non-json")
        return code, parsed
    except Exception:
        if 200 <= (code or 0) < 300:
            return 502, {"ok": False, "error": "bad_json", "http_code": code}
        return code, {"ok": False, "error": "bad_json", "http_code": code}


