    try:
        my_ip = read_first_line(PUBLIC_IP_FILE).strip()
    except Exception:
        my_ip = ""
    port = str(API_PORT)
    code, d = billing_request("GET", "/servers")
    if code == 200 and isinstance(d, dict):
        for s in (d.get("servers") or []):
            u = str(s.get("panel_web_url") or "")
            if port in u and (not my_ip or my_ip in u):
                sid = str(s.get("id") or "")
                if sid:
                    try:
                        atomic_text(SERVER_ID_FILE, sid + "\n")
                    except Exception:
                        pass
                    return sid
    return ""


