def _wd_bool(value, default):
    """Булев флаг из JSON (True/False), строки ('1'/'true'/'off'...) или отсутствия.
    first_value() глотает False как «пусто», поэтому для флагов НЕ используем его."""
    if isinstance(value, bool):
        return value
    if value is None:
        return default
    s = str(value).strip().lower()
    if s == "":
        return default
    return s in ("1", "true", "yes", "on", "enable", "enabled")


def web_domain_active(purpose_needed):
    """Домен с АКТИВНЫМ SSL нужного назначения ('sub'/'panel'), иначе "".
    Единственный источник — web_domains.json (его пишет handle_webdomains)."""
    try:
        for d in load_web_domains():
            if str(d.get("ssl_status")) == "active":
                p = str(d.get("purpose") or "both")
                if p == "both" or p == purpose_needed:
                    dom = str(d.get("domain") or "").strip()
                    if dom:
                        return dom
    except Exception:
        pass
    return ""


def public_sub_url(client_id):
    """Публичная ссылка на общую подписку. Если привязан SSL-домен подписки —
    https://<домен>/sub/<id> (без порта, iOS требует https), иначе http://host:API_PORT."""
    cid = urllib.parse.quote(str(client_id or ""), safe="")
    if not cid:
        return ""
    dom = web_domain_active("sub")
    if dom:
        return "https://" + dom + "/sub/" + cid
    return "http://" + read_domain() + ":" + str(API_PORT) + "/sub/" + cid


