def _sub_scope_local(path):
    # scope=local в query → НЕ мержим федеративные ноды (защита от рекурсии A→B→A).
    try:
        return "scope=local" in (urllib.parse.urlparse(path).query or "")
    except Exception:
        return False


def _merge_sub_links(*groups):
    seen = set()
    out = []
    for g in groups:
        for l in g:
            if l and l not in seen:
                seen.add(l)
                out.append(l)
    return out


def _decode_sub_body(text):
    import base64 as _b64
    lines = [l.strip() for l in text.splitlines() if l.strip()]
    if any("://" in l for l in lines):
        return lines
    compact = "".join(lines)
    if not compact:
        return []
    try:
        dec = _b64.b64decode(compact + "=" * (-len(compact) % 4), validate=False)
        return [l.strip() for l in dec.decode("utf-8", "ignore").splitlines() if l.strip()]
    except Exception:
        return []


def _fed_sub_base(sid):
    # База для /sub у подключённой ноды из panel_web_url биллинга ("…/panel" → "…").
    base = str((_billing_server(sid) or {}).get("panel_web_url") or "").strip().rstrip("/")
    if base.endswith("/panel"):
        base = base[:-6]
    return base


def fetch_fed_sub_links(user):
    # Ссылки ТОГО ЖЕ клиента (по uuid) со всех подключённых нод — для единой подписки.
    # ⚠ГОРЯЧИЙ ПУТЬ: /sub дёргают все VPN-клиенты. Опрашиваем ноды ПАРАЛЛЕЛЬНО с общим
    # дедлайном — иначе мёртвая/тормозящая нода вешала бы подписку на 6с×N (поток-на-запрос
    # ThreadingHTTPServer копился бы). Ровно когда нода лежит, подписка должна отдаваться быстро.
    uuid_q = urllib.parse.quote(str(user.get("uuid") or ""), safe="")
    if not uuid_q:
        return []
    sids = load_fed_links()
    if not sids:
        return []

    def _one(sid):
        base = _fed_sub_base(sid)
        if not base:
            return []
        url = base + "/sub/" + uuid_q + "?scope=local&mode=raw"
        try:
            req = urllib.request.Request(url, headers={"User-Agent": "H1CloudVPNSub/fed"})
            with urllib.request.urlopen(req, timeout=3) as resp:
                text = resp.read(512 * 1024).decode("utf-8", "ignore")
        except Exception:
            return []
        return [l for l in _decode_sub_body(text) if "://" in l]

    import concurrent.futures as _cf
    out = []
    try:
        with _cf.ThreadPoolExecutor(max_workers=min(8, len(sids))) as ex:
            futs = [ex.submit(_one, s) for s in sids]
            done, _pending = _cf.wait(futs, timeout=5)
            for f in done:
                try:
                    out.extend(f.result() or [])
                except Exception:
                    pass
    except Exception:
        pass
    return out


