def _billing_server(sid, max_age=300):
    # Кэшируем запись сервера (panel_web_url/login/password): каждый lproxy/lagg
    # иначе бьёт в биллинг и при 429/дауне ломает управление живой нодой.
    import time as _t
    sid = str(sid)
    cached = _LINKED_SERVERS.get(sid)
    if cached and (_t.time() - cached[1]) < max_age:
        return cached[0]
    rec = None
    code, d = billing_request("GET", "/servers/" + sid)
    if code == 200 and isinstance(d, dict):
        rec = d.get("server") or d
    if not rec:
        code, d = billing_request("GET", "/servers")
        for s in (d.get("servers") or []):
            if str(s.get("id")) == sid:
                rec = s
                break
    if rec:
        _LINKED_SERVERS[sid] = (rec, _t.time())
        return rec
    if cached:
        return cached[0]
    return None


def _node_api_base(server):
    url = str((server or {}).get("panel_web_url") or "").strip().rstrip("/")
    if url.endswith("/panel"):
        url = url[:-6]
    return url.rstrip("/")


def linked_node_login(sid, force=False):
    import time as _t
    if not force:
        tok = _LINKED_TOKENS.get(str(sid))
        if tok and (_t.time() - tok[1]) < 1200:
            return tok[0]
    sv = _billing_server(sid)
    if not sv:
        return ""
    base = _node_api_base(sv)
    login = str(sv.get("panel_login") or "")
    pw = str(sv.get("panel_password") or "")
    if not base or not login:
        return ""
    try:
        body = json.dumps({"username": login, "password": pw}).encode("utf-8")
        req = urllib.request.Request(base + "/api/auth/login", data=body, method="POST",
                                     headers={"Content-Type": "application/json"})
        with urllib.request.urlopen(req, timeout=12) as resp:
            d = json.loads(resp.read(65536).decode("utf-8", "ignore") or "{}")
        tok = d.get("token") or ""
        if tok:
            _LINKED_TOKENS[str(sid)] = (tok, _t.time())
        return tok
    except Exception:
        return ""


def linked_node_request(sid, method, path, raw_body=None, timeout=20, _retry=True):
    sv = _billing_server(sid)
    if not sv:
        return 502, b'{"ok":false,"error":"server_not_found"}', "application/json; charset=utf-8"
    base = _node_api_base(sv)
    tok = linked_node_login(sid)
    if not base or not tok:
        return 502, b'{"ok":false,"error":"node_login_failed"}', "application/json; charset=utf-8"
    if not path.startswith("/"):
        path = "/" + path
    headers = {"Authorization": "Bearer " + tok, "User-Agent": "H1MainNode/1.0"}
    if raw_body:
        headers["Content-Type"] = "application/json"
    req = urllib.request.Request(base + "/api" + path, data=raw_body, method=method, headers=headers)
    try:
        with urllib.request.urlopen(req, timeout=timeout) as resp:
            return resp.getcode(), resp.read(4 * 1024 * 1024), resp.headers.get("Content-Type", "application/json; charset=utf-8")
    except urllib.error.HTTPError as exc:
        if exc.code == 401 and _retry:
            linked_node_login(sid, force=True)
            return linked_node_request(sid, method, path, raw_body, timeout, _retry=False)
        try:
            ct = exc.headers.get("Content-Type", "application/json; charset=utf-8")
        except Exception:
            ct = "application/json; charset=utf-8"
        return exc.code, exc.read(4 * 1024 * 1024), ct
    except Exception as exc:
        return 502, json.dumps({"ok": False, "error": "node_unreachable: " + str(exc)[:150]}).encode("utf-8"), "application/json; charset=utf-8"


def linked_node_json(sid, method, path, payload=None, timeout=15):
    raw = json.dumps(payload, ensure_ascii=False).encode("utf-8") if payload is not None else None
    code, body, _ = linked_node_request(sid, method, path, raw, timeout)
    try:
        parsed = json.loads(body.decode("utf-8", "ignore") or "{}")
        if not isinstance(parsed, (dict, list)):
            raise ValueError("non-json")
        return code, parsed
    except Exception:
        if 200 <= (code or 0) < 300:
            return 502, {"ok": False, "error": "bad_json", "http_code": code}
        return code, {"ok": False, "error": "bad_json", "http_code": code}


