def atomic_json(path, data):
    tmp = f"{path}.tmp.{os.getpid()}"
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    os.replace(tmp, path)


def atomic_text(path, text):
    tmp = f"{path}.tmp.{os.getpid()}"
    with open(tmp, "w", encoding="utf-8") as f:
        f.write(text)
    os.replace(tmp, path)


def load_users(prune=True):
    try:
        with open(USERS_FILE, "r", encoding="utf-8") as f:
            users = json.load(f)
        if not isinstance(users, list):
            users = []
    except Exception:
        users = []

    clean = []
    changed = False
    current = now_ts()

    for item in users:
        if not isinstance(item, dict):
            changed = True
            continue

        try:
            name = str(item.get("name", ""))
            client_id = str(item.get("uuid", ""))
            expires_at = int(item.get("expires_at", 0))
        except Exception:
            changed = True
            continue

        if not name or not client_id:
            changed = True
            continue

        if prune and expires_at <= current:
            changed = True
            continue

        clean.append(item)

    if prune and changed:
        atomic_json(USERS_FILE, clean)
        write_keys(clean)
        write_config(clean)
        log_action("prune_expired", "api removed expired users")

    return clean


def save_users(users):
    atomic_json(USERS_FILE, users)
    write_keys(users)
    write_config(users)

def _first_query(params, key, default=""):
    values = params.get(key)
    if not values:
        return default
    return urllib.parse.unquote(values[0])


def _alpn_list(value):
    value = urllib.parse.unquote(value or "").replace("http1", "http/1.1")
    return [p for p in (part.strip() for part in value.split(",")) if p]


def direct_outbound_from_link(link):
    link = str(link or "").strip()
    if not link:
        return {
            "protocol": "freedom",
            "tag": "direct",
            "settings": {
                "domainStrategy": "UseIPv4"
            },
        }

    parsed = urllib.parse.urlparse(link)
    if parsed.scheme != "vless" or not parsed.username or not parsed.hostname:
        raise ValueError("bad egress link")

    params = urllib.parse.parse_qs(parsed.query)
    network = _first_query(params, "type", "tcp") or "tcp"
    security = _first_query(params, "security", "none") or "none"
    user = {
        "id": urllib.parse.unquote(parsed.username),
        "encryption": _first_query(params, "encryption", "none") or "none",
    }
    if _first_query(params, "flow"):
        user["flow"] = _first_query(params, "flow")

    outbound = {
        "protocol": "vless",
        "tag": "direct",
        "settings": {
            "vnext": [
                {
                    "address": parsed.hostname,
                    "port": parsed.port or (443 if security in ("tls", "reality") else 80),
                    "users": [user],
                }
            ]
        },
        "streamSettings": {
            "network": network,
            "security": security,
        },
    }
    stream = outbound["streamSettings"]
    sni = _first_query(params, "sni") or _first_query(params, "host") or parsed.hostname

    if security == "tls":
        stream["tlsSettings"] = {
            "serverName": sni,
            "fingerprint": _first_query(params, "fp", "chrome") or "chrome",
        }
        alpn = _alpn_list(_first_query(params, "alpn"))
        if alpn:
            stream["tlsSettings"]["alpn"] = alpn
    elif security == "reality":
        stream["realitySettings"] = {
            "serverName": sni,
            "fingerprint": _first_query(params, "fp", "chrome") or "chrome",
            "publicKey": _first_query(params, "pbk"),
            "shortId": _first_query(params, "sid"),
            "spiderX": _first_query(params, "spx", "/") or "/",
        }

    path = _first_query(params, "path", "/")
    host = _first_query(params, "host")
    if network == "ws":
        stream["wsSettings"] = {"path": path}
        if host:
            stream["wsSettings"]["headers"] = {"Host": host}
    elif network == "xhttp":
        xs = {
            "path": path,
            "mode": _first_query(params, "mode", "packet-up") or "packet-up",
        }
        if host:
            xs["host"] = host
        raw_extra = _first_query(params, "extra")
        if raw_extra:
            try:
                extra = json.loads(raw_extra)
                if isinstance(extra, dict):
                    xs["extra"] = extra
            except Exception:
                pass
        stream["xhttpSettings"] = xs
    elif network == "grpc":
        stream["grpcSettings"] = {"serviceName": _first_query(params, "serviceName")}

    return outbound


def build_egress_config(egress_xray_link):
    # Селективный egress: RU (домены+IP) напрямую, всё остальное через релей.
    # Без egress-ссылки — всё напрямую (поведение как раньше, полностью совместимо).
    eg = direct_outbound_from_link(egress_xray_link)
    if not egress_xray_link:
        return (
            [eg, {"protocol": "freedom", "tag": "api"}],
            {"rules": [{"type": "field", "inboundTag": ["api"], "outboundTag": "api"}]},
        )
    eg["tag"] = "proxy"
    outbounds = [
        eg,
        {"protocol": "freedom", "tag": "direct", "settings": {"domainStrategy": "UseIPv4"}},
        {"protocol": "freedom", "tag": "api"},
    ]
    routing = {
        "domainStrategy": "IPIfNonMatch",
        "rules": [
            {"type": "field", "inboundTag": ["api"], "outboundTag": "api"},
            {"type": "field", "domain": ["geosite:category-ru", "geosite:private"], "outboundTag": "direct"},
            {"type": "field", "ip": ["geoip:ru", "geoip:private"], "outboundTag": "direct"},
        ],
    }
    return (outbounds, routing)


# Человекочитаемые ярлыки способов подключения — идут в remark ссылки (после #),
# чтобы в приложении профиль назывался «имя · способ», а не «нода/CDN».
CHANNEL_LABELS = {"main": "VLESS", "reality": "Reality", "bs": "БС", "wscdn": "WS-CDN"}


def client_remark(name, label):
    name = str(name or "").strip() or "client"
    label = str(label or "").strip()
    return (name + " · " + label) if label else name


def user_channels(user):
    # None => клиент на всех доступных каналах (обратная совместимость: старые/биллинговые
    # юзеры без поля channels). Список (даже пустой) => ровно выбранные каналы.
    ch = user.get("channels") if isinstance(user, dict) else None
    if isinstance(ch, list):
        return set(str(x).strip() for x in ch if str(x).strip())
    return None


def user_wants_channel(user, key):
    sel = user_channels(user)
    return sel is None or key in sel


def _parse_str_list(value):
    # Принимаем JSON-массив ИЛИ csv-строку (форма/квери) -> список непустых строк.
    if isinstance(value, list):
        return [str(x).strip() for x in value if str(x).strip()]
    if isinstance(value, str) and value.strip():
        return [p.strip() for p in value.split(",") if p.strip()]
    return []


def make_ws_link(user):
    name = str(user.get("name", ""))
    client_id = str(user.get("uuid", ""))
    domain = read_domain()
    tag = urllib.parse.quote(client_remark(name, CHANNEL_LABELS["main"]), safe="")
    if str(PUBLIC_PORT) == "443":
        return (
            f"vless://{client_id}@{domain}:{PUBLIC_PORT}"
            f"?type=ws&security=tls&sni={domain}&host={domain}&path=%2Fxray&encryption=none#{tag}"
        )
    return (
        f"vless://{client_id}@{domain}:{PUBLIC_PORT}"
        f"?type=ws&security=none&host={domain}&path=%2Fxray&encryption=none#{tag}"
    )


def make_xhttp_link(user):
    name = str(user.get("name", ""))
    client_id = str(user.get("uuid", ""))
    domain = read_domain()
    security = "tls" if str(PUBLIC_PORT) == "443" else "none"
    return build_xhttp_vless(client_id, domain, PUBLIC_PORT, XHTTP_PATH, domain, client_remark(name, CHANNEL_LABELS["main"]), security=security, sni=domain, method=XHTTP_METHOD)


def make_cdn_ws_link(user):
    if not CDN_WS_ENABLED or not CDN_WS_HOST:
        return ""
    name = str(user.get("name", ""))
    client_id = str(user.get("uuid", ""))
    tag = urllib.parse.quote(client_remark(name, CHANNEL_LABELS["wscdn"]), safe="")
    return (
        f"vless://{client_id}@{CDN_WS_HOST}:{CDN_WS_PORT}"
        f"?security=tls&sni={CDN_WS_SNI}&type=ws&path={urllib.parse.quote(CDN_WS_PATH, safe='')}"
        f"&host={CDN_WS_SNI}&encryption=none#{tag}"
    )


def bs_channel_label():
    # Ярлык БС-канала в remark ссылки (после # → имя профиля в Happ): кастомное имя
    # БС-инбаунда (bs_inbound_name.txt), если задано, иначе короткий дефолт "БС".
    import os as _os
    try:
        with open(_os.path.join(_node_data_dir(), "bs_inbound_name.txt"), "r", encoding="utf-8") as f:
            v = f.read().strip()
            if v:
                return v
    except Exception:
        pass
    return CHANNEL_LABELS["bs"]


def make_cdn_xhttp_link(user):
    if not CDN_XHTTP_ENABLED or not CDN_XHTTP_HOST:
        return ""
    name = str(user.get("name", ""))
    client_id = str(user.get("uuid", ""))
    tag = client_remark(name, bs_channel_label())
    return build_xhttp_vless(client_id, CDN_XHTTP_HOST, CDN_XHTTP_PORT, CDN_XHTTP_PUBLIC_PATH, CDN_XHTTP_SNI, tag, security="tls", sni=CDN_XHTTP_SNI, method=XHTTP_METHOD)


def make_reality_link(user):
    if not REALITY_ENABLED:
        return ""
    name = str(user.get("name", ""))
    client_id = str(user.get("uuid", ""))
    host = REALITY_PUBLIC_HOST or read_domain()
    tag = urllib.parse.quote(client_remark(name, CHANNEL_LABELS["reality"]), safe="")
    reality_flow = os.environ.get("REALITY_FLOW", "xtls-rprx-vision")
    flow_q = f"&flow={reality_flow}" if reality_flow else ""
    reality_spx = urllib.parse.quote(os.environ.get("REALITY_SPX") or "/", safe="")
    return (
        f"vless://{client_id}@{host}:{PUBLIC_REALITY_PORT}"
        f"?type=tcp&security=reality&pbk={REALITY_PUBLIC_KEY}&fp={os.environ.get('REALITY_FP') or 'chrome'}"
        f"&sni={REALITY_SNI}&sid={REALITY_SHORT_ID}&spx={reality_spx}"
        f"{flow_q}&encryption=none#{tag}"
    )


def make_links(user):
    # Клиент получает ссылки ТОЛЬКО по выбранным при создании каналам (channels).
    # Нет поля channels => все доступные (старые/биллинговые клиенты).
    links = {}
    if user_wants_channel(user, "main"):
        if TRANSPORT == "xhttp":
            links["xhttp"] = make_xhttp_link(user)
        else:
            links["ws"] = make_ws_link(user)
    if user_wants_channel(user, "wscdn"):
        cdn_link = make_cdn_ws_link(user)
        if cdn_link:
            links["ws_cdn"] = cdn_link
    if user_wants_channel(user, "bs"):
        cdn_link = make_cdn_xhttp_link(user)
        if cdn_link:
            links["xhttp_cdn"] = cdn_link
    if REALITY_ENABLED and user_wants_channel(user, "reality"):
        links["reality"] = make_reality_link(user)
    return links


def _is_ip_host(value):
    v = str(value or "").strip().strip("[]")
    if not v:
        return False
    # IPv6 (contains ':') or pure-numeric IPv4
    if ":" in v:
        return True
    return bool(re.match(r"^\d{1,3}(\.\d{1,3}){3}$", v))


def make_subscription_url(user):
    if not SUB_PORT:
        return ""
    client_id = urllib.parse.quote(str(user.get("uuid", "")), safe="")
    if not client_id:
        return ""
    # Prefer a trusted router URL (https + domain), else node domain (not raw IP),
    # else fall back to http://IP:PORT.
    router_base = (os.environ.get("ROUTER_SUB_BASE", "") or "").strip().rstrip("/")
    _wd_sub = web_domain_active("sub")
    if router_base:
        url = f"{router_base}/{client_id}"
    elif _wd_sub:
        # Привязан домен с сертификатом → https без порта (iOS не принимает http-подписку).
        url = f"https://{_wd_sub}/sub/{client_id}"
    else:
        host = SUB_PUBLIC_HOST or read_domain()
        domain = read_domain()
        if domain and domain not in ("localhost", host) and not _is_ip_host(domain):
            host = domain
        url = f"http://{host}:{SUB_PORT}/sub/{client_id}"
    if SUB_NAME:
        url += "#" + urllib.parse.quote(SUB_NAME, safe="")
    return url


def user_inbound_links(user):
    # Ссылки клиента по кастомным инбаундам, где он заведён (показываем во вкладке «Клиенты»).
    out = []
    name = str(user.get("name", ""))
    if not name:
        return out
    try:
        host = read_domain()
        for spec in load_custom_inbounds():
            if not isinstance(spec, dict) or not spec.get("enabled", True):
                continue
            if str(spec.get("protocol") or "").lower() in ("socks", "http", "dokodemo-door"):
                continue
            for c in (spec.get("clients") or []):
                if isinstance(c, dict) and c.get("email") == name:
                    link = inbound_client_link(spec, c, host)
                    if link:
                        out.append({
                            "id": spec.get("id"),
                            "tag": spec.get("tag") or spec.get("id"),
                            "protocol": spec.get("protocol") or "vless",
                            "network": spec.get("network") or "tcp",
                            "security": spec.get("security") or "none",
                            "port": spec.get("port"),
                            "link": link,
                        })
    except Exception:
        pass
    return out


def user_all_links(user):
    # Все ссылки клиента (логические каналы + кастомные инбаунды) — для общей подписки.
    out = [v for v in make_links(user).values() if v]
    for il in user_inbound_links(user):
        if il.get("link"):
            out.append(il["link"])
    return out


# ---- WireGuard: пиры живут на ХОСТ-ноде (host-агент), панель общается файл-дропом через том ----
WG_INBOUND_ID = "__wg__"
WG_DEFAULT_PORT = 51820


def _node_data_dir():
    import os as _os
    return _os.path.dirname(_os.path.abspath(CUSTOM_INBOUNDS_FILE))


def wg_port():
    # Публичный UDP-порт WG (обычная аллокация сервера). Хост-агент DNAT'ит его на wg0.
    import os as _os
    try:
        with open(_os.path.join(_node_data_dir(), "wg_port.txt"), "r", encoding="utf-8") as f:
            p = int(f.read().strip())
            if 0 < p <= 65535:
                return p
    except Exception:
        pass
    return WG_DEFAULT_PORT


def _wg_drop_request(fname, obj):
    import os as _os
    try:
        rq = _os.path.join(_node_data_dir(), "wg", "requests")
        _os.makedirs(rq, exist_ok=True)
        tmp = _os.path.join(rq, fname + ".tmp")
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(obj, f)
        _os.replace(tmp, _os.path.join(rq, fname))
    except Exception:
        pass


def wg_set_port(port):
    # Сохраняем выбранный порт и шлём хост-агенту заявку на DNAT (файл-дроп через том).
    import os as _os
    with open(_os.path.join(_node_data_dir(), "wg_port.txt"), "w", encoding="utf-8") as f:
        f.write(str(int(port)))
    _wg_drop_request("__setport__.json", {"action": "set_port", "port": int(port)})


def wg_teardown():
    # Выключаем WG на ноде: снимаем флаг/порт и просим хост-агент убрать DNAT+пиров.
    import os as _os
    d = _node_data_dir()
    _wg_drop_request("__teardown__.json", {"action": "wg_teardown"})
    for fn in ("wg_enabled.txt", "wg_port.txt"):
        try:
            _os.remove(_os.path.join(d, fn))
        except Exception:
            pass


def wg_available():
    import os as _os
    try:
        with open(_os.path.join(_node_data_dir(), "wg_enabled.txt"), "r", encoding="utf-8") as f:
            return f.read().strip() == "1"
    except Exception:
        return False


def wg_request(action, cid, name):
    import os as _os
    try:
        d = _os.path.join(_node_data_dir(), "wg", "requests")
        _os.makedirs(d, exist_ok=True)
        tmp = _os.path.join(d, cid + ".json.tmp")
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump({"action": action, "id": cid, "name": name}, f)
        _os.replace(tmp, _os.path.join(d, cid + ".json"))
        return True
    except Exception:
        return False


def wg_read_conf(cid):
    import os as _os
    try:
        with open(_os.path.join(_node_data_dir(), "wg", "peers", cid + ".conf"), "r", encoding="utf-8") as f:
            return f.read()
    except Exception:
        return ""


def wg_wait_conf(cid, tries=10, delay=0.5):
    import time as _t
    for _ in range(tries):
        conf = wg_read_conf(cid)
        if conf:
            return conf
        _t.sleep(delay)
    return ""


def wg_inbound_payload():
    # Синтетический инбаунд «WireGuard» для списка/выбора (если хост-агент включён).
    if not wg_available():
        return None
    clients = []
    try:
        for u in load_users(prune=False):
            if u.get("banned") or u.get("disabled") or not u.get("wg"):
                continue
            clients.append({"email": u.get("name"), "id": str(u.get("uuid", "")), "link": ""})
    except Exception:
        clients = []
    return {
        "id": WG_INBOUND_ID,
        "tag": "WireGuard",
        "enabled": True,
        "protocol": "wireguard",
        "port": wg_port(),
        "listen": "0.0.0.0",
        "network": "udp",
        "security": "wireguard",
        "stream": {},
        "method": None,
        "clients": clients,
        "clients_count": len(clients),
        "system": True,
    }


def client_payload(user):
    current = now_ts()
    expires_at = int(user.get("expires_at", 0))
    left = max(0, expires_at - current)
    banned = bool(user.get("banned") or user.get("disabled"))
    links = {} if banned else make_links(user)
    inbound_links = [] if banned else user_inbound_links(user)
    subscription_url = "" if banned else make_subscription_url(user)
    _cid = str(user.get("uuid", ""))
    # Общая подписка (все инбаунды клиента в одной ссылке) — отдаётся API-сервером ноды
    # на том же порту, что и панель (без токена, ключ = uuid клиента).
    try:
        sub_all = "" if (banned or not _cid) else public_sub_url(_cid)
    except Exception:
        sub_all = ""
    _wg_on = bool(user.get("wg")) and wg_available()
    wg_conf = wg_read_conf(_cid) if (not banned and _wg_on and _cid) else ""
    client_id = str(user.get("uuid", ""))
    devices = load_devices().get(client_id, [])
    if not isinstance(devices, list):
        devices = []
    traffic_row = load_traffic().get(client_id, {})
    if not isinstance(traffic_row, dict):
        traffic_row = {}
    traffic_used = int(traffic_row.get("used_bytes", 0) or 0)
    traffic_limit = int(user.get("traffic_limit_bytes", 0) or 0)
    device_limit = int(user.get("device_limit", 0) or 0)
    return {
        "name": user.get("name"),
        "uuid": client_id,
        "status": "banned" if banned else "active",
        "banned": banned,
        "banned_at": int(user.get("banned_at", 0) or 0),
        "ban_reason": user.get("ban_reason", ""),
        "created_at": int(user.get("created_at", 0)),
        "expires_at": expires_at,
        "left_seconds": left,
        "left_days": left // 86400,
        "link": links.get("ws") or links.get("xhttp") or "",
        "links": links,
        "channels": user.get("channels"),
        "inbound_links": inbound_links,
        "origin": load_fed_origin().get(client_id) or None,
        "bs_label": bs_channel_label(),
        "subscription_url": subscription_url,
        "sub_url": sub_all,
        "wg": _wg_on,
        "wg_conf": wg_conf,
        "traffic_used_bytes": traffic_used,
        "traffic_used_gb": gb_from_bytes(traffic_used),
        "traffic_limit_bytes": traffic_limit,
        "traffic_limit_gb": gb_from_bytes(traffic_limit),
        "traffic_left_bytes": max(0, traffic_limit - traffic_used) if traffic_limit else None,
        "device_limit": device_limit,
        "devices_count": len(devices),
        "devices": devices,
    }


SUB_PAGE_TEMPLATE_B64 = os.environ.get("SUB_PAGE_B64", "")
SUB_QR_LIB_B64 = os.environ.get("SUB_QR_B64", "")


def _sub_info_badges(link):
    try:
        p = urllib.parse.urlparse(link)
        q = urllib.parse.parse_qs(p.query)
        proto = (p.scheme or "vless").upper()
        typ = (q.get("type", ["tcp"])[0] or "tcp").upper()
        sec = (q.get("security", ["none"])[0] or "none")
        badges = [{"t": proto, "cls": "proto"}, {"t": typ, "cls": "net"}]
        if sec and sec != "none":
            badges.append({"t": sec.upper(), "cls": "sec"})
        tag = urllib.parse.unquote(p.fragment or "") or (p.hostname or "")
        return badges, tag
    except Exception:
        return [{"t": "VLESS", "cls": "proto"}], ""


def render_sub_info_page(user, links, request_host=""):
    import base64 as _b64
    identifier = str(user.get("uuid", ""))
    host = request_host or ("%s:%s" % (read_domain(), API_PORT))
    _wd_sub = web_domain_active("sub")
    if _wd_sub:
        base_url = "https://" + _wd_sub + "/sub/" + urllib.parse.quote(identifier, safe="")
    else:
        base_url = "http://" + host + "/sub/" + urllib.parse.quote(identifier, safe="")
    used = int((load_traffic().get(identifier, {}) or {}).get("used_bytes", 0) or 0)
    last_online = 0
    for row in (load_devices().get(identifier, []) or []):
        if isinstance(row, dict):
            last_online = max(last_online, int(row.get("last_seen", 0) or 0))
    limit = int(user.get("traffic_limit_bytes", 0) or 0)
    expires_at = int(user.get("expires_at", 0) or 0)
    expires_show = 0 if (expires_at > 0 and expires_at - now_ts() > 315360000) else expires_at
    if limit <= 0:
        status, kind = "Неограниченно", "on"
    elif used >= limit:
        status, kind = "Лимит исчерпан", "bad"
    else:
        status, kind = "Активна", "on"
    configs = []
    for link in links:
        badges, tag = _sub_info_badges(link)
        configs.append({"link": link, "badges": badges, "tag": tag})
    data = {
        "id": identifier,
        "email": str(user.get("name", "") or "—"),
        "status": status,
        "status_kind": kind,
        "used_bytes": used,
        "limit_bytes": limit,
        "last_online": last_online,
        "expires_at": expires_show,
        "node": read_node_name() or "",
        "links": {"sub": base_url, "json": base_url + "/json", "clash": base_url + "/clash"},
        "configs": configs,
    }
    if not SUB_PAGE_TEMPLATE_B64:
        return "<!doctype html><meta charset=utf-8><h1>subscription</h1>"
    template = _b64.b64decode(SUB_PAGE_TEMPLATE_B64).decode("utf-8")
    qrlib = _b64.b64decode(SUB_QR_LIB_B64).decode("utf-8")
    payload = json.dumps(data, ensure_ascii=False).replace("</", "<\\/")
    return template.replace("/*__QRLIB__*/", qrlib).replace("__SUB_DATA__", payload)


def query_xray_stats():
    # Live per-client counters straight from the Xray Stats API (same source the
    # bash `vpn stats` / enforce_traffic_limits loop uses). Returns
    # {client_name: {"uplink": int, "downlink": int}} or None if unavailable.
    # NAME and NAME-reality are summed into the base client name.
    if not XRAY_BIN or not os.access(XRAY_BIN, os.X_OK):
        return None
    try:
        proc = subprocess.run(
            [XRAY_BIN, "api", "statsquery", f"--server=127.0.0.1:{XRAY_STATS_PORT}"],
            capture_output=True, timeout=6,
        )
    except Exception:
        return None
    out = (proc.stdout or b"").decode("utf-8", "replace")
    if not out.strip():
        return None
    result = {}
    for match in re.finditer(r'name:\s*"([^"]+)"[\s\S]*?value:\s*([0-9]+)', out):
        stat_name = match.group(1)
        try:
            value = int(match.group(2))
        except ValueError:
            continue
        parts = stat_name.split(">>>")
        if len(parts) < 4 or parts[0] != "user" or parts[2] != "traffic":
            continue
        email = parts[1]
        base = email[:-8] if email.endswith("-reality") else email
        row = result.setdefault(base, {"uplink": 0, "downlink": 0})
        if parts[3] == "uplink":
            row["uplink"] += value
        elif parts[3] == "downlink":
            row["downlink"] += value
    return result


def reality_x25519():
    # Generate an x25519 keypair via the xray binary. Handles all three output
    # formats: "Private key:/Public key:" (old), "PrivateKey:/Password:" (v25.3.6+),
    # "PrivateKey:/Password (PublicKey):" (post XTLS/Xray-core#5759).
    if not XRAY_BIN or not os.access(XRAY_BIN, os.X_OK):
        return None, None
    try:
        out = subprocess.run([XRAY_BIN, "x25519"], capture_output=True, timeout=8).stdout.decode("utf-8", "replace")
    except Exception:
        return None, None
    priv = pub = ""
    for line in out.splitlines():
        if ":" not in line:
            continue
        key, value = line.split(":", 1)
        key = key.strip().lower()
        value = value.strip()
        if "private" in key:
            priv = value
        elif "public" in key or "password" in key:
            pub = value
    return (priv or None), (pub or None)


CUSTOM_INBOUNDS_FILE = os.path.join(os.path.dirname(os.path.abspath(CONFIG_FILE)), "custom_inbounds.json")

# Panel login credentials (username + salted password hash). Provisioned by
# billing via POST /server/panel-credentials; the customer signs into the panel
# with these and receives the node's api_token in exchange (POST /auth/login).
PANEL_AUTH_FILE = os.path.join(os.path.dirname(os.path.abspath(CONFIG_FILE)), "panel_auth.json")


def _hash_password(password, salt):
    return hashlib.sha256((str(salt) + ":" + str(password)).encode("utf-8")).hexdigest()


def load_panel_auth():
    try:
        with open(PANEL_AUTH_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
        if isinstance(data, dict) and data.get("username") and data.get("hash") and data.get("salt"):
            return data
    except Exception:
        pass
    return None


def set_panel_credentials(username, password):
    salt = secrets.token_hex(16)
    data = {
        "username": str(username),
        "salt": salt,
        "hash": _hash_password(password, salt),
        "updated": now_ts(),
    }
    atomic_json(PANEL_AUTH_FILE, data)
    return data


def verify_panel_login(username, password):
    data = load_panel_auth()
    if not data or not username or not password:
        return False
    u_ok = secrets.compare_digest(str(username), str(data.get("username", "")))
    h_ok = secrets.compare_digest(_hash_password(password, data.get("salt", "")), str(data.get("hash", "")))
    return u_ok and h_ok


