async def _h1_kb_admin(message: Message, state: FSMContext) -> None:
    if int(message.from_user.id) not in _h1_admin_ids():
        raise SkipHandler
    if not lic.is_licensed("admin_panel"):
        await message.answer(lic.lock_text("admin_panel"))
