# --- Команды разработчика: включение/выключение модулей ------------------------
def _is_dev(event) -> bool:
    return (
        lic.DEV_TGID > 0
        and event.from_user is not None
        and int(event.from_user.id) == lic.DEV_TGID
    )


_ALIASES = {
    "admin": "admin_panel",
    "admin_panel": "admin_panel",
    "webapp": "webapp",
    "web": "webapp",
}


async def _toggle(message: Message, bot: Bot, value: bool) -> None:
    if not _is_dev(message):
        raise SkipHandler
    parts = (message.text or "").split()
    arg = parts[1].lower() if len(parts) > 1 else ""
    targets = list(lic.KEYS) if arg in ("all", "") else []
    if not targets:
        key = _ALIASES.get(arg)
        if not key:
            await message.answer("Использование: /h1unlock admin|webapp|all")
            return
        targets = [key]
    for key in targets:
        lic.set_licensed(key, value)
    state = "включены" if value else "выключены"
    note = ""
    if "webapp" in targets:
        if value and not lic.webapp_ready():
            note = "\\n\\n\\u26A0\\uFE0F Кнопка Menu не появится: нужен домен с SSL (вкладка «Домены»)."
        else:
            ok = await apply_menu_button(bot)
            if value and ok:
                note = "\\n\\nСиняя кнопка Menu слева от поля ввода обновлена."
    await message.answer(
        "\\u2705 Модули " + state + ": " + ", ".join(lic.TITLES.get(k, k) for k in targets) + note
    )


@router.message(Command("h1unlock"))
async def dev_unlock(message: Message, bot: Bot) -> None:
    await _toggle(message, bot, True)


@router.message(Command("h1lock"))
async def dev_lock(message: Message, bot: Bot) -> None:
    await _toggle(message, bot, False)


@router.message(Command("h1status"))
async def dev_status(message: Message) -> None:
    if not _is_dev(message):
        raise SkipHandler
    data = lic.load_license()
    lines = ["<b>Статус модулей</b>"]
    for key in lic.KEYS:
        mark = "\\u2705" if data.get(key) else "\\u274C"
        lines.append(mark + " " + lic.TITLES.get(key, key) + " (" + str(lic.PRICES.get(key, 0)) + " \\u20bd)")
    lines.append("")
    lines.append("/h1unlock admin|webapp|all — включить")
    lines.append("/h1lock admin|webapp|all — выключить")
    await message.answer("\\n".join(lines))
'''


def shopbot_apply_bot_patch():
    """Докладывает в скачанного бота кнопки платных модулей и dev-разблокировку.
    Идемпотентно — можно звать на каждый старт."""
    if not shopbot_installed():
        return False
    app_dir = os.path.join(SHOPBOT_DIR, "app", "bot")
    with open(os.path.join(app_dir, "h1_license.py"), "w", encoding="utf-8") as f:
        f.write(H1_LICENSE_PY)
    with open(os.path.join(app_dir, "handlers", "h1_locks.py"), "w", encoding="utf-8") as f:
        f.write(H1_LOCKS_PY)

    # 1) роутер локов должен идти ПЕРВЫМ, иначе admin-хендлеры отработают раньше гейта
    init_path = os.path.join(app_dir, "handlers", "__init__.py")
    try:
        with open(init_path, "r", encoding="utf-8") as f:
            src = f.read()
        if "h1_locks" not in src:
            src = src.replace(
                'router = Router(name="handlers")',
                'from app.bot.handlers import h1_locks\n\nrouter = Router(name="handlers")\nrouter.include_router(h1_locks.router)',
                1,
            )
            with open(init_path, "w", encoding="utf-8") as f:
                f.write(src)
    except Exception:
        pass

    # 2) кнопки в главном меню
    kb_path = os.path.join(app_dir, "keyboards.py")
    try:
        with open(kb_path, "r", encoding="utf-8") as f:
            src = f.read()
        if "h1_license" not in src:
            marker = "    return InlineKeyboardMarkup(inline_keyboard=rows)"
            addition = (
                "    try:\n"
                "        from app.bot import h1_license as _h1\n"
                "        rows.extend(_h1.menu_rows(user, settings))\n"
                "    except Exception:\n"
                "        pass\n"
            )
            idx = src.rfind(marker)
            if idx >= 0:
                src = src[:idx] + addition + src[idx:]
                with open(kb_path, "w", encoding="utf-8") as f:
                    f.write(src)
    except Exception:
        pass
    return True


