_SHOPBOT_START_LOCK = _threading.Lock()  # HTTP-рестарт vs автостарт-таймер: без лока получались ДВА бота


def shopbot_orphan_pids():
    """Процессы бота, потерянные pid-файлом (после гонки старта или затёртого pid)."""
    pids = []
    tracked = shopbot_pid()
    try:
        entries = os.listdir("/proc")
    except Exception:
        return pids
    for d in entries:
        if not d.isdigit():
            continue
        pid = int(d)
        if pid == tracked or pid == os.getpid():
            continue
        try:
            with open("/proc/%s/cmdline" % d, "rb") as fh:
                cmd = fh.read().replace(b"\0", b" ")
        except Exception:
            continue
        if b"app.bot.main" in cmd:
            pids.append(pid)
    return pids


def shopbot_sub_base():
    """База страницы подписки этой ноды: {base}/sub/<uuid> — то, что отдаёт нода."""
    dom = web_domain_active("sub")
    if dom:
        return "https://" + dom
    return "http://" + read_domain() + ":" + str(API_PORT)


def shopbot_webapp_own_url():
    """https-адрес Mini App на СОБСТВЕННОМ домене ноды (пусто, если домена нет)."""
    dom = web_domain_active("sub") or web_domain_active("panel")
    if dom:
        return "https://" + dom + "/webapp"
    return ""


def shopbot_webapp_url():
    """https-адрес Mini App для кнопки Menu.

    Telegram открывает приложения только по https, а свой SSL-домен есть не у
    всех нод. Поэтому по умолчанию отдаём ОБЩУЮ витрину на нашем домене (она
    пишет, что модуль не подключён) — кнопка есть у всех сразу. Купивший
    привязывает свой домен и его бот начинает открывать уже своё приложение."""
    paid = shopbot_license().get("webapp")
    dom = web_domain_active("sub") or web_domain_active("panel")
    if paid and dom:
        return "https://" + dom + "/webapp"
    if paid:
        return SHOPBOT_WEBAPP_SHARED_URL + "?paid=1"
    return SHOPBOT_WEBAPP_SHARED_URL


def shopbot_install():
    """Качает исходники бота и ставит зависимости в user-site (~/.local)."""
    zpath = os.path.join(SHOPBOT_BASE, "shopbot_src.zip")
    tmp = os.path.join(SHOPBOT_BASE, "shopbot_tmp")
    try:
        req = urllib.request.Request(SHOPBOT_SRC_URL, headers={"User-Agent": "h1cloud-panel"})
        with urllib.request.urlopen(req, timeout=180) as r:
            blob = r.read()
        with open(zpath, "wb") as f:
            f.write(blob)
        subprocess.run(["rm", "-rf", tmp], check=False)
        with zipfile.ZipFile(zpath) as z:
            z.extractall(tmp)
        roots = [os.path.join(tmp, d) for d in os.listdir(tmp)]
        roots = [d for d in roots if os.path.isdir(d)]
        src = roots[0] if roots else tmp
        subprocess.run(["rm", "-rf", SHOPBOT_DIR], check=False)
        os.rename(src, SHOPBOT_DIR)
    except Exception as exc:
        return False, "не удалось скачать/распаковать бота: %s" % exc
    finally:
        subprocess.run(["rm", "-rf", tmp], check=False)
        try:
            os.remove(zpath)
        except Exception:
            pass

    reqf = os.path.join(SHOPBOT_DIR, "requirements.txt")
    out = ""
    for extra in ([], ["--break-system-packages"]):
        try:
            p = subprocess.run(
                [sys.executable, "-m", "pip", "install", "--user", "--no-cache-dir"] + extra + ["-r", reqf],
                capture_output=True, text=True, timeout=1200,
            )
        except Exception as exc:
            out = "pip не запустился: %s" % exc
            continue
        out = (p.stdout or "") + (p.stderr or "")
        if p.returncode == 0:
            try:
                shopbot_apply_bot_patch()
            except Exception as exc:
                out += "\nпатч кнопок не применился: %s" % exc
            return True, out[-4000:]
    return False, ("не удалось установить зависимости:\n" + out)[-4000:]


def shopbot_write_config(cfg):
    """Генерит .env и config.yml. config.yml пишем JSON'ом — это валидный YAML,
    так не нужен yaml-дампер и не ловим ошибки экранирования."""
    os.makedirs(SHOPBOT_DIR, exist_ok=True)
    os.makedirs(os.path.join(SHOPBOT_DIR, "data"), exist_ok=True)
    sub_base = shopbot_sub_base()
    env_lines = [
        "BOT_TOKEN=" + str(cfg.get("bot_token") or "").strip(),
        "ADMIN_IDS=" + str(cfg.get("admin_ids") or "").strip(),
        "CRYPTOBOT_TOKEN=" + str(cfg.get("cryptobot_token") or "").strip(),
        "DB_PATH=data/shop.db",
        "PUBLIC_BASE_URL=" + sub_base + "/sub",
        "CONFIG_PATH=config.yml",
        # --- платные модули H1Cloud: состояние лицензий и кто их включает ---
        "H1_LICENSE_FILE=" + SHOPBOT_LICENSE_FILE,
        "H1_DEV_TGID=" + str(SHOPBOT_DEV_TGID),
        "H1_DEV_CONTACT=" + SHOPBOT_DEV_CONTACT,
        "H1_PRICE_ADMIN=" + str(SHOPBOT_ADMIN_PRICE),
        "H1_PRICE_WEBAPP=" + str(SHOPBOT_WEBAPP_PRICE),
        "H1_SUB_BASE=" + sub_base,
        # Бот выбирает адрес Mini App САМ по текущей лицензии (см. h1_license.py):
        # тут только исходные данные, а не готовый URL — иначе он замораживается.
        "H1_WEBAPP_SHARED_URL=" + SHOPBOT_WEBAPP_SHARED_URL,
        "H1_WEBAPP_OWN_URL=" + shopbot_webapp_own_url(),
        "H1_WEBAPP_URL=" + shopbot_webapp_url(),
        "",
    ]
    with open(os.path.join(SHOPBOT_DIR, ".env"), "w", encoding="utf-8") as f:
        f.write("\n".join(env_lines))

    trial = cfg.get("trial") if isinstance(cfg.get("trial"), dict) else {}
    plans = []
    for p in (cfg.get("plans") or []):
        if not isinstance(p, dict):
            continue
        plans.append({
            "id": str(p.get("id") or "").strip(),
            "title": str(p.get("title") or "").strip(),
            "days": parse_int(p.get("days"), 30),
            "traffic_gb": parse_int(p.get("traffic_gb"), 0),
            "devices": parse_int(p.get("devices"), 0),
            "price_rub": parse_int(p.get("price_rub"), 0),
            "price_stars": parse_int(p.get("price_stars"), 0),
        })
    doc = {
        "shop_name": str(cfg.get("shop_name") or NODE_NAME or "VPN Shop"),
        "support_url": str(cfg.get("support_url") or ""),
        "channel_url": str(cfg.get("channel_url") or ""),
        "trial": {
            "enabled": bool(trial.get("enabled", True)),
            "days": parse_int(trial.get("days"), 3),
            "traffic_gb": parse_int(trial.get("traffic_gb"), 0),
            "devices": parse_int(trial.get("devices"), 1),
        },
        "referral_percent": parse_int(cfg.get("referral_percent"), 0),
        "topup_amounts": [parse_int(x, 0) for x in (cfg.get("topup_amounts") or []) if parse_int(x, 0) > 0],
        "servers": [{
            "key": "main",
            "name": "🌍 Все локации",
            # бот живёт на этой же ноде — ходим в API по локалхосту, без публичного IP
            "api_url": "http://127.0.0.1:" + str(API_PORT),
            "api_token": API_TOKEN,
            "sub_url": sub_base,
            "verify_ssl": False,
        }],
        "plans": plans,
        "stars_per_rub": float(cfg.get("stars_per_rub") or 0.7),
    }
    with open(os.path.join(SHOPBOT_DIR, "config.yml"), "w", encoding="utf-8") as f:
        json.dump(doc, f, ensure_ascii=False, indent=2)


def shopbot_stop():
    pid = shopbot_pid()
    if pid > 0:
        for sig in (15, 9):
            try:
                os.kill(pid, sig)
            except Exception:
                break
            for _ in range(20):
                if not shopbot_running():
                    break
                time.sleep(0.15)
            if not shopbot_running():
                break
    try:
        os.remove(SHOPBOT_PID_FILE)
    except Exception:
        pass
    # добить сирот — иначе второй экземпляр держит getUpdates и бот "конфликтует сам с собой"
    for opid in shopbot_orphan_pids():
        for sig in (15, 9):
            try:
                os.kill(opid, sig)
                time.sleep(0.3)
            except Exception:
                break
    return not shopbot_running()


def shopbot_start(cfg=None):
    with _SHOPBOT_START_LOCK:
        return _shopbot_start_locked(cfg)


def _shopbot_start_locked(cfg=None):
    cfg = cfg or load_shopbot_cfg()
    if shopbot_running():
        return True, "уже запущен"
    orphans = shopbot_orphan_pids()
    if orphans:
        # бот жив, просто pid-файл его потерял — усыновляем вместо второго запуска
        with open(SHOPBOT_PID_FILE, "w") as f:
            f.write(str(orphans[0]))
        for extra in orphans[1:]:
            for sig in (15, 9):
                try:
                    os.kill(extra, sig)
                    time.sleep(0.3)
                except Exception:
                    break
        return True, "уже запущен"
    if not shopbot_installed():
        return False, "бот не установлен — нажми «Установить»"
    if not str(cfg.get("bot_token") or "").strip():
        return False, "не задан токен бота"
    if not str(cfg.get("admin_ids") or "").strip():
        return False, "не задан admin id"
    if not (cfg.get("plans") or []):
        return False, "не задан ни один тариф"
    try:
        shopbot_write_config(cfg)
        # патч идемпотентен: переживает обновление бота из репозитория
        shopbot_apply_bot_patch()
    except Exception as exc:
        return False, "не удалось записать конфиг: %s" % exc
    try:
        logf = open(SHOPBOT_LOG_FILE, "ab", buffering=0)
        env = dict(os.environ)
        env["PYTHONUNBUFFERED"] = "1"
        proc = subprocess.Popen(
            [sys.executable, "-m", "app.bot.main"],
            cwd=SHOPBOT_DIR, stdout=logf, stderr=logf, env=env, start_new_session=True,
        )
    except Exception as exc:
        return False, "не удалось запустить процесс: %s" % exc
    with open(SHOPBOT_PID_FILE, "w") as f:
        f.write(str(proc.pid))
    time.sleep(2.0)
    if proc.poll() is not None:
        return False, "бот упал сразу после старта — смотри логи ниже"
    return True, "бот запущен"


