def _shopbot_patch_stale():
    """Файлы патча в боте отличаются от актуальных — бот крутит старый код модулей."""
    try:
        app_dir = os.path.join(SHOPBOT_DIR, "app", "bot")
        with open(os.path.join(app_dir, "h1_license.py"), encoding="utf-8") as fh:
            if fh.read() != H1_LICENSE_PY:
                return True
        with open(os.path.join(app_dir, "handlers", "h1_locks.py"), encoding="utf-8") as fh:
            if fh.read() != H1_LOCKS_PY:
                return True
        return False
    except Exception:
        return True


def _shopbot_autostart():
    try:
        cfg = load_shopbot_cfg()
        if not shopbot_installed():
            return
        if shopbot_running():
            # панель обновилась, а бот держит старый патч модулей в памяти —
            # без этого выданные /h1unlock лицензии не отображаются у клиента
            if _shopbot_patch_stale():
                log_action("shopbot_patch_refresh", "restart after panel update")
                shopbot_stop()
                shopbot_start(cfg)
        elif cfg.get("autostart"):
            shopbot_start(cfg)
    except Exception:
        pass


try:
    import threading as _sb_threading
    _sb_threading.Timer(6.0, _shopbot_autostart).start()
except Exception:
    pass


# ---------------- Миграция с чужих панелей (3x-ui / Remnawave) ----------------
# Владелец вводит адрес + доступы старой панели — переносим всех клиентов
# (uuid сохраняется, значит выданные ссылки/подписки menyat не надо только хост).
MIGRATE_STATE = {"running": False, "phase": "idle", "log": [], "done": 0, "total": 0,
                 "imported": 0, "skipped": 0, "failed": 0, "result": None, "error": None, "source": None}
_MIGRATE_LOCK = _threading.Lock()


def _mig_log(msg, kind="info"):
    MIGRATE_STATE.setdefault("log", []).append({"t": now_ts(), "kind": kind, "msg": str(msg)[:300]})
    if len(MIGRATE_STATE["log"]) > 500:
        MIGRATE_STATE["log"] = MIGRATE_STATE["log"][-400:]


def _mig_http(method, url, headers=None, body=None, timeout=25):
    import ssl as _ssl
    ctx = _ssl.create_default_context()
    ctx.check_hostname = False
    ctx.verify_mode = _ssl.CERT_NONE  # чужие панели почти всегда на самоподписанных сертах
    req = urllib.request.Request(url, data=body, method=method)
    for k, v in (headers or {}).items():
        req.add_header(k, v)
    return urllib.request.urlopen(req, timeout=timeout, context=ctx)


def _mig_base(url, default_scheme="http"):
    base = str(url or "").strip().rstrip("/")
    if base and not base.startswith(("http://", "https://")):
        base = default_scheme + "://" + base
    return base


def _mig_name_sanitize(raw, taken, fallback_idx):
    name = re.sub(r"[^A-Za-z0-9._-]", "-", str(raw or "").strip())[:32].strip("-.") or ("mig-user-%d" % fallback_idx)
    base = name
    n = 2
    while name.lower() in taken:
        name = "%s-%d" % (base[:28], n)
        n += 1
    taken.add(name.lower())
    return name


def _xui_login(base, username, password):
    body = urllib.parse.urlencode({"username": username, "password": password}).encode()
    resp = _mig_http("POST", base + "/login",
                     {"Content-Type": "application/x-www-form-urlencoded", "Accept": "application/json"}, body)
    raw = resp.read().decode("utf-8", "replace")
    try:
        parsed = json.loads(raw)
        if isinstance(parsed, dict) and parsed.get("success") is False:
            raise ValueError("3x-ui отклонила логин/пароль: " + str(parsed.get("msg") or ""))
    except ValueError:
        raise
    except Exception:
        pass
    cookies = []
    for h, v in resp.headers.items():
        if h.lower() == "set-cookie":
            cookies.append(v.split(";")[0])
    if not cookies:
        raise ValueError("3x-ui не вернула cookie сессии — проверь логин/пароль и URL (включая секретный путь)")
    return "; ".join(cookies)


def _xui_fetch(url, username, password):
    base = _mig_base(url)
    cookie = _xui_login(base, username, password)
    resp = _mig_http("GET", base + "/panel/api/inbounds/list", {"Cookie": cookie, "Accept": "application/json"})
    data = json.loads(resp.read().decode("utf-8", "replace"))
    if not isinstance(data, dict) or not data.get("success"):
        raise ValueError("3x-ui: не удалось получить инбаунды (" + str((data or {}).get("msg") or "нет success") + ")")
    inbounds, clients = [], []
    for ib in (data.get("obj") or []):
        remark = str(ib.get("remark") or ("inbound-" + str(ib.get("id"))))
        inbounds.append({"remark": remark, "port": ib.get("port"),
                         "protocol": str(ib.get("protocol") or ""), "enabled": bool(ib.get("enable", True))})
        try:
            settings = json.loads(ib.get("settings") or "{}")
        except Exception:
            settings = {}
        for c in (settings.get("clients") or []):
            if not isinstance(c, dict):
                continue
            exp = c.get("expiryTime") or 0
            try:
                exp = int(exp)
            except Exception:
                exp = 0
            if exp < 0:  # «N мс после первого подключения» — считаем срок от сегодня
                exp = now_ts() * 1000 + abs(exp)
            total = c.get("totalGB") or c.get("total") or 0
            try:
                total = int(total)
            except Exception:
                total = 0
            clients.append({
                "name": str(c.get("email") or "").strip(),
                "uuid": str(c.get("id") or "").strip(),
                "proto": str(ib.get("protocol") or ""), "inbound": remark,
                "expires_ms": exp, "limit_bytes": total if total > 0 else 0,
                "device_limit": parse_int(c.get("limitIp"), 0) or 0,
                "enabled": bool(c.get("enable", True)),
            })
    return {"panel": "3x-ui", "inbounds": inbounds, "clients": clients}


def _remna_fetch(url, token):
    import datetime as _dt
    base = _mig_base(url, "https")
    headers = {"Authorization": "Bearer " + token, "Accept": "application/json"}
    users, start, size = [], 0, 250
    while True:
        resp = _mig_http("GET", base + "/api/users?start=%d&size=%d" % (start, size), headers)
        data = json.loads(resp.read().decode("utf-8", "replace"))
        payload = data.get("response") if isinstance(data, dict) and isinstance(data.get("response"), dict) else data
        if isinstance(payload, dict):
            chunk = payload.get("users")
            total = payload.get("total")
        else:
            chunk, total = payload, None
        if not isinstance(chunk, list):
            chunk = []
        users.extend(chunk)
        if not chunk or total is None or len(users) >= parse_int(total, 0):
            break
        start += size
    clients = []
    for u in users:
        if not isinstance(u, dict):
            continue
        exp = 0
        expire_at = u.get("expireAt") or u.get("expire_at")
        if expire_at:
            try:
                s = str(expire_at).replace("Z", "+00:00")
                exp = int(_dt.datetime.fromisoformat(s).timestamp() * 1000)
            except Exception:
                exp = 0
        clients.append({
            "name": str(u.get("username") or "").strip(),
            "uuid": str(u.get("vlessUuid") or u.get("uuid") or "").strip(),
            "proto": "vless", "inbound": "",
            "expires_ms": exp,
            "limit_bytes": parse_int(u.get("trafficLimitBytes"), 0) or 0,
            "device_limit": parse_int(u.get("hwidDeviceLimit"), 0) or 0,
            "enabled": str(u.get("status") or "ACTIVE").upper() == "ACTIVE",
        })
    inbounds = []
    try:
        resp = _mig_http("GET", base + "/api/inbounds", headers)
        data = json.loads(resp.read().decode("utf-8", "replace"))
        payload = data.get("response") if isinstance(data, dict) and isinstance(data.get("response"), dict) else data
        arr = payload.get("inbounds") if isinstance(payload, dict) else payload
        for ib in (arr or []):
            if isinstance(ib, dict):
                inbounds.append({"remark": str(ib.get("tag") or ib.get("remark") or ""), "port": ib.get("port"),
                                 "protocol": str(ib.get("type") or ib.get("protocol") or ""), "enabled": True})
    except Exception:
        pass
    return {"panel": "remnawave", "inbounds": inbounds, "clients": clients}


def _migrate_fetch(payload):
    src = str(payload.get("source") or "").strip().lower()
    url = str(payload.get("url") or "").strip()
    if not url:
        raise ValueError("не указан адрес панели-источника")
    if src in ("xui", "3x-ui", "3xui", "x-ui"):
        u = str(payload.get("username") or "").strip()
        p = str(payload.get("password") or "")
        if not u or not p:
            raise ValueError("для 3x-ui нужны логин и пароль")
        return _xui_fetch(url, u, p)
    if src in ("remna", "remnawave"):
        t = str(payload.get("token") or payload.get("api_key") or "").strip()
        if not t:
            raise ValueError("для Remnawave нужен API-токен")
        return _remna_fetch(url, t)
    raise ValueError("неизвестный источник: " + (src or "пусто"))


def migrate_probe(payload):
    data = _migrate_fetch(payload)
    active = sum(1 for c in data["clients"] if c.get("enabled", True))
    return {"ok": True, "panel": data["panel"], "clients": len(data["clients"]), "active": active,
            "inbounds": [{"remark": i["remark"], "port": i["port"], "protocol": i["protocol"]}
                         for i in data["inbounds"]][:20],
            "inbounds_total": len(data["inbounds"]),
            "sample": [c.get("name") or "?" for c in data["clients"]][:12]}


def _migrate_worker(payload):
    try:
        MIGRATE_STATE.update({"phase": "fetch", "error": None})
        _mig_log("Подключаюсь к " + str(payload.get("url") or "") + "…")
        data = _migrate_fetch(payload)
        clients = data["clients"]
        MIGRATE_STATE.update({"phase": "import", "total": len(clients), "done": 0})
        _mig_log("Источник: %s. Клиентов: %d, инбаундов: %d" % (data["panel"], len(clients), len(data["inbounds"])))
        users = load_users()
        existing_uuids = set(str(u.get("uuid")) for u in users)
        taken = set(str(u.get("name", "")).lower() for u in users)
        current = now_ts()
        default_days = parse_int(payload.get("default_days"), 3650) or 3650
        imported = skipped = failed = 0
        for idx, c in enumerate(clients):
            MIGRATE_STATE["done"] = idx + 1
            label = c.get("name") or (str(c.get("uuid") or "?")[:8])
            try:
                cid = str(c.get("uuid") or "").strip()
                try:
                    cid = str(uuid.UUID(cid))
                except Exception:
                    cid = str(uuid.uuid4())  # trojan/ss без uuid — выдаём новый
                if cid in existing_uuids:
                    skipped += 1
                    MIGRATE_STATE["skipped"] = skipped
                    _mig_log("= %s — уже есть на этой ноде (uuid совпал), пропуск" % label, "skip")
                    continue
                exp_ms = int(c.get("expires_ms") or 0)
                if exp_ms and exp_ms // 1000 <= current:
                    skipped += 1
                    MIGRATE_STATE["skipped"] = skipped
                    _mig_log("~ %s — срок истёк ещё на старой панели, пропуск" % label, "skip")
                    continue
                name = _mig_name_sanitize(c.get("name"), taken, idx + 1)
                rec = {"name": name, "uuid": cid, "created_at": current,
                       "expires_at": (exp_ms // 1000) if exp_ms else current + default_days * 86400,
                       "banned": (not c.get("enabled", True))}
                lb = parse_int(c.get("limit_bytes"), 0) or 0
                if lb > 0:
                    rec["traffic_limit_bytes"] = lb
                    rec["traffic_reset_pending"] = True
                dl = parse_int(c.get("device_limit"), 0) or 0
                if dl > 0:
                    rec["device_limit"] = dl
                users.append(rec)
                existing_uuids.add(cid)
                imported += 1
                MIGRATE_STATE["imported"] = imported
                _mig_log("+ %s -> перенесён" % name, "ok")
            except Exception as exc:
                failed += 1
                MIGRATE_STATE["failed"] = failed
                _mig_log("! %s — ошибка: %s" % (label, exc), "err")
        MIGRATE_STATE["phase"] = "save"
        _mig_log("Сохраняю клиентов и перезапускаю xray…")
        save_users(users)
        atomic_text(XRAY_RESTART_REQUEST_FILE, "migrate %d\n" % now_ts())
        MIGRATE_STATE.update({"phase": "done", "result": {
            "panel": data["panel"], "imported": imported, "skipped": skipped, "failed": failed,
            "total": len(clients), "inbounds_seen": len(data["inbounds"])}})
        _mig_log("Готово: перенесено %d, пропущено %d, ошибок %d" % (imported, skipped, failed), "ok")
        log_action("migrate_done", "%s +%d ~%d !%d" % (data["panel"], imported, skipped, failed))
    except Exception as exc:
        MIGRATE_STATE.update({"phase": "error", "error": str(exc)})
        _mig_log("Миграция прервана: %s" % exc, "err")
        log_action("migrate_failed", str(exc))
    finally:
        MIGRATE_STATE["running"] = False


# Curated dest/SNI targets known to serve TLS1.3 + H2 (good Reality camouflage).
REALITY_TARGET_SUGGESTIONS = [
    "www.microsoft.com", "www.cloudflare.com", "www.apple.com", "www.amazon.com",
    "dl.google.com", "www.samsung.com", "www.nvidia.com", "www.tesla.com",
    "www.lovelive-anime.jp", "www.swift.com", "yahoo.com", "www.bing.com",
]


def reality_scan(target):
    # Connect FROM this node to target:port and check Reality-dest suitability:
    # TLS 1.3 support + HTTP/2 ALPN + read cert SANs (candidate SNIs).
    import socket
    import ssl
    raw = str(target or "").strip()
    raw = re.sub(r"^[a-zA-Z]+://", "", raw).split("/")[0].strip()
    port = 443
    host = raw
    if raw.count(":") == 1:
        host, p = raw.rsplit(":", 1)
        try:
            port = int(p)
        except ValueError:
            port = 443
    if not host:
        return {"ok": False, "error": "bad_target"}

    result = {"ok": False, "target": host, "port": port, "tls13": False, "h2": False,
              "tls_version": None, "alpn": None, "sni_suggestions": [], "cert": {}}

    # Step 1: permissive handshake — always yields negotiated version + ALPN.
    try:
        ctx = ssl.SSLContext(ssl.PROTOCOL_TLS_CLIENT)
        ctx.check_hostname = False
        ctx.verify_mode = ssl.CERT_NONE
        try:
            ctx.minimum_version = ssl.TLSVersion.TLSv1_2
        except Exception:
            pass
        try:
            ctx.set_alpn_protocols(["h2", "http/1.1"])
        except Exception:
            pass
        with socket.create_connection((host, port), timeout=6) as sock:
            with ctx.wrap_socket(sock, server_hostname=host) as ss:
                result["tls_version"] = ss.version()
                result["alpn"] = ss.selected_alpn_protocol()
                result["tls13"] = ss.version() == "TLSv1.3"
                result["h2"] = ss.selected_alpn_protocol() == "h2"
    except Exception as exc:
        result["error"] = f"connect_failed: {exc}"
        return result

    # Step 2: verified handshake to read the certificate SANs (best-effort).
    sans = []
    try:
        vctx = ssl.create_default_context()
        with socket.create_connection((host, port), timeout=6) as sock:
            with vctx.wrap_socket(sock, server_hostname=host) as ss:
                cert = ss.getpeercert() or {}
        result["cert"] = {
            "subject": dict(x[0] for x in cert.get("subject", [])).get("commonName", ""),
            "issuer": dict(x[0] for x in cert.get("issuer", [])).get("organizationName", ""),
            "expires": cert.get("notAfter", ""),
        }
        for typ, val in cert.get("subjectAltName", []):
            if typ == "DNS" and not val.startswith("*") and val not in sans:
                sans.append(val)
    except Exception:
        pass
    if host not in sans:
        sans.insert(0, host)
    result["sni_suggestions"] = sans[:12]
    result["ok"] = True
    result["suitable"] = bool(result["tls13"])
    return result


def load_custom_inbounds():
    try:
        with open(CUSTOM_INBOUNDS_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
        return data if isinstance(data, list) else []
    except Exception:
        return []


def save_custom_inbounds(items):
    atomic_json(CUSTOM_INBOUNDS_FILE, items)


def _panel_mode_active():
    import os as _os
    try:
        p = _os.path.join(_os.path.dirname(_os.path.abspath(CUSTOM_INBOUNDS_FILE)), "panel_mode.txt")
        with open(p, "r", encoding="utf-8") as f:
            return f.read().strip() == "1"
    except Exception:
        return False


def _owned_ports():
    """Порты, реально выделенные этому серверу (billing пишет allocations.json)."""
    import os as _os
    try:
        af = _os.path.join(_os.path.dirname(_os.path.abspath(CUSTOM_INBOUNDS_FILE)), "allocations.json")
        with open(af, "r", encoding="utf-8") as f:
            data = json.load(f)
        if isinstance(data, dict):
            data = data.get("ports") or data.get("allocations") or []
        out = []
        for it in (data or []):
            p = it.get("port") if isinstance(it, dict) else it
            try:
                p = int(p)
            except Exception:
                continue
            if 0 < p <= 65535 and p not in out:
                out.append(p)
        return out
    except Exception:
        return []


def _bs_inbound_port():
    """Порт обход-инбаунда: в панель-режиме = минимальный НЕ-первичный выделенный
    порт (панель занимает первичный SERVER_PORT). Вне панель-режима = первичный.
    Должно совпадать с backend_port, на который billing онбордит шлюз БС."""
    try:
        primary = int(XRAY_PORT)
    except Exception:
        return XRAY_PORT
    if not _panel_mode_active():
        return primary
    non_primary = sorted(p for p in _owned_ports() if p != primary)
    return non_primary[0] if non_primary else primary


def list_allocations():
    """Ports allocated to this Pterodactyl server (billing writes allocations.json),
    split into used (by our services / existing inbounds) and free."""
    import os as _os
    all_ports = []
    try:
        alloc_file = _os.path.join(_os.path.dirname(_os.path.abspath(CUSTOM_INBOUNDS_FILE)), "allocations.json")
        with open(alloc_file, "r", encoding="utf-8") as f:
            data = json.load(f)
        if isinstance(data, dict):
            data = data.get("ports") or data.get("allocations") or []
        for item in (data or []):
            p = item.get("port") if isinstance(item, dict) else item
            try:
                p = int(p)
            except Exception:
                continue
            if 0 < p <= 65535 and p not in all_ports:
                all_ports.append(p)
    except Exception:
        all_ports = []
    if not all_ports:
        try:
            base = int(XRAY_PORT)
            all_ports = [base + i for i in range(0, 8) if base + i <= 65535]
        except Exception:
            all_ports = []
    used = set()
    if _panel_mode_active():
        _core = [API_PORT]
        if CDN_XHTTP_ENABLED and CDN_XHTTP_HOST:
            _core.append(_bs_inbound_port())
    else:
        _core = (XRAY_PORT, API_PORT, REALITY_PORT, SUB_PORT)
    for p in _core:
        try:
            p = int(p)
        except Exception:
            continue
        if p > 0:
            used.add(p)
    for spec in load_custom_inbounds():
        try:
            used.add(int(spec.get("port")))
        except Exception:
            pass
    if wg_available():
        try:
            used.add(int(wg_port()))
        except Exception:
            pass
    available = [p for p in all_ports if p not in used]
    return {
        "ports": all_ports,
        "used": sorted(p for p in used if p in all_ports),
        "available": available,
    }


def inbound_client_link(spec, client, host):
    # Build a connect link for one client of a custom inbound.
    proto = str(spec.get("protocol", "")).lower()
    port = spec.get("port")
    network = str(spec.get("network") or "tcp").lower()
    security = str(spec.get("security") or "none").lower()
    stream = spec.get("stream") if isinstance(spec.get("stream"), dict) else {}
    _email = str(client.get("email") or "").strip()
    _tag = str(spec.get("tag") or "").strip() or proto
    label = client_remark(_email or _tag, _tag if _email else "")

    params = {"type": network, "security": security}
    if network == "ws":
        params["path"] = stream.get("path") or "/"
        if stream.get("host"):
            params["host"] = stream["host"]
    elif network == "grpc":
        params["serviceName"] = stream.get("serviceName") or stream.get("service_name") or ""
    elif network in ("xhttp", "httpupgrade"):
        params["path"] = stream.get("path") or "/"
        if stream.get("host"):
            params["host"] = stream["host"]
        if network == "xhttp":
            params["mode"] = stream.get("mode") or "auto"
    if security == "tls":
        if stream.get("sni"):
            params["sni"] = stream["sni"]
        params["fp"] = stream.get("fp") or "chrome"
        if stream.get("alpn"):
            params["alpn"] = stream["alpn"]
    elif security == "reality":
        params["sni"] = stream.get("sni") or ""
        params["fp"] = stream.get("fp") or "chrome"
        params["pbk"] = stream.get("public_key") or stream.get("publicKey") or ""
        params["sid"] = stream.get("short_id") or stream.get("shortId") or ""
        params["spx"] = stream.get("spx") or "/"

    def qs(extra=None):
        merged = dict(params)
        if extra:
            merged.update(extra)
        return urllib.parse.urlencode({k: v for k, v in merged.items() if v not in ("", None)})

    frag = urllib.parse.quote(label, safe="")
    if proto == "vless":
        flow = client.get("flow") or ""
        query = qs({"encryption": "none", "flow": flow} if flow else {"encryption": "none"})
        return f"vless://{client.get('id','')}@{host}:{port}?{query}#{frag}"
    if proto == "trojan":
        return f"trojan://{client.get('password','')}@{host}:{port}?{qs()}#{frag}"
    if proto == "vmess":
        body = {
            "v": "2", "ps": label, "add": host, "port": str(port), "id": client.get("id", ""),
            "aid": "0", "scy": "auto", "net": network, "type": "none",
            "host": stream.get("host", "") if network in ("ws", "xhttp", "httpupgrade") else "",
            "path": stream.get("path", "") if network in ("ws", "xhttp", "httpupgrade") else (stream.get("serviceName", "") if network == "grpc" else ""),
            "tls": "tls" if security == "tls" else "",
            "sni": stream.get("sni", "") if security == "tls" else "",
        }
        raw = base64_encode_json(body)
        return f"vmess://{raw}"
    if proto == "shadowsocks":
        method = spec.get("method") or client.get("method") or "aes-256-gcm"
        password = spec.get("password") or client.get("password") or ""
        userinfo = _b64(f"{method}:{password}".encode("utf-8"))
        return f"ss://{userinfo}@{host}:{port}#{frag}"
    return ""


def _b64(data):
    import base64 as _bb
    return _bb.b64encode(data).decode("ascii")


def base64_encode_json(obj):
    import base64 as _bb
    return _bb.b64encode(json.dumps(obj, ensure_ascii=False).encode("utf-8")).decode("ascii")


def custom_inbound_payload(spec):
    host = read_domain()
    clients = spec.get("clients") if isinstance(spec.get("clients"), list) else []
    out_clients = []
    for c in clients:
        if not isinstance(c, dict):
            continue
        out_clients.append({
            **c,
            "link": inbound_client_link(spec, c, host),
        })
    return {
        "id": spec.get("id"),
        "tag": spec.get("tag"),
        "enabled": bool(spec.get("enabled", True)),
        "protocol": spec.get("protocol"),
        "port": spec.get("port"),
        "listen": spec.get("listen", "0.0.0.0"),
        "network": spec.get("network", "tcp"),
        "security": spec.get("security", "none"),
        "stream": spec.get("stream", {}),
        "method": spec.get("method"),
        "clients": out_clients,
        "clients_count": len(out_clients),
    }


# Синтетический id главного LTE/обход-инбаунда (xhttp-CDN). В панель-режиме этот инбаунд
# создаётся не через custom_inbounds.json, а как главный inbound с body-схемой обхода —
# показываем его в списке панели read-only (клиентами рулит вкладка «Клиенты»).
BS_MAIN_INBOUND_ID = "__bs_main__"


def bs_inbound_name():
    # Отображаемое имя БС-инбаунда: кастомный override (файл) или дефолт из CDN-тега.
    import os as _os
    try:
        with open(_os.path.join(_node_data_dir(), "bs_inbound_name.txt"), "r", encoding="utf-8") as f:
            v = f.read().strip()
            if v:
                return v
    except Exception:
        pass
    return (CDN_XHTTP_TAG or "CDN") + " · обход (BS)"


def bs_main_inbound_payload():
    """Read-only карточка главного обход-инбаунда для списка панели (если LTE/CDN включён)."""
    if not (CDN_XHTTP_ENABLED and CDN_XHTTP_HOST):
        return None
    clients = []
    try:
        for u in load_users(prune=False):
            if u.get("banned") or u.get("disabled"):
                continue
            # только клиенты, у которых выбран канал БС/обход (или без выбора = все)
            if not user_wants_channel(u, "bs"):
                continue
            link = make_cdn_xhttp_link(u) or ""
            clients.append({
                "email": u.get("name"),
                "id": str(u.get("uuid", "")),
                "link": link,
            })
    except Exception:
        clients = []
    return {
        "id": BS_MAIN_INBOUND_ID,
        "tag": bs_inbound_name(),
        "enabled": True,
        "protocol": "vless",
        "port": _bs_inbound_port(),
        "listen": "0.0.0.0",
        "network": "xhttp",
        "security": "none",
        "stream": {"path": CDN_XHTTP_PUBLIC_PATH, "host": CDN_XHTTP_HOST, "mode": "packet-up"},
        "method": None,
        "clients": clients,
        "clients_count": len(clients),
        "system": True,
    }


def status_payload(users):
    current = now_ts()
    active = []
    expired = []
    banned = []
    for user in users:
        try:
            if user.get("banned") or user.get("disabled"):
                banned.append(user)
            elif int(user.get("expires_at", 0)) > current:
                active.append(user)
            else:
                expired.append(user)
        except Exception:
            expired.append(user)

    return {
        "ok": True,
        "service": "vpn-api",
        "version": os.environ.get("SCRIPT_VERSION") or "",
        "node_name": read_node_name(),
        "domain": read_domain(),
        "api": {
            "port": API_PORT,
        },
        "ws": {
            "local_port": XRAY_PORT,
            "public_port": PUBLIC_PORT,
            "path": "/xray",
        },
        "transport": {
            "mode": TRANSPORT,
            "xhttp_path": XHTTP_PATH,
            "xhttp_uplink_method": XHTTP_METHOD,
        },
        "cdn_ws": {
            "enabled": bool(CDN_WS_ENABLED and CDN_WS_HOST),
            "host": CDN_WS_HOST,
            "sni": CDN_WS_SNI,
            "port": CDN_WS_PORT,
            "tag_suffix": CDN_WS_TAG,
            "path": CDN_WS_PATH,
        },
        "cdn_xhttp": {
            "enabled": bool(CDN_XHTTP_ENABLED and CDN_XHTTP_HOST),
            "host": CDN_XHTTP_HOST,
            "sni": CDN_XHTTP_SNI,
            "port": CDN_XHTTP_PORT,
            "tag_suffix": CDN_XHTTP_TAG,
            "public_path": CDN_XHTTP_PUBLIC_PATH,
