#logo .cur { display: inline-block; width: 8px; height: 15px; background: var(--acc); margin-left: 4px; vertical-align: -2px; animation: blink 1.1s steps(1) infinite; }
@keyframes blink { 50% { opacity: 0; } }
#logo .l2 { font-size: 9.5px; color: var(--dim); letter-spacing: .22em; text-transform: uppercase; margin-top: 4px; }
nav { padding: 10px 0; flex: 1; overflow-y: auto; }
nav a {
  display: flex; align-items: center; gap: 11px;
  padding: 10px 16px; color: var(--mut); font-size: 12.5px; letter-spacing: .08em;
  border-left: 2px solid transparent; text-transform: uppercase;
}
nav a svg { width: 16px; height: 16px; flex: none; }
nav a:hover { color: var(--txt); text-shadow: none; background: rgba(53,255,139,.04); }
nav a.act {
  color: var(--acc); border-left-color: var(--acc); background: linear-gradient(90deg, rgba(53,255,139,.09), transparent);
  text-shadow: var(--glow);
}
#sideinfo { border-top: 1px solid var(--line); padding: 12px 16px; display: grid; gap: 7px; font-size: 11px; }
#sideinfo .row { display: flex; align-items: center; gap: 8px; color: var(--mut); }
#wrap { flex: 1; min-width: 0; display: flex; flex-direction: column; }
#top {
  display: flex; align-items: center; gap: 14px; flex-wrap: wrap;
  padding: 14px 22px; border-bottom: 1px solid var(--line);
  background: rgba(5,11,7,.75); backdrop-filter: blur(4px);
  position: sticky; top: 0; z-index: 20;
}
#top .node { font-size: 15px; font-weight: 800; letter-spacing: .05em; }
#top .node::before { content: "> "; color: var(--acc2); }
#top .spacer { flex: 1; }
#page { padding: 20px 22px 60px; max-width: 1280px; width: 100%; }

/* ---- tiles ---- */
.tiles { display: grid; grid-template-columns: repeat(auto-fill, minmax(190px, 1fr)); gap: 12px; margin-bottom: 14px; }
.tile { position: relative; border: 1px solid var(--line); background: var(--card); padding: 13px 15px; }
.tile .k { font-size: 10px; color: var(--mut); text-transform: uppercase; letter-spacing: .16em; display: flex; align-items: center; gap: 7px; }
.tile .k svg { width: 13px; height: 13px; color: var(--acc2); }
.tile .v { font-size: 22px; font-weight: 800; margin-top: 6px; letter-spacing: .02em; }
.tile .v .u { font-size: 11px; color: var(--mut); font-weight: 400; margin-left: 4px; }
.tile .s { font-size: 11px; color: var(--dim); margin-top: 3px; }
.tile.hot .v { color: var(--acc); text-shadow: var(--glow); }
.tile.warn .v { color: var(--amber); }
.tile.bad .v { color: var(--red); }

/* ---- tables ---- */
.tbl { width: 100%; border-collapse: collapse; }
.tbl th {
  text-align: left; font-size: 10px; color: var(--mut); text-transform: uppercase; letter-spacing: .16em;
  padding: 9px 10px; border-bottom: 1px solid var(--line2); white-space: nowrap;
}
.tbl td { padding: 10px; border-bottom: 1px solid var(--line); vertical-align: middle; }
.tbl tbody tr { transition: background .1s; }
.tbl tbody tr:hover { background: rgba(53,255,139,.035); }
.tbl tr.expandable { cursor: pointer; }
.tbl .name { font-weight: 700; letter-spacing: .03em; }
.tbl .sub { font-size: 10.5px; color: var(--dim); margin-top: 2px; }
.tblwrap { overflow-x: auto; }

/* progress bar */
.bar { height: 5px; background: #071009; border: 1px solid var(--line); width: 130px; }
.bar i { display: block; height: 100%; background: var(--acc2); box-shadow: 0 0 6px rgba(53,255,139,.4); }
.bar i.warn { background: var(--amber); box-shadow: 0 0 6px rgba(255,200,87,.4); }
.bar i.bad { background: var(--red); box-shadow: 0 0 6px rgba(255,98,98,.4); }
.bartxt { font-size: 10.5px; color: var(--mut); margin-top: 4px; white-space: nowrap; }

/* expanded client row */
.exp { background: rgba(53,255,139,.025); }
.exp td { padding: 14px 16px; }
.linkrow { display: flex; align-items: center; gap: 8px; margin: 5px 0; }
.linkrow .lt { flex: none; width: 110px; font-size: 10px; color: var(--mut); text-transform: uppercase; letter-spacing: .12em; }
.linkrow code { flex: 1; font-size: 11px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; color: #9adfb4; }

/* port allocations hint */
.porthint { font-size: 11px; color: var(--mut); margin: -4px 0 2px; }
.porthint__lbl { display: block; text-transform: uppercase; letter-spacing: .12em; font-size: 9.5px; margin-bottom: 5px; }
.portchips { display: flex; flex-wrap: wrap; gap: 6px; }
.portchip { font: inherit; font-size: 11px; padding: 3px 9px; border-radius: 7px; cursor: pointer;
  color: #9adfb4; background: rgba(60,220,130,.08); border: 1px solid rgba(60,220,130,.35); transition: background .12s; }
.portchip:hover { background: rgba(60,220,130,.2); }
.portchip--busy { color: var(--mut); background: rgba(255,255,255,.03); border-color: rgba(255,255,255,.1); cursor: not-allowed; text-decoration: line-through; }

/* section heading inside modals */
.fld-head { font-size: 10px; color: var(--mut); text-transform: uppercase; letter-spacing: .16em; margin: 14px 0 6px; }
.fld-head::before { content: "// "; color: var(--acc2); }

/* multi-select dropdown */
.h1dd { position: relative; }
.h1dd-head {
  display: flex; align-items: center; justify-content: space-between; gap: 8px; width: 100%;
  font: inherit; text-align: left; cursor: pointer; padding: 10px 12px;
  color: var(--txt); background: var(--card2); border: 1px solid var(--line2); min-height: 0;
}
.h1dd-head:hover { border-color: var(--acc2); box-shadow: none; }
.h1dd-head.open { border-color: var(--acc2); box-shadow: 0 0 0 1px rgba(53,255,139,.18); }
.h1dd-head .cap { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.h1dd-head .cap.ph { color: var(--mut); }
.h1dd-head .arw { flex: none; color: var(--acc2); font-size: 10px; transition: transform .16s; }
.h1dd-head.open .arw { transform: rotate(180deg); }
.h1dd-menu {
  margin-top: 6px; padding: 5px; display: grid; gap: 2px; max-height: 250px; overflow: auto;
  border: 1px solid var(--line2); background: var(--bg2);
}
.h1dd-menu .empty { padding: 12px; }

/* pretty checkbox row */
.h1chk {
  display: flex; align-items: center; gap: 11px; cursor: pointer; user-select: none;
  padding: 9px 11px; font-size: 12.5px; color: var(--txt);
  border: 1px solid transparent; transition: background .12s, border-color .12s;
}
.h1chk:hover { background: rgba(53,255,139,.05); border-color: var(--line); }
.h1chk.on { background: rgba(53,255,139,.09); border-color: rgba(53,255,139,.32); }
.h1chk input { position: absolute; opacity: 0; width: 0; height: 0; pointer-events: none; }
.h1chk .cbox {
  flex: none; width: 18px; height: 18px; display: grid; place-items: center; line-height: 1;
  border: 1px solid var(--line2); background: var(--bg); color: transparent;
  font-size: 12px; font-weight: 800; transition: background .12s, border-color .12s;
}
.h1chk.on .cbox { background: var(--acc); border-color: var(--acc); color: #03170a; box-shadow: 0 0 8px rgba(53,255,139,.4); }
.h1chk .ctxt { flex: 1; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.h1chk .cmeta { color: var(--mut); font-size: 11px; margin-left: 6px; }

/* client connections (3x-ui-like list) */
.ibadge { font-size: 9px; font-weight: 700; letter-spacing: .06em; padding: 2px 6px; border: 1px solid var(--line2); color: var(--mut); flex: none; }
.ibadge.vless { color: var(--acc); border-color: rgba(53,255,139,.4); }
.ibadge.net { color: #8fb7ff; border-color: rgba(143,183,255,.35); }
.ibadge.sec { color: #ffcf6b; border-color: rgba(255,207,107,.38); }
.ibadge.sec.reality { color: #ff8fdf; border-color: rgba(255,143,223,.42); }
.subcard { border: 1px solid var(--line2); background: linear-gradient(90deg, rgba(53,255,139,.1), transparent); padding: 11px 13px; margin-bottom: 12px; }
.subcard .st { display: flex; align-items: center; gap: 8px; }
.subcard .st svg { width: 15px; height: 15px; }
.subcard .st b { color: var(--acc); letter-spacing: .03em; font-size: 12.5px; text-shadow: var(--glow); }
.connlist { display: grid; gap: 7px; }
.connrow { border: 1px solid var(--line); background: var(--card2); }
.connrow-h { display: flex; align-items: center; gap: 7px; padding: 9px 11px; cursor: pointer; }
.connrow-h:hover { background: rgba(53,255,139,.05); }
.connrow-car { color: var(--acc2); font-size: 10px; flex: none; width: 10px; }
.connrow-t { flex: 1; font-size: 12.5px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.connrow-loc { color: var(--mut); font-size: 11px; flex: none; }
.connrow-b { display: none; padding: 8px 12px 14px; border-top: 1px solid var(--line); max-width: 360px; }
.qrwrap { display: flex; justify-content: center; padding: 6px 0 12px; }
.qrwrap canvas { background: #fff; padding: 8px; width: 100%; max-width: 190px; height: auto; }
.conncode { display: block; white-space: pre-wrap; word-break: break-all; font-size: 11px; line-height: 1.55; color: #9adfb4; background: var(--bg); border: 1px solid var(--line); padding: 8px 10px; }
.cpbtn { margin-top: 8px; width: 100%; justify-content: center; display: flex; align-items: center; gap: 6px; }
.linkrow code { min-width: 0; }

/* toolbar */
.bar-tools { display: flex; gap: 10px; flex-wrap: wrap; align-items: center; margin-bottom: 14px; }
.bar-tools input[type="search"] { width: 240px; }
.chips { display: flex; gap: 6px; flex-wrap: wrap; }
.chip {
  font-size: 10.5px; letter-spacing: .1em; text-transform: uppercase; cursor: pointer;
  border: 1px solid var(--line2); color: var(--mut); padding: 6px 10px; background: transparent;
  min-height: 0;
}
.chip.act { color: var(--acc); border-color: var(--acc2); background: rgba(53,255,139,.07); text-shadow: var(--glow); }

/* key-value grid */
.kv { display: grid; grid-template-columns: minmax(130px, max-content) 1fr; gap: 6px 16px; font-size: 12.5px; }
.kv dt { color: var(--mut); }
.kv dd { margin: 0; overflow-wrap: anywhere; }

.grid2 { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; align-items: start; }
@media (max-width: 980px) { .grid2 { grid-template-columns: 1fr; } }

/* ---- login ---- */
#login {
  min-height: 100vh; display: flex; align-items: center; justify-content: center; padding: 20px;
  background: radial-gradient(ellipse at 50% 30%, rgba(23,217,109,.06), transparent 60%), var(--bg);
}
#login .box { width: 420px; max-width: 100%; }
#login .ascii {
  color: var(--acc); text-shadow: var(--glow); font-size: 24px; font-weight: 800; letter-spacing: .07em;
  margin-bottom: 4px;
}
#login .ascii .sl { color: var(--acc2); }
#login .tag { color: var(--dim); font-size: 10.5px; letter-spacing: .28em; text-transform: uppercase; margin-bottom: 26px; }
#login .boot { font-size: 11.5px; color: var(--mut); margin-bottom: 18px; min-height: 54px; }
#login .boot div::before { content: "> "; color: var(--acc2); }
#login .err { color: var(--red); font-size: 12px; margin-top: 10px; min-height: 18px; }
#login .err:not(:empty)::before { content: "> отказ: "; }
#login form { display: grid; gap: 10px; }
#login .tokenlogin { margin-top: 16px; text-align: left; }
#login .tokenlogin > summary { color: var(--dim); font-size: 11px; letter-spacing: .1em; text-transform: uppercase; cursor: pointer; list-style: none; }
#login .tokenlogin > summary::before { content: "> "; color: var(--acc2); }
#login .tokenlogin[open] > summary { margin-bottom: 10px; }
#login .tokenlogin form { margin-bottom: 8px; }

/* ---- sparkline ---- */
.spark { width: 100%; height: 120px; display: block; }
.sparkhead { display: flex; align-items: baseline; gap: 12px; margin-bottom: 8px; }
.sparkhead .cur { font-size: 20px; font-weight: 800; color: var(--acc); text-shadow: var(--glow); }

/* ---- logs ---- */
.logbox {
  background: #030704; border: 1px solid var(--line); padding: 12px 14px;
  font-size: 11.5px; line-height: 1.65; max-height: 640px; overflow: auto; white-space: pre-wrap; overflow-wrap: anywhere;
}
.logbox .t { color: var(--dim); }
.logbox .a { color: var(--acc2); }
.logbox .e { color: var(--red); }

/* ---- toasts ---- */
#toasts { position: fixed; right: 18px; bottom: 18px; z-index: 400; display: grid; gap: 8px; }
.toast {
  border: 1px solid var(--acc2); background: rgba(6,16,10,.96); color: var(--txt);
  padding: 10px 14px; font-size: 12px; min-width: 220px; max-width: 360px;
  box-shadow: 0 0 18px rgba(53,255,139,.15); animation: tin .18s ease-out;
}
.toast::before { content: "[ok] "; color: var(--acc); font-weight: 700; }
.toast.err { border-color: var(--red); box-shadow: 0 0 18px rgba(255,98,98,.15); }
.toast.err::before { content: "[err] "; color: var(--red); }
@keyframes tin { from { transform: translateY(8px); opacity: 0; } }

/* ---- modal ---- */
#modalRoot .back {
  position: fixed; inset: 0; z-index: 300; background: rgba(2,5,3,.78); backdrop-filter: blur(3px);
  display: flex; align-items: flex-start; justify-content: center; padding: 8vh 16px 16px; overflow-y: auto;
}
.modal { width: 480px; max-width: 100%; border: 1px solid var(--line2); background: var(--card); box-shadow: 0 0 40px rgba(0,0,0,.6), 0 0 22px rgba(53,255,139,.08); animation: min .16s ease-out; }
@keyframes min { from { transform: translateY(-10px); opacity: 0; } }
.modal .mh { display: flex; align-items: center; padding: 13px 16px; border-bottom: 1px solid var(--line); }
.modal .mh h3 { font-size: 12px; letter-spacing: .16em; text-transform: uppercase; flex: 1; }
.modal .mh h3::before { content: "// "; color: var(--acc2); }
.modal .mb { padding: 16px; display: grid; gap: 12px; }
.modal .mf { display: flex; gap: 10px; justify-content: flex-end; padding: 0 16px 16px; }
.modal.wide { width: 640px; }

/* qr modal */
.qrbox { display: grid; place-items: center; gap: 12px; }
.qrbox canvas { background: #fff; padding: 12px; image-rendering: pixelated; max-width: 100%; }
.qrbox .qt { font-size: 10.5px; color: var(--mut); overflow-wrap: anywhere; text-align: center; max-width: 380px; }

/* federation / peers */
.peer { display: flex; align-items: center; gap: 10px; padding: 9px 0; border-bottom: 1px solid var(--line); }
.peer:last-child { border-bottom: 0; }
.peer .pn { font-weight: 700; min-width: 70px; }
.peer code { flex: 1; font-size: 11px; }

/* federation: серверы + агрегация */
.fednode { display: flex; align-items: center; gap: 12px; padding: 11px 0; border-bottom: 1px solid var(--line); }
.fednode:last-child { border-bottom: 0; }
.fednode .fn-main { flex: 1; min-width: 0; }
.fednode .fn-name { font-weight: 700; }
.fednode .fn-url { font-size: 11px; color: var(--mut); display: block; margin-top: 2px; overflow: hidden; text-overflow: ellipsis; }
.fednode .fn-stat { font-size: 11px; color: var(--acc2); white-space: nowrap; }
.led.off { background: #5a1f1f; box-shadow: 0 0 6px #b33; }
/* --- миграция --- */
.migbar { height: 10px; border-radius: 6px; background: rgba(255,255,255,.06); border: 1px solid var(--line); overflow: hidden; }
.migbar-fill { height: 100%; background: linear-gradient(90deg, var(--acc), #6affb0); box-shadow: var(--glow); transition: width .4s ease; }
.migstats { display: flex; gap: 12px; flex-wrap: wrap; }
.migstat { flex: 1; min-width: 90px; border: 1px solid var(--line); border-radius: 10px; padding: 12px; text-align: center; background: rgba(255,255,255,.02); }
.migstat-n { font-size: 26px; font-weight: 700; line-height: 1; }
.migstat-l { font-size: 11px; text-transform: uppercase; letter-spacing: .06em; color: var(--dim); margin-top: 6px; }
.migstat.ok .migstat-n { color: var(--acc); text-shadow: var(--glow); }
.migstat.warn .migstat-n { color: var(--amber); }
.migstat.err .migstat-n { color: #ff6b6b; }
.miglog { max-height: 260px; overflow-y: auto; font-family: ui-monospace, "SF Mono", Menlo, monospace; font-size: 12px; line-height: 1.55; background: rgba(0,0,0,.28); border: 1px solid var(--line); border-radius: 10px; padding: 10px 12px; }
.migline { white-space: pre-wrap; word-break: break-word; }
.fedrow { display: flex; align-items: center; gap: 10px; padding: 8px 0; border-bottom: 1px solid var(--line); font-size: 12.5px; }
.fedrow:last-child { border-bottom: 0; }
.fedrow .fr-name { flex: 1; min-width: 0; font-weight: 600; overflow: hidden; text-overflow: ellipsis; }
.srvtag { font-size: 10px; text-transform: uppercase; letter-spacing: .08em; background: rgba(53,255,139,.10); color: var(--acc); border: 1px solid var(--line); border-radius: 6px; padding: 2px 7px; white-space: nowrap; }
/* селектор активного сервера в шапке навигации */
.srvpick-wrap { display: flex; align-items: center; gap: 7px; padding: 8px 10px 10px; border-bottom: 1px solid var(--line); margin-bottom: 8px; }
.srvpick-wrap.empty { display: none; }
.srvpick-lbl { font-size: 10px; text-transform: uppercase; letter-spacing: .12em; color: var(--mut); }
.srvpick { flex: 1; min-width: 0; background: #030704; color: var(--txt); border: 1px solid var(--line); border-radius: 8px; padding: 6px 8px; font-size: 12px; font-family: inherit; }
.srvpick-wrap.remote { background: rgba(255,180,53,.06); }
.srvpick-wrap.remote .srvpick { border-color: var(--warn, #e5a13a); color: var(--warn, #e5a13a); }
.fedbanner { display: flex; align-items: center; gap: 12px; flex-wrap: wrap; background: rgba(255,180,53,.08); border: 1px solid var(--warn, #e5a13a); border-radius: 12px; padding: 10px 14px; margin-bottom: 14px; color: var(--warn, #e5a13a); font-size: 13px; }
.fedbanner span { flex: 1; min-width: 0; }

.cmd { background: #030704; border: 1px solid var(--line); padding: 9px 12px; font-size: 11.5px; color: #9adfb4; display: flex; gap: 8px; align-items: center; margin: 6px 0; }
.cmd::before { content: "$"; color: var(--acc2); font-weight: 700; }
.cmd code { flex: 1; }

/* платный модуль — запертая карточка */
.lockcard { border-style: dashed; border-color: var(--line2); background: linear-gradient(180deg, rgba(255,200,87,.05), rgba(6,13,8,.9)); }
.lockcard::before, .lockcard::after { border-color: var(--amber); }
.lockhead { display: flex; align-items: center; gap: 12px; flex-wrap: wrap; }
.lockhead > div { flex: 1; min-width: 160px; }
.lockicon { color: var(--amber); display: inline-flex; flex: none; }
.lockicon svg { width: 22px; height: 22px; }
.lockmsg { color: var(--amber); font-size: 12.5px; margin: 12px 0; }
.lockprice { font-size: 20px; font-weight: 800; color: var(--amber); letter-spacing: .02em; margin-right: 4px; }
.lockcard.ok { border-style: solid; background: linear-gradient(180deg, rgba(53,255,139,.05), rgba(6,13,8,.9)); }
.lockcard.ok::before, .lockcard.ok::after { border-color: var(--acc2); }
.lockicon.ok { color: var(--acc); }
.lockmsg.ok { color: var(--acc); }

.empty { text-align: center; color: var(--dim); padding: 34px 10px; font-size: 12px; }
.empty::before { content: "[ "; color: var(--line2); } .empty::after { content: " ]"; color: var(--line2); }

/* ---- responsive ---- */
@media (max-width: 860px) {
  #app { flex-direction: column; }
  #side { width: 100%; height: auto; position: static; flex-direction: row; align-items: center; overflow-x: auto; }
  #logo { border-bottom: 0; padding: 12px 14px; flex: none; }
  #logo .l2 { display: none; }
  nav { display: flex; padding: 0; }
  nav a { padding: 14px 10px; border-left: 0; border-bottom: 2px solid transparent; white-space: nowrap; }
  nav a.act { border-bottom-color: var(--acc); background: none; }
  nav a span { display: none; }
  #sideinfo { display: none; }
  #page { padding: 14px 12px 50px; }
  #top { padding: 12px 14px; }
  .bar-tools input[type="search"] { width: 100%; }
}

/* ---- phone: dense tables become stacked cards ---- */
@media (max-width: 640px) {
  /* touch targets */
  button { min-height: 38px; }
  button.icon { width: 40px; min-height: 40px; }
  input, select, textarea { padding: 11px 12px; font-size: 16px; } /* 16px = no iOS zoom-on-focus */

  /* toolbar: stack vertically, primary action full-width */
  .bar-tools { flex-direction: column; align-items: stretch; gap: 12px; }
  .bar-tools > div[style*="flex:1"], .bar-tools > div[style*="flex: 1"] { display: none; }
  .bar-tools > button.primary { width: 100%; }
  .bar-tools .chips { justify-content: flex-start; }
  .chip { padding: 8px 11px; }

  /* table -> cards: kill the wrapper chrome, each row is its own card */
  .tblwrap.card { border: 0 !important; background: none !important; padding: 0 !important; overflow: visible; }
  .tblwrap.card::before, .tblwrap.card::after { display: none !important; }
  .tbl, .tbl tbody { display: block; width: 100%; }
  .tbl thead { display: none; }
  .tbl tr.expandable {
    display: block; position: relative;
    border: 1px solid var(--line2); background: var(--card);
    padding: 13px 14px; margin: 0 0 10px;
  }
  .tbl tr.expandable > td { display: block; border: 0; padding: 4px 0; white-space: normal; vertical-align: top; }
  .tbl tr.expandable > td[data-label]::before {
    content: attr(data-label); display: block; margin-bottom: 3px;
    font-size: 9px; text-transform: uppercase; letter-spacing: .14em; color: var(--mut);
  }
  /* first cell = card header (name + uuid + badge) */
  .tbl tr.expandable > td.namecell { padding: 0 0 9px; margin-bottom: 7px; border-bottom: 1px solid var(--line); }
  .tbl tr.expandable > td.namecell .name { font-size: 15px; }
  .bar { width: 100%; max-width: 220px; }
  /* actions: full-width row of larger buttons */
  .tbl tr.expandable > td.actcell {
    display: flex; flex-wrap: wrap; gap: 9px; text-align: left !important;
    white-space: normal !important; margin-top: 11px; padding-top: 11px; border-top: 1px solid var(--line);
  }
  .tbl tr.expandable > td.actcell button.icon { width: 44px; min-height: 42px; }
  .tbl tr.expandable > td.actcell .pill { align-self: center; }

  /* expanded detail row: full width, no horizontal clipping */
  .tbl tr.exp { display: block; margin: -10px 0 10px; }
  .tbl tr.exp > td { display: block; padding: 13px; border-left: 2px solid var(--acc2); background: rgba(53,255,139,.03); }
  .connrow-b { max-width: none; }
  .linkrow { flex-wrap: wrap; gap: 4px 8px; }
  .linkrow .lt { width: auto; }
  .subcard, .connrow, .conncode { overflow-wrap: anywhere; }
  .subcard code, .linkrow code, .conncode { white-space: normal; word-break: break-all; }

  /* тарифы бота: строка в аккуратную сетку вместо рваного переноса */
  .planrow { display: grid !important; grid-template-columns: auto 1fr; gap: 8px 10px;
    border: 1px solid var(--line); padding: 11px; margin-bottom: 10px; }
  .planrow > input:first-child { grid-column: 1 / -1; }

  /* sparkline: keep the big number on one line */
  .sparkhead { flex-wrap: wrap; }
  .sparkhead .cur { white-space: nowrap; }
}
</style>

