<script>
"use strict";
/* H1//VLESS control panel — hacker-green single-page UI.
   Talks to the node's built-in HTTP API (Bearer token). No build step, no CDN. */

const API = location.origin + "/api";
const LS = "h1vless.token";
const $ = (id) => document.getElementById(id);
const el = (t, a = {}, kids = []) => {
  const n = document.createElement(t);
  for (const k in a) {
    if (k === "class") n.className = a[k];
    else if (k === "html") n.innerHTML = a[k];
    else if (k === "text") n.textContent = a[k];
    else if (k.startsWith("on") && typeof a[k] === "function") n.addEventListener(k.slice(2), a[k]);
    else if (a[k] != null && a[k] !== false) n.setAttribute(k, a[k]);
  }
  for (const c of [].concat(kids)) if (c != null) n.append(c.nodeType ? c : document.createTextNode(c));
  return n;
};
const svg = (id, cls) =>
  `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round"${cls ? ` class="${cls}"` : ""}><use href="#${id}"/></svg>`;
const esc = (v) => String(v ?? "").replace(/[&<>"]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" }[c]));

let TOKEN = localStorage.getItem(LS) || "";
let STATUS = null;
let CLIENTS = [];
// Федерация: "" = этот сервер (локально); иначе id ноды из реестра — все обычные
// вызовы api() проксируются на неё через мастера. /fed/* всегда идёт локально.
let FED_NODE = "";
let FED_NODE_NAME = "";
const state = { view: "dash", q: "", filter: "all", expanded: new Set() };
let trafficHist = [];

/* ---------------- API ---------------- */
async function api(path, opts = {}) {
  const headers = { Authorization: "Bearer " + TOKEN, ...(opts.headers || {}) };
  if (opts.body) headers["Content-Type"] = "application/json";
  const base = opts.node ? (API + "/fed/lproxy/" + opts.node)
             : (FED_NODE && !opts.local && !path.startsWith("/fed")) ? (API + "/fed/lproxy/" + FED_NODE) : API;
  const res = await fetch(base + path, {
    method: opts.method || "GET",
    headers,
    body: opts.body ? JSON.stringify(opts.body) : undefined,
  });
  const text = await res.text();
  let data = {};
  try { data = text ? JSON.parse(text) : {}; } catch { data = { ok: false, error: text || res.statusText }; }
  if (res.status === 401) { forceLogout(); throw new Error("unauthorized"); }
  if (!res.ok || data.ok === false) throw new Error(data.error || res.statusText || "request_failed");
  return data;
}

/* ---------------- helpers ---------------- */
function fmtDays(d) {
  if (d == null) return "—";
  if (d <= 0) return "истёк";
  if (d < 31) return d + " дн";
  const m = Math.floor(d / 30);
  return m + " мес " + (d % 30) + " дн";
}
function fmtTs(ts) {
  if (!ts) return "—";
  const d = new Date(ts * 1000);
  return d.toLocaleString("ru-RU", { day: "2-digit", month: "2-digit", year: "numeric", hour: "2-digit", minute: "2-digit" });
}
function fmtGb(gb) {
  if (gb == null) return "∞";
  if (gb >= 1024) return (gb / 1024).toFixed(2) + " ТБ";
  return (Math.round(gb * 100) / 100) + " ГБ";
}
function clientStatus(c) {
  if (c.banned) return { k: "bad", t: "бан" };
  if (c.left_days <= 0) return { k: "warn", t: "истёк" };
  if (c.left_days <= 3) return { k: "warn", t: "скоро" };
  return { k: "on", t: "актив" };
}

function toast(msg, err = false) {
  const t = el("div", { class: "toast" + (err ? " err" : ""), text: msg });
  $("toasts").append(t);
  setTimeout(() => { t.style.transition = "opacity .3s"; t.style.opacity = "0"; setTimeout(() => t.remove(), 300); }, err ? 5000 : 3000);
}
function legacyCopy(text) {
  const ta = el("textarea", {}, []); ta.value = text;
  ta.style.position = "fixed"; ta.style.top = "-1000px"; ta.style.opacity = "0";
  document.body.append(ta); ta.focus(); ta.select();
  let ok = false;
  try { ok = document.execCommand("copy"); } catch { ok = false; }
  ta.remove();
  return ok;
}
async function copy(text, label) {
  try {
    if (navigator.clipboard && window.isSecureContext) { await navigator.clipboard.writeText(text); toast((label || "Скопировано") + " → буфер"); return; }
  } catch { /* fall through to legacy */ }
  if (legacyCopy(text)) toast((label || "Скопировано") + " → буфер");
  else toast("Не удалось скопировать", true);
}

/* ---------------- modal ---------------- */
function closeModal() { $("modalRoot").innerHTML = ""; }
function modal({ title, body, footer, wide }) {
  const box = el("div", { class: "modal" + (wide ? " wide" : "") }, [
    el("div", { class: "mh" }, [
      el("h3", { text: title }),
      el("button", { class: "icon ghost", html: svg("i-x"), onclick: closeModal }),
    ]),
    el("div", { class: "mb" }, body),
    footer ? el("div", { class: "mf" }, footer) : null,
  ]);
  const back = el("div", { class: "back", onclick: (e) => { if (e.target === back) closeModal(); } }, [box]);
  $("modalRoot").innerHTML = "";
  $("modalRoot").append(back);
  document.addEventListener("keydown", function onEsc(e) { if (e.key === "Escape") { closeModal(); document.removeEventListener("keydown", onEsc); } });
  return box;
}
function confirmModal(title, text, onOk, danger) {
  const btn = el("button", { class: danger ? "danger" : "primary", text: danger ? "Подтвердить" : "OK",
    onclick: async () => { btn.disabled = true; try { await onOk(); closeModal(); } catch (e) { toast(e.message, true); btn.disabled = false; } } });
  modal({ title, body: [el("p", { text }, [])], footer: [el("button", { class: "ghost", text: "Отмена", onclick: closeModal }), btn] });
}

/* ---------------- QR ---------------- */
function drawQr(text) {
  const canvas = el("canvas", {}, []);
  try {
    const qr = qrcodegen.QrCode.encodeText(text, qrcodegen.QrCode.Ecc.MEDIUM);
    const scale = 6, border = 3, dim = (qr.size + border * 2) * scale;
    canvas.width = dim; canvas.height = dim;
    const ctx = canvas.getContext("2d");
    ctx.fillStyle = "#fff"; ctx.fillRect(0, 0, dim, dim);
    ctx.fillStyle = "#03170a";
    for (let y = 0; y < qr.size; y++)
      for (let x = 0; x < qr.size; x++)
        if (qr.getModule(x, y)) ctx.fillRect((x + border) * scale, (y + border) * scale, scale, scale);
  } catch (e) { canvas.replaceWith(el("div", { class: "empty", text: "ссылка слишком длинная для QR" })); }
  return canvas;
}
function qrModal(title, text) {
  modal({ title: "QR · " + title, body: [el("div", { class: "qrbox" }, [drawQr(text), el("div", { class: "qt", text })])],
    footer: [el("button", { class: "primary", html: svg("i-copy") + "Копировать", onclick: () => copy(text, "Ссылка") })] });
}

/* ---------------- navigation ---------------- */
const NAV = [
  { id: "dash", label: "Обзор", icon: "i-dash" },
  { id: "clients", label: "Клиенты", icon: "i-users" },
  { id: "inbounds", label: "Инбаунды", icon: "i-chip" },
  { id: "transport", label: "Транспорт", icon: "i-net" },
  { id: "settings", label: "Настройки", icon: "i-gear" },
  { id: "domains", label: "Домены", icon: "i-net" },
  { id: "federation", label: "Серверы", icon: "i-fed" },
  { id: "shopbot", label: "Бот", icon: "i-bot" },
  { id: "migrate", label: "Миграция", icon: "i-mig" },
  { id: "backups", label: "Бэкапы", icon: "i-box" },
  { id: "logs", label: "Логи", icon: "i-term" },
];
function renderNav() {
  const nav = $("nav");
  nav.innerHTML = "";
  for (const n of NAV) {
    nav.append(el("a", {
      class: state.view === n.id ? "act" : "", href: "#" + n.id,
      html: svg(n.icon) + "<span>" + esc(n.label) + "</span>",
      onclick: (e) => { e.preventDefault(); go(n.id); },
    }));
  }
}
function go(view) { state.view = view; location.hash = view; renderNav(); render(); }

/* ---------------- data load ---------------- */
async function loadAll() {
  const [st, cl] = await Promise.all([api("/status"), api("/clients")]);
  STATUS = st; CLIENTS = cl.clients || [];
  const used = CLIENTS.reduce((s, c) => s + (c.traffic_used_bytes || 0), 0);
  trafficHist.push(used);
  if (trafficHist.length > 40) trafficHist.shift();
  paintChrome();
}
function paintChrome() {
  if (!STATUS) return;
  $("topNode").textContent = STATUS.node_name || "node";
  $("topDomain").innerHTML = svg("i-net") + esc(STATUS.domain || "—");
  const tr = (STATUS.transport && STATUS.transport.mode || "ws").toUpperCase();
  $("topTransport").textContent = tr + (STATUS.reality && STATUS.reality.enabled ? " + REALITY" : "");
  $("ledXray").className = "led on";
  $("verRow").textContent = "node: " + (STATUS.node_name || "—");
  $("verVersion").textContent = STATUS.version ? "panel: " + STATUS.version.replace(/^\d{4}\.\d{2}\.\d{2}-panel-/, "") + " (" + STATUS.version.split("-")[0] + ")" : "";
}

/* ---------------- views ---------------- */
function render() {
  const p = $("page");
  p.innerHTML = "";
  if (FED_NODE) p.append(fedBanner());
  ({ dash: viewDash, clients: viewClients, inbounds: viewInbounds, transport: viewTransport, settings: viewSettings,
     domains: viewDomains, federation: viewFederation, shopbot: viewShopBot, migrate: viewMigrate, backups: viewBackups, logs: viewLogs }[state.view] || viewDash)(p);
}

function tile(k, v, unit, sub, mod, icon) {
  return el("div", { class: "tile" + (mod ? " " + mod : "") }, [
    el("div", { class: "k", html: (icon ? svg(icon) : "") + esc(k) }),
    el("div", { class: "v", html: esc(v) + (unit ? ' <span class="u">' + esc(unit) + "</span>" : "") }),
    sub ? el("div", { class: "s", text: sub }) : null,
  ]);
}

function viewDash(p) {
  const s = STATUS || {};
  const c = s.clients || {};
  const totalUsed = CLIENTS.reduce((a, x) => a + (x.traffic_used_bytes || 0), 0);
  const usedGb = totalUsed / 1073741824;
  const expSoon = CLIENTS.filter((x) => !x.banned && x.left_days > 0 && x.left_days <= 3).length;

  p.append(el("div", { class: "tiles" }, [
    tile("Клиенты всего", c.total ?? CLIENTS.length, "", null, "hot", "i-users"),
    tile("Активные", c.active ?? 0, "", expSoon ? expSoon + " истекают ≤3дн" : "все в норме", expSoon ? "warn" : "", "i-power"),
    tile("Забанены", c.banned ?? 0, "", null, (c.banned ? "bad" : ""), "i-ban"),
    tile("Истекли", c.expired ?? 0, "", null, "", "i-clock"),
    tile("Суммарный трафик", fmtGb(Math.round(usedGb * 100) / 100).replace(" ГБ", "").replace(" ТБ", ""), usedGb >= 1024 ? "ТБ" : "ГБ", "по всем клиентам", "", "i-gauge"),
    tile("Peers", (s.peers || []).length, "", "federation-локации", "", "i-net"),
  ]));

  // sparkline
  const spark = el("div", { class: "card" }, [
    el("h3", { text: "Совокупный трафик (сессия)" }),
    el("div", { class: "sparkhead" }, [
      el("span", { class: "cur", text: fmtGb(Math.round(usedGb * 100) / 100) }),
      el("small", { text: "обновляется каждые 10 сек · " + trafficHist.length + " точек" }),
    ]),
    sparkSvg(),
  ]);
  p.append(spark);

  const grid = el("div", { class: "grid2" }, []);
  // node facts
  const ws = s.ws || {}, tr = s.transport || {}, sub = s.subscription || {}, rt = s.reality || {}, eg = s.egress || {};
  grid.append(el("div", { class: "card" }, [
    el("h3", { text: "Узел" }),
    kv([
      ["Имя ноды", s.node_name],
      ["Домен", s.domain],
      ["Транспорт", (tr.mode || "ws").toUpperCase()],
      ["XHTTP path", tr.xhttp_path || "—"],
      ["Публичный порт", ws.public_port],
      ["Reality", rt.enabled ? "вкл · порт " + rt.public_port : "выкл"],
      ["Subscription", sub.enabled ? "порт " + sub.port : "выкл"],
      ["Egress", eg.mode === "xray" ? "через xray-релей" : "напрямую"],
      ["API порт", (s.api || {}).port],
    ]),
  ]));
  // cdn facts
  const cw = s.cdn_ws || {}, cx = s.cdn_xhttp || {};
  grid.append(el("div", { class: "card" }, [
    el("h3", { text: "CDN / обход" }),
    el("div", { class: "kv" }, [
      el("dt", { text: "WS-CDN" }), el("dd", {}, [pill(cw.enabled)]),
      ...(cw.enabled ? [el("dt", { text: "  host" }), el("dd", { html: "<code>" + esc(cw.host || "—") + "</code>" }),
                        el("dt", { text: "  sni" }), el("dd", { html: "<code>" + esc(cw.sni || "—") + "</code>" })] : []),
      el("dt", { text: "XHTTP-CDN" }), el("dd", {}, [pill(cx.enabled)]),
      ...(cx.enabled ? [el("dt", { text: "  host" }), el("dd", { html: "<code>" + esc(cx.host || "—") + "</code>" }),
                        el("dt", { text: "  path" }), el("dd", { html: "<code>" + esc(cx.public_path || "—") + "</code>" })] : []),
    ]),
  ]));
  p.append(grid);
}

function sparkSvg() {
  const w = 640, h = 120, pad = 4;
  const data = trafficHist.length ? trafficHist : [0];
  const max = Math.max(...data, 1), min = Math.min(...data);
  const span = max - min || 1;
  const pts = data.map((v, i) => {
    const x = pad + (i / Math.max(1, data.length - 1)) * (w - pad * 2);
    const y = h - pad - ((v - min) / span) * (h - pad * 2);
    return [x, y];
  });
  const line = pts.map((p, i) => (i ? "L" : "M") + p[0].toFixed(1) + " " + p[1].toFixed(1)).join(" ");
  const area = line + ` L${(w - pad).toFixed(1)} ${h - pad} L${pad} ${h - pad} Z`;
  const ns = "http://www.w3.org/2000/svg";
  const el2 = (t, a) => { const n = document.createElementNS(ns, t); for (const k in a) n.setAttribute(k, a[k]); return n; };
  const s = el2("svg", { class: "spark", viewBox: `0 0 ${w} ${h}`, preserveAspectRatio: "none" });
  const grad = el2("linearGradient", { id: "sg", x1: "0", y1: "0", x2: "0", y2: "1" });
  grad.append(el2("stop", { offset: "0", "stop-color": "#35ff8b", "stop-opacity": ".28" }));
  grad.append(el2("stop", { offset: "1", "stop-color": "#35ff8b", "stop-opacity": "0" }));
  const defs = el2("defs", {}); defs.append(grad); s.append(defs);
  for (let i = 1; i < 4; i++) s.append(el2("line", { x1: 0, x2: w, y1: (h / 4) * i, y2: (h / 4) * i, stroke: "#14301e", "stroke-width": "1" }));
  s.append(el2("path", { d: area, fill: "url(#sg)" }));
  s.append(el2("path", { d: line, fill: "none", stroke: "#35ff8b", "stroke-width": "1.8", "vector-effect": "non-scaling-stroke" }));
  if (pts.length) s.append(el2("circle", { cx: pts[pts.length - 1][0], cy: pts[pts.length - 1][1], r: "3", fill: "#35ff8b" }));
  return s;
}

function kv(rows) {
  const d = el("dl", { class: "kv" }, []);
  for (const [k, v] of rows) { d.append(el("dt", { text: k })); d.append(el("dd", { text: v == null || v === "" ? "—" : String(v) })); }
  return d;
}
function pill(on, onTxt, offTxt) {
  return el("span", { class: "pill " + (on ? "on" : "off"), html: '<span class="led ' + (on ? "on" : "") + '"></span>' + (on ? (onTxt || "вкл") : (offTxt || "выкл")) });
}

/* ---------- clients ---------- */
let CLIENTS_VIEW = [];
let CLIENTS_ALL = [];
let SELF_NAME = "";
// Имя ЭТОЙ панели (для маркера origin, который она ставит на реплики соседних нод).
async function ensureSelfName() {
  if (SELF_NAME) return SELF_NAME;
  try { const st = await api("/bill/status", { local: true }); if (st && st.self_name) SELF_NAME = st.self_name; } catch (e) { /* тихо */ }
  return SELF_NAME || "основная панель";
}
function cNode(c) { return c && c._node ? c._node.id : undefined; }
// Клиент с одним uuid, живущий на нескольких панелях, показываем ОДНОЙ строкой.
// _panels = [{node, pname, cname}] — все панели, где он есть (node=null → основная).
// Инбаунды мержим со ВСЕХ панелей (чтобы разворот показывал все локации, а не только свою).
const CONN_CHANNELS = ["xhttp", "ws", "reality", "xhttp_cdn", "ws_cdn"];
function dedupClients(list) {
  const byU = new Map();
  for (const c of list) {
    const key = String(c.uuid || ("name:" + c.name));
    if (!byU.has(key)) byU.set(key, { rep: c, panels: [], ibl: [], remoteConns: [], localOrigin: null, hasLocal: false });
    const g = byU.get(key);
    g.panels.push({ node: c._node ? c._node.id : null, pname: c._node ? c._node.name : null, cname: c.name });
    for (const il of (c.inbound_links || [])) if (il && il.link) g.ibl.push(il);
    // Канальные ссылки удалённой панели (БС/xhttp_cdn, ws_cdn, reality…) лежат в c.links, НЕ в inbound_links —
    // подтягиваем их отдельно, чтобы разворот показывал ВСЕ локации, как и подписка.
    if (c._node && c.links) for (const k of CONN_CHANNELS) if (c.links[k]) g.remoteConns.push({ k: k, link: c.links[k], bsLabel: c.bs_label, node: c._node });
    if (!c._node) { g.rep = c; g.hasLocal = true; g.localOrigin = c.origin || null; }
  }
  const out = [];
  byU.forEach((g) => {
    const seenL = {}, mergedIbl = g.ibl.filter((il) => (seenL[il.link] ? false : (seenL[il.link] = true)));
    // origin для бейджа берём у ЛОКАЛЬНОГО клиента (если он есть); у чисто удалённого бейдж рисуется по _node.
    const origin = g.hasLocal ? g.localOrigin : (g.rep.origin || null);
    // удалённые канальные ссылки, которых нет ни в локальных links, ни в merged inbound_links
    const localLinkSet = new Set(Object.values(g.rep.links || {}));
    const iblSet = new Set(mergedIbl.map((il) => il.link));
    const seenR = {};
    const remoteConns = g.remoteConns.filter((rc) => rc.link && !localLinkSet.has(rc.link) && !iblSet.has(rc.link) && (seenR[rc.link] ? false : (seenR[rc.link] = true)));
    out.push(Object.assign({}, g.rep, { _panels: g.panels, inbound_links: mergedIbl, origin: origin, _remoteConns: remoteConns }));
  });
  return out;
}
// Все панели клиента (для операций «на всех локациях сразу»).
function clientPanels(c) {
  if (c._panels && c._panels.length) return c._panels.map((p) => ({ node: p.node || undefined, name: p.cname }));
  return [{ node: cNode(c), name: c.name }];
}
function fromPanelBadge(txt) {
  return el("span", { class: "pill warn", style: "margin-top:4px", html: svg("i-net") + "с панели: " + esc(txt) });
}
// Метка «с панели: …»:
//  1) origin — клиент ЗАВЕДЁН с другой панели и раскинут сюда (реплика) → метка с именем панели-источника,
//     даже если он физически есть и у нас (симметрично работает на обеих панелях).
//  2) иначе — если клиента у нас локально НЕТ (только в агрегате подключённой ноды) → метка по имени ноды.
//  Родной локальный клиент (без origin) — без метки.
function clientPanelBadge(c) {
  if (c.origin && c.origin.name) return fromPanelBadge(c.origin.name);
  const panels = c._panels || [];
  const onMain = panels.length ? panels.some((p) => !p.node) : !c._node;
  if (onMain) return null;
  let remotes = panels.filter((p) => p.node).map((p) => p.pname).filter(Boolean);
  if (!remotes.length && c._node) remotes = [c._node.name];
  if (!remotes.length) return null;
  const seen = {}, uniq = remotes.filter((n) => (seen[n] ? false : (seen[n] = true)));
  return fromPanelBadge(uniq.join(", "));
}
function viewClients(p) {
  CLIENTS_ALL = (CLIENTS || []).map((c) => Object.assign({}, c, { _node: null, _ckey: "self:" + c.name }));
  CLIENTS_VIEW = dedupClients(CLIENTS_ALL);
  buildClientsView(p);
  // Дотягиваем клиентов всех подключённых нод, дедупим по uuid и перерисовываем.
  (async () => {
    try {
      const agg = await api("/fed/lagg", { local: true });
      const extra = [];
      for (const n of (agg.nodes || [])) { if (!n.online) continue; for (const c of (n.clients || [])) extra.push(Object.assign({}, c, { _node: { id: String(n.id), name: n.name || ("#" + n.id) }, _ckey: n.id + ":" + c.name })); }
      if (extra.length && state.view === "clients") { CLIENTS_VIEW = dedupClients(CLIENTS_ALL.concat(extra)); p.innerHTML = ""; buildClientsView(p); }
    } catch (e) { /* федерации может не быть — тихо */ }
  })();
}
function buildClientsView(p) {
  const counts = { all: CLIENTS_VIEW.length, active: 0, expiring: 0, expired: 0, banned: 0 };
  for (const c of CLIENTS_VIEW) {
    if (c.banned) counts.banned++;
    else if (c.left_days <= 0) counts.expired++;
    else { counts.active++; if (c.left_days <= 3) counts.expiring++; }
  }
