function multiDropdown(placeholder, items) {
  const state = {};
  items.forEach((it) => (state[it.id] = !!it.on));
  const cap = el("span", { class: "cap" });
  const arw = el("span", { class: "arw", text: "▼" });
  const head = el("button", { type: "button", class: "h1dd-head" }, [cap, arw]);
  const menu = el("div", { class: "h1dd-menu" });
  menu.style.display = "none";
  let open = false;
  function sync() {
    const chosen = items.filter((i) => state[i.id]);
    if (chosen.length) { cap.className = "cap"; cap.textContent = chosen.length <= 2 ? chosen.map((i) => i.short || i.label).join(", ") : ("Выбрано: " + chosen.length); }
    else { cap.className = "cap ph"; cap.textContent = placeholder; }
  }
  for (const it of items) {
    const { cb, row } = checkRow(it.label, state[it.id], it.meta);
    cb.addEventListener("change", () => { state[it.id] = cb.checked; sync(); });
    menu.append(row);
  }
  head.addEventListener("click", () => { open = !open; head.classList.toggle("open", open); menu.style.display = open ? "grid" : "none"; });
  sync();
  return { root: el("div", { class: "h1dd" }, [head, menu]), getSelected: () => items.filter((i) => state[i.id]).map((i) => i.id) };
}
