// preselect(item,rawInbound)->bool. opts.localOnly = только основная нода (для edit).
function inboundSelector(preselect, opts) {
  opts = opts || {};
  const root = el("div", {}, [el("div", { class: "mut", text: "загрузка инбаундов…" })]);
  const ref = { getSelected: () => [], items: [] };
  (async () => {
    const all = [];
    if (opts.homeNode) {
      // Инбаунды конкретной подключённой ноды (редактирование клиента, пришедшего с неё).
      try { const r = await api("/inbounds", { node: opts.homeNode }); for (const ib of (r.inbounds || [])) all.push({ ib, node: null }); } catch (e) { /* тихо */ }
    } else {
      try { const r = await api("/inbounds", { local: true }); for (const ib of (r.inbounds || [])) all.push({ ib, node: null }); } catch (e) { /* тихо */ }
      if (!opts.localOnly) {
        let nodes = opts.nodes;
        if (!nodes) { try { const agg = await api("/fed/lagg", { local: true }); nodes = agg.nodes || []; } catch (e) { nodes = []; } }
        for (const n of nodes) { if (!n.online) continue; for (const ib of (n.inbounds || [])) all.push({ ib, node: { id: String(n.id), name: n.name || ("#" + n.id) } }); }
      }
    }
    const items = [];
    for (const rec of all) {
      const ib = rec.ib, node = rec.node;
      if (["socks", "http", "dokodemo-door"].includes(String(ib.protocol))) continue;
      const isBs = ib.id === "__bs_main__";
      const isWg = ib.id === "__wg__";
      const shortNode = node ? (node.name.length > 20 ? node.name.slice(0, 20) + "…" : node.name) : "";
      const it = {
        id: (node ? node.id : "self") + ":" + ib.id,
        _ibid: ib.id,
        _node: node,
        label: (isBs ? (ib.tag || "БС / обход") : isWg ? "WireGuard" : (ib.tag || ib.id)),
        meta: (isBs ? "обход БС" : isWg ? "WG · UDP" : (":" + ib.port + " " + (ib.protocol || ""))) + (node ? " · с панели " + shortNode : ""),
        short: (isBs ? (ib.tag || "БС") : isWg ? "WG" : (ib.tag || ib.id)),
        _bs: isBs,
      };
      it.on = preselect ? !!preselect(it, ib) : (isBs && !node);
      items.push(it);
    }
    ref.items = items;
    root.innerHTML = "";
    if (!items.length) { root.append(el("div", { class: "mut", text: "нет инбаундов — создай во вкладке «Инбаунды»" })); return; }
    const dd = multiDropdown("Выбрать инбаунды…", items);
    ref.getSelected = dd.getSelected;
    root.append(dd.root);
  })();
