      try {
        await api("/create", { method: "POST", body, node: g.node || undefined }); okN++;
        if (sharedUuid && (g.node || null) !== primaryId) {
          try { await api("/fed/origin", { method: "POST", node: g.node || undefined, body: { uuid: sharedUuid, name: primaryName } }); } catch (e2) { /* маркер некритичен */ }
        }
      }
      catch (e) { fails.push((g.node ? "нода " + g.node : "основная") + ": " + e.message); }
    }
    closeModal();
    if (fails.length) toast("Создан на " + okN + " локац.; ошибки: " + fails.join("; "), true);
    else toast("Клиент создан" + (okN > 1 ? " на " + okN + " локациях (одна подписка)" : ": " + name));
    await refresh();
  } });
  modal({ title: "Новый клиент", body: [
    wrap,
    el("div", { class: "fld-head", text: "Инбаунды — куда завести клиента (можно с разных подключённых панелей — будет одна подписка)" }),
    sel.root,
  ], footer: [el("button", { class: "ghost", text: "Отмена", onclick: closeModal }), btn] });
}
function editClientModal(c) {
  (async () => {
    // Клиент — сущность по UUID, может жить на любой комбинации панелей (основная + подключённые).
    // Собираем текущее членство по uuid на ВСЕХ панелях, чтобы преселектить и синхронизировать.
    let laggNodes = [];
    try { const agg = await api("/fed/lagg", { local: true }); laggNodes = agg.nodes || []; } catch (e) { /* тихо */ }
    function memOf(cli) {
      return cli
        ? { has: true, name: cli.name, wg: !!cli.wg, inbIds: new Set((cli.inbound_links || []).map((x) => x.id)), bs: (cli.channels == null || (cli.channels || []).includes("bs")), chans: (cli.channels == null ? null : cli.channels) }
        : { has: false, name: null, wg: false, inbIds: new Set(), bs: false, chans: null };
    }
    const mainMem = memOf((CLIENTS || []).find((x) => String(x.uuid) === String(c.uuid)) || null);
    const remoteMem = {};
    for (const n of laggNodes) remoteMem[String(n.id)] = memOf((n.clients || []).find((x) => String(x.uuid) === String(c.uuid)) || null);
    const { wrap, refs } = fields([
      { name: "new_name", label: "переименовать (пусто = не менять)", ph: c.name },
      { name: "days", label: "продлить на (дней, 0 = не менять)", type: "number", min: "0", value: "0" },
      { name: "traffic_limit_gb", label: "лимит трафика, ГБ (0 = ∞)", type: "number", min: "0", step: "0.1", value: c.traffic_limit_bytes ? c.traffic_limit_gb : 0 },
      { name: "device_limit", label: "лимит устройств (0 = ∞)", type: "number", min: "0", value: c.device_limit || 0 },
    ]);
    const preselect = (it) => {
      const m = it._node ? remoteMem[it._node.id] : mainMem;
      if (!m || !m.has) return false;
      if (it._ibid === "__wg__") return m.wg;
      if (it._bs) return m.bs;
      return m.inbIds.has(it._ibid);
    };
    const sel = inboundSelector(preselect, { nodes: laggNodes });
    const replicaDays = () => { const d = parseInt(refs.days.value, 10); return d > 0 ? d : (c.left_days > 0 ? c.left_days : 30); };
    const btn = el("button", { class: "primary", html: svg("i-edit") + "Сохранить", onclick: async () => {
      const groups = selToNodeBodies(sel.getSelected(), sel.items());
      // Пустой выбор НЕ означает «удалить со всех локаций» (иначе транзиентная ошибка загрузки
      // инбаундов или случайно снятые галочки молча стёрли бы клиента). Для удаления — кнопка «Удалить».
      if (!groups.length) { toast("Выберите хотя бы один инбаунд (чтобы удалить клиента целиком — кнопка «Удалить»)", true); return; }
      const newName = refs.new_name.value.trim() || c.name;
      const days = parseInt(refs.days.value, 10) || 0;
      const tgb = parseFloat(refs.traffic_limit_gb.value) || 0;
      const dev = parseInt(refs.device_limit.value, 10) || 0;
      btn.disabled = true;
      await ensureSelfName();
      // «Дом» клиента для метки origin: панель, где он УЖЕ есть (до сохранения), кроме целевой.
      // Реплику на новой панели помечаем «заведён с {дом}» → бейдж «с панели: {дом}».
      const homeName = (forId) => {
        if (forId !== null && mainMem.has) return SELF_NAME || "основная панель";
        for (const n of laggNodes) { const id = String(n.id); if (id === String(forId)) continue; if ((remoteMem[id] || {}).has) return n.name || ("#" + id); }
        return SELF_NAME || "основная панель";
      };
      // Приводим членство на КАЖДОЙ панели (основная = id:null) к выбору: есть+выбран→PATCH,
      // нет+выбран→create(uuid), был+не выбран→delete. Всё по общему uuid → одна подписка.
      const panels = [{ id: null, mem: mainMem }].concat(laggNodes.map((n) => ({ id: String(n.id), mem: remoteMem[String(n.id)] })));
      const fails = [];
      for (const pnl of panels) {
        const g = groups.find((x) => (x.node || null) === pnl.id);
        const m = pnl.mem || { has: false };
        const nodeOpt = pnl.id || undefined;
        try {
          if (g) {
            if (m.has) {
              const rb = Object.assign({ traffic_limit_gb: tgb, device_limit: dev }, g.body);
              // Сохраняем логические каналы (main/reality/wscdn), которых нет в селекторе —
              // иначе PATCH затирал бы их до ['bs'] у биллинговых/legacy клиентов (channels=all).
              const bsSel = !!(g.body && g.body.channels && g.body.channels.indexOf("bs") >= 0);
              const mc = mergeChannels(m.chans, bsSel);
              if (mc === null) delete rb.channels; else rb.channels = mc;
              if (newName !== m.name) rb.new_name = newName;
              if (days > 0) rb.days = days;
              await api("/clients/" + encodeURIComponent(m.name), { method: "PATCH", body: rb, node: nodeOpt });
            } else {
              const rb = Object.assign({ name: newName, days: replicaDays(), uuid: c.uuid, traffic_limit_gb: tgb, device_limit: dev }, g.body);
              await api("/create", { method: "POST", body: rb, node: nodeOpt });
              // Реплика на новой панели → метка «заведён с {дом}» (для бейджа «с панели: …»).
              try { await api("/fed/origin", { method: "POST", node: nodeOpt, body: { uuid: c.uuid, name: homeName(pnl.id) } }); } catch (e2) { /* маркер некритичен */ }
            }
          } else if (m.has) {
            await api("/clients/" + encodeURIComponent(m.name), { method: "DELETE", node: nodeOpt });
            try { await api("/fed/origin/" + encodeURIComponent(c.uuid), { method: "DELETE", node: nodeOpt }); } catch (e2) { /* тихо */ }
          }
        } catch (e) { fails.push((pnl.id ? "нода " + pnl.id : "основная") + ": " + e.message); }
      }
      closeModal();
      if (fails.length) toast("Часть панелей не удалась: " + fails.join("; "), true);
      else toast("Сохранено: " + newName);
      await refresh();
    } });
    modal({ title: "Клиент · " + c.name + (c._node ? " · с панели " + c._node.name : ""), body: [
      wrap,
      el("div", { class: "fld-head", text: "Инбаунды / каналы (любые панели — основная и подключённые; будет одна подписка)" }),
      sel.root,
    ], footer: [el("button", { class: "ghost", text: "Отмена", onclick: closeModal }), btn] });
  })();
}
// Метка панели для сообщений об ошибках по локациям.
function panelTag(pnl) { return pnl.node ? "нода " + pnl.node : "основная"; }
function banModal(c) {
  const inp = el("input", { placeholder: "напр. chargeback (необязательно)" });
  const btn = el("button", { class: "danger", html: svg("i-ban") + "Забанить", onclick: async () => {
    btn.disabled = true;
    const fails = [];
    // Каждую локацию — в своём try: лежащая нода не должна прерывать бан на остальных.
    for (const pnl of clientPanels(c)) {
      try { await api("/clients/" + encodeURIComponent(pnl.name) + "/ban", { method: "PATCH", body: { reason: inp.value.trim() }, node: pnl.node }); }
      catch (e) { fails.push(panelTag(pnl) + ": " + e.message); }
    }
    closeModal();
    toast(fails.length ? ("Забанен частично; не удалось: " + fails.join("; ")) : ("Забанен: " + c.name), fails.length > 0);
    await refresh();
  } });
  modal({ title: "Бан · " + c.name, body: [el("label", { class: "f", text: "причина" }, [inp])], footer: [el("button", { class: "ghost", text: "Отмена", onclick: closeModal }), btn] });
}
async function doUnban(c) {
  const fails = [];
  for (const pnl of clientPanels(c)) {
    try { await api("/clients/" + encodeURIComponent(pnl.name) + "/unban", { method: "PATCH", node: pnl.node }); }
    catch (e) { fails.push(panelTag(pnl) + ": " + e.message); }
  }
  toast(fails.length ? ("Разбанен частично; не удалось: " + fails.join("; ")) : ("Разбанен: " + c.name), fails.length > 0);
  await refresh();
}
function delModal(c) {
  confirmModal("Удалить клиента", "Клиент «" + c.name + "» и его ссылки будут удалены безвозвратно (на всех локациях). Продолжить?",
    async () => {
      const fails = [];
      for (const pnl of clientPanels(c)) {
        try {
          await api("/clients/" + encodeURIComponent(pnl.name), { method: "DELETE", node: pnl.node });
          try { await api("/fed/origin/" + encodeURIComponent(c.uuid), { method: "DELETE", node: pnl.node }); } catch (e) { /* тихо */ }
        } catch (e) { fails.push(panelTag(pnl) + ": " + e.message); }
      }
      toast(fails.length ? ("Удалён частично; остался на: " + fails.join("; ")) : ("Удалён: " + c.name), fails.length > 0);
      await refresh();
    }, true);
}
async function resetLimit(c, action) {
  const fails = [];
  for (const pnl of clientPanels(c)) {
    try { await api("/clients/" + encodeURIComponent(pnl.name) + "/" + action, { method: "PATCH", node: pnl.node }); }
    catch (e) { fails.push(panelTag(pnl) + ": " + e.message); }
  }
  const base = action === "reset-traffic" ? "Трафик сброшен" : "Устройства сброшены";
  toast(fails.length ? (base + " частично; не удалось: " + fails.join("; ")) : base, fails.length > 0);
  await refresh();
}

