/* ---------------- Домены (панель + подписка) ---------------- */
function webDomainChip(d) {
  const st = d.ssl_status || (d.ssl ? "pending" : "not_issued");
  if (st === "active") return { k: "on", t: "SSL активен" };
  if (st === "error") return { k: "bad", t: "SSL ошибка" };
  if (st === "removed") return { k: "off", t: "удалён" };
  if (d.ssl) return { k: "warn", t: "SSL ожидается" };
  return { k: "off", t: "без SSL" };
}
const WEBDOMAIN_PURPOSE = { panel: "Панель", sub: "Подписка", both: "Панель + Подписка" };

function webDomainRow(d) {
  const st = d.ssl_status || (d.ssl ? "pending" : "not_issued");
  const chip = webDomainChip(d);
  const scheme = st === "active" ? "https://" : "http://";
  const purpose = d.purpose || "both";
  const btns = [];
  if (purpose !== "sub")
    btns.push(el("button", { class: "ghost", html: svg("i-net") + "Панель", onclick: () => window.open(scheme + d.domain + "/panel", "_blank") }));
  if (st !== "active" && d.ssl)
    btns.push(el("button", { class: "ghost", html: svg("i-refresh") + "Выдать SSL", onclick: () => reissueWebDomain(d) }));
  btns.push(el("button", { class: "danger", html: svg("i-trash") + "Удалить",
    onclick: () => confirmModal("Удалить домен", "Отвязать " + d.domain + "? Панель и подписка снова будут только по IP.", () => deleteWebDomain(d.domain), true) }));
  return el("div", { class: "card" }, [
    el("div", { class: "linkrow" }, [el("code", { text: d.domain }), el("span", { class: "pill " + chip.k, text: chip.t })]),
    el("div", { class: "mut", style: "margin:6px 0 10px" , text: WEBDOMAIN_PURPOSE[purpose] + (d.ssl_error ? " · " + d.ssl_error : "") }),
    el("div", { style: "display:flex;gap:8px;flex-wrap:wrap" }, btns),
  ]);
}

async function viewDomains(p) {
  p.append(el("div", { class: "vhead" }, [
    el("div", {}, [el("h2", { text: "Домены" }),
      el("p", { class: "mut", text: "Свой домен для панели и подписки. SSL (Let's Encrypt) выдаётся автоматически — как в Pterodactyl." })]),
    el("button", { class: "primary", html: svg("i-plus") + "Добавить домен", onclick: () => addWebDomainModal() }),
  ]));
  const box = el("div", {}, [el("div", { class: "empty", text: "Загрузка…" })]);
  p.append(box);
  let data;
  try { data = await api("/webdomains"); }
  catch (e) { box.innerHTML = ""; box.append(el("div", { class: "empty", text: "Ошибка: " + e.message })); return; }
  box.innerHTML = "";
  if (!data.linked) {
    box.append(el("div", { class: "empty", text: "Панель ещё не связана с личным кабинетом — привязка доменов недоступна." }));
    return;
  }
