    el("p", { class: "mut", html: "Создайте <b>A-запись</b> домена на IP этой ноды: <code>" + esc(data.public_ip || "—") +
      "</code>, дождитесь распространения DNS, затем добавьте домен." }),
  ]));
  const doms = data.domains || [];
  if (!doms.length) box.append(el("div", { class: "empty", text: "Доменов пока нет. Нажмите «Добавить домен»." }));
  const grid = el("div", { class: "grid1" }, []);
  for (const d of doms) grid.append(webDomainRow(d));
  box.append(grid);
  box.append(settingCard("Host в конфигах клиентов", "Адрес, который подставляется в сами vless-ссылки (не панель и не подписка).",
    [["Host", (STATUS || {}).domain || "—"]],
    [el("button", { html: svg("i-edit") + "Изменить", onclick: domainModal })]));
}

/* ---------------- Бот-магазин (video-seller) ---------------- */
let SHOPBOT = null;

async function viewShopBot(p) {
  p.append(el("div", { class: "vhead" }, [
    el("div", {}, [
      el("h2", { text: "Бот-магазин" }),
      el("p", { class: "mut", text: "Готовый Telegram-бот, который продаёт подписки этой ноды: тарифы, пробный период, рефералы, Stars и CryptoBot. Нужны только токен бота и ваш Telegram ID — сервер, API-токен и ссылки на подписку панель подставляет сама." }),
    ]),
  ]));
  const box = el("div", {}, [el("div", { class: "empty", text: "Загрузка…" })]);
  p.append(box);
  await shopBotReload(box);
}

async function shopBotReload(box) {
  try {
    const r = await api("/shopbot");
    SHOPBOT = r.shopbot || {};
  } catch (e) {
    box.innerHTML = "";
    box.append(el("div", { class: "empty", text: "Ошибка: " + e.message }));
    return;
  }
  renderShopBot(box);
}

function renderShopBot(box) {
  const s = SHOPBOT || {}, cfg = s.config || {}, wa = s.webapp || {};
  box.innerHTML = "";

  /* --- состояние + управление --- */
  const st = !s.installed ? { k: "off", t: "не установлен" }
    : s.running ? { k: "on", t: "работает" } : { k: "warn", t: "остановлен" };
  const btns = [];
  if (!s.installed) {
    btns.push(el("button", { class: "primary", html: svg("i-down") + "Установить бота",
      onclick: (e) => shopBotInstall(e.target.closest("button"), box) }));
  } else {
    if (s.running) {
      btns.push(el("button", { html: svg("i-refresh") + "Перезапустить", onclick: () => shopBotPower("restart", box) }));
      btns.push(el("button", { class: "danger", html: svg("i-power") + "Остановить", onclick: () => shopBotPower("stop", box) }));
    } else {
      btns.push(el("button", { class: "primary", html: svg("i-power") + "Запустить", onclick: () => shopBotPower("start", box) }));
    }
    btns.push(el("button", { class: "ghost", html: svg("i-term") + "Логи", onclick: shopBotLogsModal }));
  }
  const head = el("div", { class: "card" }, [
    el("h3", { text: "Состояние" }),
    el("div", { style: "display:flex;align-items:center;gap:12px;flex-wrap:wrap" }, [
      el("span", { class: "pill " + st.k, html: '<span class="led ' + st.k + '"></span>' + st.t }),
      el("div", { style: "flex:1" }, []),
      ...btns,
    ]),
    !s.installed ? el("p", { class: "mut", style: "margin:10px 0 0",
      text: "Установка скачивает бота и его зависимости на эту ноду (~2–4 минуты, около 150 МБ)." }) : null,
  ].filter(Boolean));
  box.append(head);

  /* --- подключение --- */
  const { wrap, refs } = fields([
    { name: "bot_token", label: "Токен бота (@BotFather)", value: cfg.bot_token || "", ph: "123456:ABC-DEF…" },
    { name: "admin_ids", label: "Admin ID через запятую (@userinfobot)", value: cfg.admin_ids || "", ph: "123456789" },
    { name: "shop_name", label: "Название магазина", value: cfg.shop_name || "", ph: "Neon VPN" },
    { name: "support_url", label: "Поддержка (ссылка, необязательно)", value: cfg.support_url || "", ph: "https://t.me/your_support" },
    { name: "cryptobot_token", label: "Токен CryptoBot (необязательно)", value: cfg.cryptobot_token || "", ph: "пусто = крипта выключена" },
  ]);
  const saveBtn = el("button", { class: "primary", html: svg("i-down") + "Сохранить", onclick: async () => {
    const body = {};
    for (const k of ["bot_token", "admin_ids", "shop_name", "support_url", "cryptobot_token"]) body[k] = refs[k].value.trim();
    if (!body.bot_token) return toast("Укажите токен бота", true);
    if (!body.admin_ids) return toast("Укажите ваш Telegram ID", true);
    saveBtn.disabled = true;
    try {
      await api("/shopbot", { method: "POST", body });
      toast(SHOPBOT && SHOPBOT.running ? "Сохранено — нажмите «Перезапустить», чтобы применить" : "Сохранено");
      await shopBotReload(box);
    } catch (e) { toast("Ошибка: " + e.message, true); }
    finally { saveBtn.disabled = false; }
  } });
  // Enter в любом поле = «Сохранить». Без этого юзер жмёт Enter, ничего не
  // происходит, и кажется, что настройки уже сохранены.
  for (const k of Object.keys(refs)) {
    refs[k].addEventListener("keydown", (e) => {
      if (e.key === "Enter") { e.preventDefault(); saveBtn.click(); }
    });
  }
  box.append(el("div", { class: "card" }, [
    el("h3", { text: "Подключение" }),
    wrap,
    el("div", { style: "margin-top:12px;display:flex;justify-content:flex-end;gap:10px;align-items:center" }, [
      el("small", { class: "mut", text: "Enter или кнопка →" }),
      saveBtn,
    ]),
  ]));

  /* --- что панель подставила сама --- */
  box.append(el("div", { class: "card soft" }, [
    el("h3", { text: "Подставлено автоматически" }),
    el("dl", { class: "kv" }, [
      el("dt", { text: "Сервер" }), el("dd", { text: "эта нода (" + ((STATUS && STATUS.node_name) || "—") + ")" }),
      el("dt", { text: "API" }), el("dd", { text: "локальный, токен ноды" }),
      el("dt", { text: "Ссылка подписки" }), el("dd", {}, [el("code", { text: (s.sub_base || "") + "/sub/<uuid>" })]),
    ]),
    el("p", { class: "mut", style: "margin:10px 0 0",
      text: "Покупатель получает ссылку на страницу подписки этой ноды — она работает сразу, отдельный веб-модуль для этого не нужен." }),
  ]));

  /* --- тарифы --- */
  const plans = (cfg.plans || []).slice();
  const rows = el("div", { class: "grid1" }, []);
  const planRefs = [];
  for (const pl of plans) {
    const t = el("input", { value: pl.title || "", style: "flex:2;min-width:120px" });
    const d = el("input", { type: "number", value: pl.days || 30, style: "flex:1;min-width:70px" });
    const pr = el("input", { type: "number", value: pl.price_rub || 0, style: "flex:1;min-width:80px" });
    planRefs.push({ id: pl.id, title: t, days: d, price: pr, src: pl });
    rows.append(el("div", { class: "planrow", style: "display:flex;gap:8px;align-items:center;flex-wrap:wrap;margin-bottom:8px" }, [
      t, el("span", { class: "mut", text: "дней" }), d, el("span", { class: "mut", text: "₽" }), pr,
    ]));
  }
  const planSave = el("button", { class: "primary", text: "Сохранить тарифы", onclick: async () => {
    const body = { plans: planRefs.map((r) => Object.assign({}, r.src, {
      title: r.title.value.trim(), days: parseInt(r.days.value, 10) || 30, price_rub: parseInt(r.price.value, 10) || 0,
    })) };
    planSave.disabled = true;
    try { await api("/shopbot", { method: "POST", body }); toast("Тарифы сохранены"); await shopBotReload(box); }
    catch (e) { toast("Ошибка: " + e.message, true); }
    finally { planSave.disabled = false; }
  } });
  box.append(el("div", { class: "card" }, [
    el("h3", { text: "Тарифы" }),
    rows,
    el("div", { style: "margin-top:6px;display:flex;justify-content:flex-end" }, [planSave]),
  ]));

  /* --- платные модули --- */
  const contact = String(wa.contact || "@welwesov");
  const ap = s.admin_panel || {};
  const webappUrl = location.origin + (wa.url || "/webapp");

  box.append(moduleCard({
    obj: wa, title: "Веб-приложение (Mini App)",
    desc: "Синяя кнопка Menu слева от поля ввода в боте — открывает магазин внутри Telegram.",
    fallbackPrice: 5000, contact,
    extra: el("button", { class: "blue", html: svg("i-out") + "WebApp", title: "Открыть страницу приложения",
      onclick: () => window.open(webappUrl, "_blank") }),
    note: el("p", { class: "mut", style: "margin:10px 0 0", html:
      "Кнопка Menu в боте ведёт на <code>" + esc(wa.public_url || "") + "</code>." +
      (wa.own_domain
        ? ""
        : " Это общая витрина. После покупки привяжите свой домен во вкладке «Домены» — бот начнёт открывать ваше приложение.") }),
  }));

  box.append(moduleCard({
    obj: ap, title: "Админ-панель",
    desc: "Кнопка «Админ-панель» в боте и команда /admin — для Telegram ID из списка админов.",
    fallbackPrice: 500, contact,
    extra: el("button", { html: svg("i-lock") + "Админ-панель",
      onclick: () => shopBotLockedModal("Админ-панель",
        ap.message || "Админ-панель заблокирована. Разблокировка — 500 ₽, писать в Telegram.",
        ap.price || 500, String(ap.contact || contact)) }),
  }));

  box.append(el("div", { class: "card soft" }, [
    el("p", { class: "mut", style: "margin:0",
      html: "Модули включает разработчик прямо в боте после оплаты — командой <code>/h1unlock</code>. " +
            "Из панели разблокировать нельзя: это защита от самостоятельной активации." }),
  ]));
}

// Карточка платного модуля: заперта или активирована — состояние приходит с ноды.
function moduleCard({ obj, title, desc, fallbackPrice, contact, extra, note }) {
  const on = !!(obj && obj.licensed);
  const who = String((obj && obj.contact) || contact || "@welwesov");
  const head = el("div", { class: "lockhead" }, [
    el("span", { class: "lockicon" + (on ? " ok" : ""), html: svg(on ? "i-unban" : "i-lock") }),
    el("div", {}, [
      el("h3", { text: title, style: "margin:0" }),
      el("div", { class: "mut", style: "margin-top:4px", text: desc }),
    ]),
    on ? el("span", { class: "pill on", html: '<span class="led on"></span>активировано' })
       : el("span", { class: "pill off", text: "не куплено" }),
  ]);
  if (on) {
    return el("div", { class: "card lockcard ok" }, [
      head,
      el("p", { class: "lockmsg ok", text: "Модуль оплачен и включён — кнопка в боте работает." }),
      extra ? el("div", { style: "display:flex;gap:10px;flex-wrap:wrap" }, [extra]) : null,
      note || null,
    ].filter(Boolean));
  }
  return el("div", { class: "card lockcard" }, [
    head,
    el("p", { class: "lockmsg", text: (obj && obj.message) || "Модуль не куплен." }),
    el("div", { style: "display:flex;gap:10px;align-items:center;flex-wrap:wrap" }, [
      el("span", { class: "lockprice", text: ((obj && obj.price) || fallbackPrice) + " ₽" }),
      extra,
      el("button", { class: "primary", html: svg("i-out") + "Написать " + esc(who),
        onclick: () => window.open("https://t.me/" + who.replace(/^@/, ""), "_blank") }),
    ].filter(Boolean)),
    note || null,
  ].filter(Boolean));
}

