async function shopBotInstall(btn, box) {
  if (btn) { btn.disabled = true; btn.textContent = "Устанавливаем… (до 4 мин)"; }
  try {
    const r = await api("/shopbot/install", { method: "POST" });
    toast(r.message || "Бот установлен");
    await shopBotReload(box);
  } catch (e) {
    toast("Установка не удалась: " + e.message, true);
    if (btn) { btn.disabled = false; btn.innerHTML = svg("i-down") + "Установить бота"; }
  }
}

async function shopBotPower(action, box) {
  try {
    const r = await api("/shopbot/" + action, { method: "POST" });
    toast(r.message || "Готово");
    await shopBotReload(box);
  } catch (e) {
    toast("Ошибка: " + e.message, true);
    await shopBotReload(box);
  }
}

