function addWebDomainModal() {
  const { wrap, refs } = fields([{ name: "domain", label: "Домен", value: "", ph: "vpn.example.com" }]);
  const purpose = el("select", {}, [
    el("option", { value: "both", text: "Панель + Подписка" }),
    el("option", { value: "sub", text: "Только подписка" }),
    el("option", { value: "panel", text: "Только панель" }),
  ]);
  const sslCb = el("input", { type: "checkbox" }); sslCb.checked = true;
  const forceCb = el("input", { type: "checkbox" }); forceCb.checked = true;
  const btn = el("button", { class: "primary", text: "Привязать", onclick: async () => {
    const domain = refs.domain.value.trim();
    if (!domain) return toast("Укажите домен", true);
    btn.disabled = true; btn.textContent = sslCb.checked ? "Выдаём SSL…" : "Привязываем…";
    try {
      const r = await api("/webdomains", { method: "POST", body: {
        domain, purpose: purpose.value, ssl: sslCb.checked, force_https: forceCb.checked } });
      closeModal();
      const st = r.domain && r.domain.ssl_status;
      if (st === "active") toast("Домен привязан, SSL активен");
      else if (st === "error") toast("Домен добавлен, но SSL не выдан: " + ((r.domain && r.domain.ssl_error) || "проверьте DNS"), true);
      else toast("Домен привязан");
      setTimeout(refresh, 1200);
    } catch (e) { toast(e.message, true); btn.disabled = false; btn.textContent = "Привязать"; }
  } });
  modal({ title: "Добавить домен", body: [
    el("p", { class: "mut", text: "Домен должен A-записью указывать на IP этой ноды. Сертификат Let's Encrypt выдаётся сразу." }),
    wrap,
    el("label", { class: "f", text: "Назначение" }, [purpose]),
    el("label", { class: "f", style: "display:flex;align-items:center;gap:8px" }, [sslCb, el("span", { text: "Выдать SSL-сертификат (HTTPS)" })]),
    el("label", { class: "f", style: "display:flex;align-items:center;gap:8px" }, [forceCb, el("span", { text: "Перенаправлять HTTP → HTTPS" })]),
  ], footer: [el("button", { class: "ghost", text: "Отмена", onclick: closeModal }), btn] });
}

async function reissueWebDomain(d) {
  try {
    const r = await api("/webdomains", { method: "POST", body: { domain: d.domain, purpose: d.purpose || "both", ssl: true, force_https: true } });
    const st = r.domain && r.domain.ssl_status;
    toast(st === "active" ? "SSL выдан" : ("SSL не выдан: " + ((r.domain && r.domain.ssl_error) || "проверьте DNS")), st !== "active");
