function realityScannerRow(sniInput, destInput) {
  // Shared Reality-dest scanner: probe a target from the node (TLS1.3/H2),
  // suggest SNIs from its cert SANs, and autofill the sni/dest fields.
  const dlId = "rt-dl-" + Math.random().toString(36).slice(2);
  const target = el("input", { placeholder: "example.com:443", list: dlId });
  const dl = el("datalist", { id: dlId }, []);
  const verdict = el("span", { class: "pill off", text: "не проверено" });
  const sniSel = el("select", { style: "display:none;margin-top:8px" }, [el("option", { value: "", text: "— SNI из скана —" })]);
  const setV = (cls, text) => { verdict.className = "pill " + cls; verdict.textContent = text; };
  const scan = async () => {
    const t = target.value.trim();
    if (!t) return toast("Укажите цель", true);
    setV("warn", "сканирую…");
    try {
      const r = await api("/reality/scan?target=" + encodeURIComponent(t));
      const s = r.scan || {};
      if (!s.ok) { setV("bad", "недоступно: " + (s.error || "ошибка")); sniSel.style.display = "none"; return; }
      setV(s.suitable ? "on" : "warn", (s.suitable ? "подходит · " : "не идеально · ") + (s.tls_version || "нет TLS1.3") + (s.h2 ? " · H2" : ""));
      const opts = s.sni_suggestions || [];
      sniSel.innerHTML = "";
      sniSel.append(el("option", { value: "", text: "— выбрать SNI (" + opts.length + ") —" }));
      for (const o of opts) sniSel.append(el("option", { value: o, text: o }));
      sniSel.style.display = opts.length ? "block" : "none";
      const host = String(s.target || t).split(":")[0];
      if (sniInput) sniInput.value = opts[0] || host;
      if (destInput && !destInput.value.trim()) destInput.value = host + ":443";
    } catch (e) { setV("bad", e.message); }
  };
  const find = async () => {
    try {
      const r = await api("/reality/targets");
      const list = r.targets || [];
      dl.innerHTML = "";
      for (const t of list) dl.append(el("option", { value: t }));
      if (!target.value.trim() && list.length) target.value = list[0];
      toast("Целей: " + list.length + " — выбери и просканируй");
    } catch (e) { toast(e.message, true); }
  };
  sniSel.addEventListener("change", () => {
    if (!sniSel.value) return;
    if (sniInput) sniInput.value = sniSel.value;
    if (destInput && !destInput.value.trim()) destInput.value = sniSel.value + ":443";
  });
  return el("div", { class: "card", style: "margin:0" }, [
    el("div", { class: "f", style: "margin-bottom:6px", text: "Reality-сканер цели" }),
    el("div", { style: "display:flex;gap:8px;flex-wrap:wrap;align-items:center" }, [
      el("div", { style: "flex:1;min-width:150px" }, [target, dl]),
      el("button", { type: "button", class: "primary", html: svg("i-search") + "Сканировать", onclick: scan }),
      el("button", { type: "button", class: "ghost", html: svg("i-search") + "Найти цели", onclick: find }),
    ]),
    el("div", { style: "margin-top:8px" }, [verdict]),
    sniSel,
  ]);
}

