/* ---------- inbounds (3x-ui style custom inbounds) ---------- */
let INBOUNDS = [];
const inbExpanded = new Set();
const PROTOS = ["vless", "vmess", "trojan", "shadowsocks", "socks", "http", "dokodemo-door", "wireguard"];
const NETWORKS = ["tcp", "ws", "grpc", "xhttp", "httpupgrade"];
const SECURITIES = ["none", "tls", "reality"];
const SS_METHODS = ["aes-256-gcm", "aes-128-gcm", "chacha20-ietf-poly1305", "2022-blake3-aes-256-gcm"];

function protoPill(proto) {
  const map = { vless: "on", vmess: "on", trojan: "warn", shadowsocks: "warn" };
  return el("span", { class: "pill " + (map[proto] || "off"), text: (proto || "?").toUpperCase() });
}

// Инбаунд, привязанный к ноде: помощник для роутинга управляющих вызовов.
function ibOpts(ib, extra) {
  const o = Object.assign({}, extra || {});
  if (ib && ib._node) o.node = ib._node.id;
  return o;
}

async function loadInbounds() {
  // Инбаунды ОСНОВНОЙ ноды + всех подключённых нод — единым списком, каждый с пометкой панели-источника.
  let local = [];
  try { const r = await api("/inbounds", { local: true }); local = (r.inbounds || []).map((ib) => Object.assign({}, ib, { _node: null, _key: "self:" + ib.id })); }
  catch (e) { toast(e.message, true); }
  let remote = [];
  try {
    const agg = await api("/fed/lagg", { local: true });
    for (const n of (agg.nodes || [])) {
      if (!n.online) continue;
      for (const ib of (n.inbounds || [])) remote.push(Object.assign({}, ib, { _node: { id: String(n.id), name: n.name || ("#" + n.id) }, _key: n.id + ":" + ib.id }));
    }
  } catch (e) { /* федерации может не быть — тихо */ }
  INBOUNDS = local.concat(remote);
}

async function viewInbounds(p) {
  p.innerHTML = "";
  p.append(el("div", { class: "bar-tools" }, [
    el("div", { style: "flex:1" }, [el("small", { text: "Инбаунды основной ноды и всех подключённых панелей — единым списком. Колонка «Панель» показывает источник; управление идёт прямо на нужную ноду." })]),
    el("button", { class: "primary", html: svg("i-plus") + "Новый инбаунд", onclick: inboundCreateModal }),
  ]));
  const host = el("div", { id: "inbHost" }, [el("div", { class: "empty", text: "загрузка…" })]);
  p.append(host);
  await loadInbounds();
  renderInboundList();
}

function renderInboundList() {
  const host = $("inbHost");
  if (!host) return;
  host.innerHTML = "";
  if (!INBOUNDS.length) { host.append(el("div", { class: "empty", text: "нет кастомных инбаундов" })); return; }
  const table = el("table", { class: "tbl" }, [
    el("thead", {}, [el("tr", {}, [
      th("Протокол"), th("Тег"), th("Панель"), th("Порт"), th("Транспорт"), th("Клиенты"), th("Статус"), th("", "text-align:right"),
    ])]),
    el("tbody", { id: "inbRows" }, []),
  ]);
  host.append(el("div", { class: "card tblwrap", style: "padding:0" }, [table]));
  const tb = $("inbRows");
  for (const ib of INBOUNDS) {
    const tr = el("tr", { class: "expandable", onclick: (e) => { if (e.target.closest("button")) return; toggleInb(ib._key); } }, [
      el("td", { "data-label": "Протокол" }, [protoPill(ib.protocol)]),
      el("td", { class: "namecell" }, [el("div", { class: "name", text: ib.tag }), el("div", { class: "sub", text: ib.id })]),
      el("td", { "data-label": "Панель" }, [ib._node
        ? el("span", { class: "pill warn", html: svg("i-net") + "с панели: " + esc(ib._node.name) })
        : el("span", { class: "pill on", html: '<span class="led on"></span>Основная' })]),
      el("td", { "data-label": "Порт" }, [el("code", { text: ":" + ib.port })]),
      el("td", { "data-label": "Транспорт" }, [el("span", { text: (ib.network || "tcp") }), el("span", { class: "sub", text: " · " + (ib.security || "none") })]),
      el("td", { "data-label": "Клиенты" }, [String(ib.clients_count || 0)]),
      el("td", { "data-label": "Статус" }, [ib.enabled ? el("span", { class: "pill on", html: '<span class="led on"></span>вкл' }) : el("span", { class: "pill off", text: "выкл" })]),
      el("td", { class: "actcell", style: "text-align:right;white-space:nowrap" }, ib.id === "__bs_main__" ? [
        el("span", { class: "pill on", html: '<span class="led on"></span>обход БС' }),
        iconBtn("i-edit", "Переименовать", (e) => { e.stopPropagation(); bsRenameModal(ib); }),
      ] : ib.id === "__wg__" ? [
        el("span", { class: "pill on", html: '<span class="led on"></span>WireGuard' }),
        iconBtn("i-trash", "Удалить (выключить WireGuard)", (e) => { e.stopPropagation(); inboundDeleteModal(ib); }, "danger"),
      ] : [
        iconBtn(ib.enabled ? "i-power" : "i-power", ib.enabled ? "Выключить" : "Включить", (e) => { e.stopPropagation(); toggleInbEnabled(ib); }),
        iconBtn("i-edit", "Изменить", (e) => { e.stopPropagation(); inboundEditModal(ib); }),
        iconBtn("i-trash", "Удалить", (e) => { e.stopPropagation(); inboundDeleteModal(ib); }, "danger"),
      ]),
    ]);
    tb.append(tr);
    if (inbExpanded.has(ib._key)) tb.append(inboundExpand(ib));
  }
}
function toggleInb(key) { if (inbExpanded.has(key)) inbExpanded.delete(key); else inbExpanded.add(key); renderInboundList(); }

function inboundExpand(ib) {
  const body = el("td", { colspan: "8" }, []);
  const grid = el("div", { class: "grid2" }, []);
  // clients + links
  const cbox = el("div", {}, [el("h3", { text: "Клиенты", style: "font-size:11px;color:var(--mut);letter-spacing:.16em;text-transform:uppercase;margin-bottom:10px" })]);
  if (!(ib.clients || []).length) cbox.append(el("div", { class: "empty", text: "нет клиентов" }));
  for (const c of (ib.clients || [])) {
    cbox.append(el("div", { class: "linkrow" }, [
      el("span", { class: "lt", text: c.email || "—" }),
      el("span", { class: "sub", text: (c.id || c.password || "").slice(0, 18) }),
    ]));
  }
  cbox.append(el("div", { class: "sub", style: "margin-top:10px", text: "Клиентов создают и получают ссылки во вкладке «Клиенты» (там же выбирают, в какие инбаунды завести). Здесь — только список заведённых." }));
  grid.append(cbox);
  // details
  const st = ib.stream || {};
  const rows = [["ID", ib.id], ["Протокол", ib.protocol], ["Порт", ib.port], ["Сеть", ib.network], ["Security", ib.security]];
  if (st.path) rows.push(["path", st.path]);
  if (st.host) rows.push(["host", st.host]);
  if (st.serviceName) rows.push(["serviceName", st.serviceName]);
  if (st.sni) rows.push(["SNI", st.sni]);
  if (st.dest) rows.push(["dest", st.dest]);
  if (ib.method) rows.push(["метод SS", ib.method]);
  const dbox = el("div", {}, [el("h3", { text: "Параметры", style: "font-size:11px;color:var(--mut);letter-spacing:.16em;text-transform:uppercase;margin-bottom:10px" }), kv(rows)]);
  if (st.public_key) dbox.append(el("div", { class: "linkrow", style: "margin-top:10px" }, [el("span", { class: "lt", text: "pbk" }), el("code", { text: st.public_key }), iconBtn("i-copy", "Копировать", () => copy(st.public_key, "public key"))]));
  if (st.short_id) dbox.append(el("div", { class: "linkrow" }, [el("span", { class: "lt", text: "sid" }), el("code", { text: st.short_id }), iconBtn("i-copy", "Копировать", () => copy(st.short_id, "short id"))]));
  grid.append(dbox);
  body.append(grid);
  return el("tr", { class: "exp" }, [body]);
}

async function refreshInbounds() { await loadInbounds(); renderInboundList(); }

async function toggleInbEnabled(ib) {
  try { await api("/inbounds/" + ib.id, ibOpts(ib, { method: "PATCH", body: { enabled: !ib.enabled } })); toast((ib.enabled ? "Инбаунд выключен" : "Инбаунд включён") + ", xray перезапускается"); setTimeout(refreshInbounds, 2500); }
  catch (e) { toast(e.message, true); }
}
function bsRenameModal(ib) {
