    catch (e) { toast(e.message, true); btn.disabled = false; }
  } });
  modal({ title: "Переименовать БС-инбаунд",
    body: [el("label", { class: "f", text: "название (только ярлык в панели, обход не затрагивается)" }, [inp])],
    footer: [el("button", { class: "ghost", text: "Отмена", onclick: closeModal }), btn] });
}
function inboundDeleteModal(ib) {
  const isWg = ib.id === "__wg__";
  const msg = isWg
    ? "WireGuard будет выключен на сервере, порт :" + ib.port + " освободится, все WG-подключения перестанут работать. Продолжить?"
    : "Инбаунд «" + ib.tag + "» (:" + ib.port + ") и все его клиенты будут удалены. Продолжить?";
  confirmModal(isWg ? "Удалить WireGuard" : "Удалить инбаунд", msg,
    async () => {
      await api("/inbounds/" + ib.id, ibOpts(ib, { method: "DELETE" }));
      toast(isWg ? "WireGuard выключен" : "Инбаунд удалён, xray перезапускается");
      setTimeout(refreshInbounds, 2000);
    }, true);
}
async function inboundDelClient(ib, email) {
  try { await api("/inbounds/" + ib.id + "/clients/" + encodeURIComponent(email), ibOpts(ib, { method: "DELETE" })); toast("Клиент удалён"); setTimeout(refreshInbounds, 2000); }
  catch (e) { toast(e.message, true); }
}

function selectEl(options, value) {
  const s = el("select", {}, options.map((o) => el("option", { value: o, text: o })));
  if (value) s.value = value;
  return s;
}

function inboundCreateModal() {
  const protoSel = selectEl(PROTOS, "vless");
  const netSel = selectEl(NETWORKS, "tcp");
  const secSel = selectEl(SECURITIES, "none");
  const ssMethodSel = selectEl(SS_METHODS, "aes-256-gcm");
  // Порт — отдельным полем, чтобы чипы свободных портов шли СРАЗУ под ним.
  const portInput = el("input", { type: "number", min: "1", placeholder: "напр. 26000" });
  const portLabel = el("label", { class: "f", text: "порт" }, [portInput]);
  // Свободные порты этого сервера из панели Pterodactyl — подставляем первый
  // автоматом, остальные показываем зелёными чипами (клик = выбрать).
  const portHint = el("div", { class: "porthint", text: "Загрузка портов…" });
  (async () => {
    try {
      const a = await api("/allocations");
      const avail = a.available || [];
      portHint.innerHTML = "";
      if (!avail.length) {
        portHint.appendChild(el("span", { class: "mut", text: "Свободных портов нет — напиши в поддержку, добавим ещё." }));
        return;
      }
      if (!portInput.value) portInput.value = String(avail[0]);
      portHint.appendChild(el("span", { class: "porthint__lbl", text: "Свободные порты (нажми, чтобы выбрать):" }));
      const row = el("div", { class: "portchips" });
      for (const p of avail) {
        row.appendChild(el("button", {
          type: "button", class: "portchip", text: String(p),
          title: "Нажми, чтобы подставить порт",
          onclick: () => { portInput.value = String(p); },
        }));
      }
      portHint.appendChild(row);
    } catch (e) { portHint.textContent = "Не удалось получить порты: " + (e.message || e); }
  })();
  const { wrap, refs } = fields([
    { name: "tag", label: "тег (пусто = авто)", ph: "custom-vless" },
  ]);
  // conditional stream fields
  const path = el("input", { placeholder: "/path", value: "/" });
  const host = el("input", { placeholder: "host заголовок (необяз.)" });
  const serviceName = el("input", { placeholder: "gRPC serviceName" });
  const sni = el("input", { placeholder: "SNI / serverName" });
  const dest = el("input", { placeholder: "dest host:port (reality)" });
  const lblPath = el("label", { class: "f", text: "path" }, [path]);
  const lblHost = el("label", { class: "f", text: "host" }, [host]);
  const lblSvc = el("label", { class: "f", text: "gRPC serviceName" }, [serviceName]);
  const lblSni = el("label", { class: "f", text: "SNI" }, [sni]);
  const lblDest = el("label", { class: "f", text: "dest (host:port)" }, [dest]);
  const lblSs = el("label", { class: "f", text: "метод Shadowsocks" }, [ssMethodSel]);
  const realityNote = el("p", { class: "mut", style: "display:none", text: "Ключи Reality (x25519 + short id) сгенерируются автоматически." });
  const scanner = realityScannerRow(sni, dest);
  scanner.style.display = "none";
  const lblNet = el("label", { class: "f", text: "сеть (транспорт)" }, [netSel]);
  const lblSec = el("label", { class: "f", text: "security" }, [secSel]);
  // socks/http — прокси с логином-паролём; dokodemo-door — проброс порта.
  const puser = el("input", { placeholder: "логин (пусто = авто)" });
  const ppass = el("input", { placeholder: "пароль (пусто = авто)" });
  const lblUser = el("label", { class: "f", text: "логин прокси" }, [puser]);
  const lblPass = el("label", { class: "f", text: "пароль прокси" }, [ppass]);
  const tgtAddr = el("input", { placeholder: "напр. 1.1.1.1 или example.com" });
  const tgtPort = el("input", { placeholder: "напр. 443", type: "number", min: "1" });
  const lblTgtAddr = el("label", { class: "f", text: "адрес назначения" }, [tgtAddr]);
  const lblTgtPort = el("label", { class: "f", text: "порт назначения" }, [tgtPort]);
  const wgNote = el("p", { class: "mut", style: "display:none",
    text: "WireGuard-сервер работает на самом хосте ноды. Выбери любой свободный порт ниже — он станет публичным UDP-портом WireGuard, клиентов добавишь во вкладке «Клиенты»." });
  const sync = () => {
    const net = netSel.value, sec = secSel.value, proto = protoSel.value;
    const isProxy = proto === "socks" || proto === "http";
    const isDoko = proto === "dokodemo-door";
    const isWg = proto === "wireguard";
    const simple = isProxy || isDoko || isWg;
    // WG использует ОБЫЧНЫЙ свободный порт (аллокацию) — порт-пикер показываем,
    // а транспорт/security/tag/прочее прячем (WG-сервер на хосте, конфиг типовой).
    wgNote.style.display = isWg ? "block" : "none";
    wrap.style.display = isWg ? "none" : "";
    if (isWg) {
      portLabel.style.display = "grid"; portHint.style.display = "";
      lblNet.style.display = "none"; lblSec.style.display = "none";
      lblUser.style.display = "none"; lblPass.style.display = "none";
      lblTgtAddr.style.display = "none"; lblTgtPort.style.display = "none";
      lblPath.style.display = "none"; lblHost.style.display = "none";
      lblSvc.style.display = "none"; lblSni.style.display = "none";
      lblDest.style.display = "none"; realityNote.style.display = "none";
      scanner.style.display = "none"; lblSs.style.display = "none";
      return;
    }
    portLabel.style.display = "grid"; portHint.style.display = "";
    lblNet.style.display = simple ? "none" : "grid";
    lblSec.style.display = simple ? "none" : "grid";
    lblUser.style.display = isProxy ? "grid" : "none";
    lblPass.style.display = isProxy ? "grid" : "none";
    lblTgtAddr.style.display = isDoko ? "grid" : "none";
    lblTgtPort.style.display = isDoko ? "grid" : "none";
    lblPath.style.display = !simple && ["ws", "xhttp", "httpupgrade"].includes(net) ? "grid" : "none";
    lblHost.style.display = !simple && ["ws", "xhttp", "httpupgrade"].includes(net) ? "grid" : "none";
    lblSvc.style.display = !simple && net === "grpc" ? "grid" : "none";
    lblSni.style.display = !simple && (sec === "tls" || sec === "reality") ? "grid" : "none";
    lblDest.style.display = !simple && sec === "reality" ? "grid" : "none";
    realityNote.style.display = !simple && sec === "reality" ? "block" : "none";
    scanner.style.display = !simple && sec === "reality" ? "block" : "none";
    lblSs.style.display = proto === "shadowsocks" ? "grid" : "none";
  };
  protoSel.addEventListener("change", sync);
  netSel.addEventListener("change", sync);
  secSel.addEventListener("change", sync);
  sync();
  const btn = el("button", { class: "primary", html: svg("i-plus") + "Создать", onclick: async () => {
    const proto = protoSel.value;
    const port = parseInt(portInput.value, 10);
    if (!port) return toast("Укажите порт", true);
    if (proto === "wireguard") {
      btn.disabled = true;
      try {
        const r = await api("/inbounds", { method: "POST", body: { protocol: "wireguard", port } });
        closeModal(); toast("Инбаунд WireGuard создан на порту " + port);
        inboundCreatedModal(r.inbound);
        refreshInbounds();
        setTimeout(refreshInbounds, 2500);
      } catch (e) { toast(e.message, true); btn.disabled = false; }
      return;
    }
    const isProxy = proto === "socks" || proto === "http";
    const isDoko = proto === "dokodemo-door";
    const body = { protocol: proto, port, network: netSel.value, security: secSel.value };
    const tag = refs.tag.value.trim(); if (tag) body.tag = tag;
    if (proto === "shadowsocks") body.method = ssMethodSel.value;
    if (isProxy) {
      const u = puser.value.trim(), p = ppass.value.trim();
      if (u) body.user = u;
      if (p) body.password = p;
    }
    if (isDoko) {
      if (!tgtAddr.value.trim()) return toast("Укажите адрес назначения", true);
      const tp = parseInt(tgtPort.value, 10);
      if (!tp) return toast("Укажите порт назначения", true);
      body.target_address = tgtAddr.value.trim();
      body.target_port = tp;
    }
    const stream = {};
    if (!isProxy && !isDoko) {
      if (["ws", "xhttp", "httpupgrade"].includes(netSel.value)) { if (path.value.trim()) stream.path = path.value.trim(); if (host.value.trim()) stream.host = host.value.trim(); }
      if (netSel.value === "grpc" && serviceName.value.trim()) stream.serviceName = serviceName.value.trim();
      if ((secSel.value === "tls" || secSel.value === "reality") && sni.value.trim()) stream.sni = sni.value.trim();
      if (secSel.value === "reality" && dest.value.trim()) stream.dest = dest.value.trim();
    }
    if (Object.keys(stream).length) body.stream = stream;
    btn.disabled = true;
    try {
      const r = await api("/inbounds", { method: "POST", body });
      closeModal(); toast("Инбаунд создан, xray перезапускается");
      inboundCreatedModal(r.inbound);
      refreshInbounds();
      setTimeout(refreshInbounds, 2500);
      setTimeout(refreshInbounds, 6000);
    } catch (e) { toast(e.message, true); btn.disabled = false; }
  } });
  modal({ title: "Новый инбаунд",
    body: [
      el("label", { class: "f", text: "протокол" }, [protoSel]),
      wgNote,
      portLabel,
      portHint,
      wrap,
      lblNet,
      lblSec,
      lblUser, lblPass, lblTgtAddr, lblTgtPort,
      lblSs, lblPath, lblHost, lblSvc, lblSni, lblDest, realityNote, scanner,
    ],
    footer: [el("button", { class: "ghost", text: "Отмена", onclick: closeModal }), btn] });
}

function inboundCreatedModal(ib) {
  if (!ib) return;
  const st = ib.stream || {};
  const kids = [el("p", { class: "mut", text: "Инбаунд «" + (ib.tag || "") + "» создан на порту " + ib.port + "." })];
  for (const c of (ib.clients || [])) {
    if (c.link) kids.push(el("div", { class: "linkrow" }, [
      el("span", { class: "lt", text: c.email || "" }), el("code", { text: c.link }),
      iconBtn("i-copy", "Копировать", () => copy(c.link, "Ссылка")),
      iconBtn("i-qr", "QR", () => qrModal(ib.tag, c.link)),
    ]));
  }
  if (st.public_key) kids.push(el("div", { class: "linkrow" }, [el("span", { class: "lt", text: "pbk" }), el("code", { text: st.public_key }), iconBtn("i-copy", "Копировать", () => copy(st.public_key, "public key"))]));
  if (st.short_id) kids.push(el("div", { class: "linkrow" }, [el("span", { class: "lt", text: "sid" }), el("code", { text: st.short_id }), iconBtn("i-copy", "Копировать", () => copy(st.short_id, "short id"))]));
  modal({ title: "Инбаунд создан", body: kids, footer: [el("button", { class: "primary", text: "Готово", onclick: closeModal })] });
}

function inboundEditModal(ib) {
  const st = ib.stream || {};
  const { wrap, refs } = fields([
    { name: "tag", label: "тег", value: ib.tag || "" },
    { name: "port", label: "порт", type: "number", min: "1", value: ib.port || "" },
  ]);
  const path = el("input", { value: st.path || "" });
  const host = el("input", { value: st.host || "" });
  const sni = el("input", { value: st.sni || "" });
  const extra = [];
  if (["ws", "xhttp", "httpupgrade"].includes(ib.network)) { extra.push(el("label", { class: "f", text: "path" }, [path])); extra.push(el("label", { class: "f", text: "host" }, [host])); }
  if (ib.security === "tls" || ib.security === "reality") extra.push(el("label", { class: "f", text: "SNI" }, [sni]));
  const btn = el("button", { class: "primary", text: "Сохранить", onclick: async () => {
    const body = {};
    const tag = refs.tag.value.trim(); if (tag) body.tag = tag;
    const port = parseInt(refs.port.value, 10); if (port) body.port = port;
    const stream = {};
    if (["ws", "xhttp", "httpupgrade"].includes(ib.network)) { stream.path = path.value.trim(); stream.host = host.value.trim(); }
    if (ib.security === "tls" || ib.security === "reality") stream.sni = sni.value.trim();
    if (Object.keys(stream).length) body.stream = stream;
    btn.disabled = true;
    try { await api("/inbounds/" + ib.id, ibOpts(ib, { method: "PATCH", body })); closeModal(); toast("Инбаунд обновлён, xray перезапускается"); setTimeout(refreshInbounds, 2500); }
    catch (e) { toast(e.message, true); btn.disabled = false; }
  } });
  modal({ title: "Инбаунд · " + ib.tag, body: [wrap, ...extra], footer: [el("button", { class: "ghost", text: "Отмена", onclick: closeModal }), btn] });
}

function addClientModal(ib) {
  const proto = ib.protocol;
  const defs = [{ name: "email", label: "имя клиента (пусто = авто)", ph: "user2" }];
  if (proto === "vless" || proto === "vmess") defs.push({ name: "id", label: "UUID (пусто = авто)", ph: "auto" });
  if (proto === "trojan" || proto === "shadowsocks") defs.push({ name: "password", label: "пароль (пусто = авто)", ph: "auto" });
  const { wrap, refs } = fields(defs);
  const flowSel = proto === "vless" ? selectEl(["", "xtls-rprx-vision"], "") : null;
  const btn = el("button", { class: "primary", html: svg("i-plus") + "Добавить", onclick: async () => {
    const body = {};
    const email = refs.email.value.trim(); if (email) body.email = email;
    if (refs.id && refs.id.value.trim()) body.id = refs.id.value.trim();
    if (refs.password && refs.password.value.trim()) body.password = refs.password.value.trim();
    if (flowSel && flowSel.value) body.flow = flowSel.value;
    btn.disabled = true;
    try { await api("/inbounds/" + ib.id + "/clients", { method: "POST", body }); closeModal(); toast("Клиент добавлен, xray перезапускается"); setTimeout(refreshInbounds, 2500); }
    catch (e) { toast(e.message, true); btn.disabled = false; }
  } });
  const body = [wrap];
  if (flowSel) body.push(el("label", { class: "f", text: "flow (vless)" }, [flowSel]));
  modal({ title: "Новый клиент · " + ib.tag, body, footer: [el("button", { class: "ghost", text: "Отмена", onclick: closeModal }), btn] });
}

/* ---------- federation ---------- */
function viewFederation(p) {
  const wrap = el("div", {});
  p.append(wrap);
  loadBillingServers(wrap);
}

async function loadBillingServers(wrap) {
  wrap.innerHTML = "";
  const head = el("div", { class: "card" }, [el("h3", { text: "Мои VLESS-серверы" })]);
  wrap.append(head);
  const listCard = el("div", { class: "card" }, [el("div", { class: "mut", text: "загрузка серверов…" })]);
  wrap.append(listCard);
  const aggBox = el("div", {});
  wrap.append(aggBox);
  let st;
  try { st = await api("/bill/status", { local: true }); } catch (e) { st = { linked: false }; }
  if (!st.linked) {
    listCard.innerHTML = "";
    listCard.append(el("div", { class: "empty", text: "Панель ещё не связана с личным кабинетом. Если сервер только что создан — подожди пару минут и обнови страницу." }));
    return;
  }
  let linkData = { links: [], main: false };
  try { linkData = await api("/fed/link", { local: true }); } catch (e) { /* тихо */ }
  const links = new Set((linkData.links || []).map(String));
  let attached = [];
  try { const ar = await api("/fed/attached", { local: true }); attached = ar.attached || []; } catch (e) { /* тихо */ }
  head.innerHTML = "";
  head.append(el("h3", { text: "Мои VLESS-серверы" }));
  head.append(el("div", { style: "display:flex;align-items:center;gap:10px;margin-top:8px;flex-wrap:wrap" }, [
    linkData.main
      ? el("span", { class: "pill on", html: '<span class="led on"></span>Это основная нода' })
      : el("button", { class: "primary", html: svg("i-plus") + "Сделать основной нодой", onclick: async () => { try { await api("/fed/main", { method: "POST", body: { main: true }, local: true }); toast("Эта панель — основная"); loadBillingServers(wrap); } catch (e) { toast(e.message, true); } } }),
    el("button", { class: "ghost", html: svg("i-refresh") + "Обновить", onclick: () => loadBillingServers(wrap) }),
  ]));
  head.append(el("p", { class: "mut", style: "margin-top:8px", text: "Все твои VLESS-сервера подтянулись сами. Нажми «Добавить ноду» — её инбаунды и клиенты появятся здесь, и ими можно рулить прямо с этой панели." }));
  let d;
  try { d = await api("/bill/servers", { local: true }); }
  catch (e) { listCard.innerHTML = ""; listCard.append(el("div", { class: "empty", text: "не удалось загрузить: " + e.message })); return; }
  const raw = d.servers || d.data || [];
  // Только НАША VLESS-панель: panel_enabled, не 3x-ui, не remna, не бот-тариф (Basic).
  const servers = raw.filter((s) => s && s.panel_enabled === true && !s.xui_enabled && !s.remnanode_enabled && s.tariff_group !== "Basic");
  listCard.innerHTML = "";
  const hid = raw.length - servers.length;
  listCard.append(el("div", { style: "margin-bottom:10px" }, [
    el("span", { class: "sub", text: servers.length + " серверов" + (hid > 0 ? " · скрыто " + hid + " (3x-ui / remna / боты)" : "") }),
  ]));
  if (!servers.length) { listCard.append(el("div", { class: "empty", text: "серверов с нашей панелью нет" })); return; }
  const selfId = String((st && st.self_server_id) || "");
  // основная нода (этот сервер) — всегда первой, без кнопок
  servers.sort((a, b) => (String(a.id) === selfId ? -1 : 0) - (String(b.id) === selfId ? -1 : 0));
  for (const sv of servers) {
    const active = sv.status === "active";
    const isSelf = selfId && String(sv.id) === selfId;
    const linked = links.has(String(sv.id));
    const kids = [
      el("span", { class: "led " + (active ? "on" : "off") }, []),
      el("div", { class: "fn-main" }, [
        el("div", { class: "fn-name", text: sv.name || ("#" + sv.id) }),
        el("code", { class: "fn-url", text: "#" + sv.id + " · " + (sv.status || "") + " · " + fmtDays(sv.days_left) }),
      ]),
      el("span", { class: "srvtag", text: "VLESS" + (sv.vpn_bs_enabled ? " · БС" : "") }),
    ];
    if (isSelf) {
      kids.push(el("span", { class: "pill on", html: '<span class="led on"></span>Основная нода' }));
      for (const a of attached) kids.push(el("span", { class: "pill warn", html: svg("i-net") + "подключена к: " + esc(a.name || ("#" + a.id)) }));
      listCard.append(el("div", { class: "fednode self" }, kids));
      continue;
    }
    if (linked) {
      kids.push(el("span", { class: "pill on", text: "добавлена" }));
      kids.push(el("button", { class: "ghost", text: "Управлять", onclick: () => manageNode(sv) }));
      kids.push(iconBtn("i-trash", "Отвязать", () => confirmModal("Отвязать ноду",
        "Нода «" + (sv.name || sv.id) + "» пропадёт из основной (сам сервер не трогается). Продолжить?",
        async () => { await api("/fed/link/" + sv.id, { method: "DELETE", local: true }); toast("Отвязана"); loadBillingServers(wrap); }, true), "danger"));
    } else {
      kids.push(el("button", { class: "primary", html: svg("i-plus") + "Добавить ноду", onclick: async (e) => {
        e.target.disabled = true;
        try { await api("/fed/link", { method: "POST", body: { server_id: String(sv.id) }, local: true }); toast("Нода добавлена: " + (sv.name || sv.id)); loadBillingServers(wrap); }
        catch (err) { toast("Не удалось: " + err.message, true); e.target.disabled = false; }
      } }));
      if (sv.panel_web_url) kids.push(el("button", { class: "ghost", text: "Панель", onclick: () => window.open(sv.panel_web_url, "_blank", "noopener") }));
    }
    listCard.append(el("div", { class: "fednode" }, kids));
  }
  if (links.size) loadLinkedAggregate(aggBox);
}

async function loadLinkedAggregate(aggBox) {
  aggBox.innerHTML = "";
  const card = el("div", { class: "card" }, [el("h3", { text: "Добавленные ноды" }), el("div", { class: "mut", text: "загрузка инбаундов и клиентов…" })]);
  aggBox.append(card);
  let d;
  try { d = await api("/fed/lagg", { local: true }); }
  catch (e) { card.innerHTML = ""; card.append(el("h3", { text: "Добавленные ноды" }), el("div", { class: "empty", text: e.message })); return; }
  const nodes = d.nodes || [];
  const allInb = [], allCli = [];
  for (const n of nodes) {
    for (const ib of (n.inbounds || [])) allInb.push({ srv: n.name, ib });
    for (const c of (n.clients || [])) allCli.push({ srv: n.name, c });
  }
  card.innerHTML = "";
  card.append(el("h3", { text: "Инбаунды добавленных нод (" + allInb.length + ")" }));
  if (!allInb.length) card.append(el("div", { class: "empty", text: "нет" }));
  for (const r of allInb) card.append(el("div", { class: "fedrow" }, [
    el("span", { class: "srvtag", text: r.srv }),
    el("span", { class: "fr-name", text: r.ib.tag || r.ib.id }),
    el("code", { text: ":" + r.ib.port }),
    el("span", { class: "sub", text: (r.ib.protocol || "") + " · " + (r.ib.clients_count || 0) + " кл" }),
  ]));
  const cliCard = el("div", { class: "card" }, [el("h3", { text: "Клиенты добавленных нод (" + allCli.length + ")" })]);
  if (!allCli.length) cliCard.append(el("div", { class: "empty", text: "нет" }));
  for (const r of allCli) {
    const stt = clientStatus(r.c);
    cliCard.append(el("div", { class: "fedrow" }, [
      el("span", { class: "srvtag", text: r.srv }),
      el("span", { class: "fr-name", text: r.c.name }),
      el("span", { class: "pill " + stt.k, text: stt.t }),
      el("span", { class: "sub", text: fmtDays(r.c.left_days) }),
    ]));
  }
  aggBox.append(cliCard);
}

function manageNode(sv) {
  FED_NODE = String(sv.id); FED_NODE_NAME = sv.name || ("#" + sv.id);
  loadAll().then(() => { toast("Управляем: " + FED_NODE_NAME); go("clients"); })
    .catch((e) => { toast("Нода недоступна: " + e.message, true); FED_NODE = ""; FED_NODE_NAME = ""; });
}
function backToMain() {
  const pn = FED_NODE, pnn = FED_NODE_NAME;
  FED_NODE = ""; FED_NODE_NAME = "";
  loadAll().then(() => { toast("Основная нода"); go("federation"); })
    .catch((e) => { FED_NODE = pn; FED_NODE_NAME = pnn; render(); toast("Не удалось загрузить основную ноду: " + e.message, true); });
}
function fedBanner() {
  return el("div", { class: "fedbanner" }, [
    el("span", { html: '🌐 Управляем нодой: <b>' + esc(FED_NODE_NAME) + "</b>" }),
    el("button", { class: "ghost", text: "← Вернуться на основную", onclick: backToMain }),
  ]);
}

/* ---------------- миграция с чужих панелей (3x-ui / Remnawave) ---------------- */
let MIG_TIMER = null;
let MIG_FORM = { source: "xui", url: "", username: "", password: "", token: "" };

function migSourceCard() {
  const card = el("div", { class: "card" });
  card.append(el("h3", { text: "Откуда переносим" }));
  const tabs = el("div", { class: "segtabs", style: "display:flex;gap:8px;margin:10px 0 16px" });
  const bodyWrap = el("div", {});
  const sources = [
    { id: "xui", label: "3x-ui" },
    { id: "remna", label: "Remnawave" },
  ];
  function paintTabs() {
    tabs.innerHTML = "";
    for (const s of sources) {
      tabs.append(el("button", {
        class: MIG_FORM.source === s.id ? "primary" : "ghost",
        text: s.label, onclick: () => { MIG_FORM.source = s.id; paintTabs(); paintBody(); },
      }));
    }
  }
  function paintBody() {
    bodyWrap.innerHTML = "";
    const rows = [
      { name: "url", label: MIG_FORM.source === "xui" ? "Адрес панели 3x-ui (с секретным путём, если есть)" : "Адрес Remnawave",
        ph: MIG_FORM.source === "xui" ? "http://1.2.3.4:2053/secretpath" : "https://panel.example.com", value: MIG_FORM.url },
    ];
    if (MIG_FORM.source === "xui") {
      rows.push({ name: "username", label: "Логин", ph: "admin", value: MIG_FORM.username });
      rows.push({ name: "password", label: "Пароль", type: "password", ph: "••••••••", value: MIG_FORM.password });
    } else {
      rows.push({ name: "token", label: "API-токен (Bearer)", ph: "eyJhbGciOi…", value: MIG_FORM.token });
    }
    const { wrap, refs } = fields(rows);
    for (const k of Object.keys(refs)) refs[k].addEventListener("input", () => { MIG_FORM[k] = refs[k].value.trim(); });
    bodyWrap.append(wrap);
    const btns = el("div", { style: "display:flex;gap:10px;margin-top:16px;flex-wrap:wrap" }, [
      el("button", { class: "ghost", html: svg("i-refresh") + "Проверить связь", onclick: (e) => migProbe(e.target) }),
      el("button", { class: "primary", html: svg("i-mig") + "Начать перенос", onclick: (e) => migStart(e.target) }),
    ]);
    bodyWrap.append(btns);
    bodyWrap.append(el("p", { class: "mut", style: "margin-top:12px;font-size:12px",
      text: "UUID клиентов сохраняется — их старые ссылки и подписки продолжат работать, поменяется только хост. Уже существующие на этой ноде (по UUID) и просроченные пропускаются." }));
  }
  paintTabs(); paintBody();
  card.append(tabs, bodyWrap);
  return card;
}

async function migProbe(btn) {
  if (!MIG_FORM.url) { toast("Укажи адрес панели", true); return; }
  if (btn) { btn.disabled = true; }
  try {
    const r = await api("/migrate/probe", { method: "POST", body: MIG_FORM });
    modal({
      title: "Связь есть · " + (r.panel || MIG_FORM.source),
      body: [
        el("p", { text: "Нашёл клиентов: " + r.clients + " (активных " + r.active + "), инбаундов: " + (r.inbounds_total ?? "?") }),
        r.sample && r.sample.length ? el("p", { class: "mut", style: "font-size:12px;margin-top:8px", text: "Например: " + r.sample.join(", ") }) : null,
      ].filter(Boolean),
      footer: [el("button", { class: "primary", text: "Ок", onclick: closeModal })],
    });
  } catch (e) {
    toast("Не подключиться: " + e.message, true);
  } finally { if (btn) btn.disabled = false; }
}

async function migStart(btn) {
  if (!MIG_FORM.url) { toast("Укажи адрес панели", true); return; }
  if (btn) btn.disabled = true;
  try {
    await api("/migrate/start", { method: "POST", body: MIG_FORM });
    toast("Миграция запущена");
    migPoll(true);
  } catch (e) {
    toast(e.message, true);
    if (btn) btn.disabled = false;
  }
}

function migPhaseLabel(ph) {
  return ({ idle: "ожидание", fetch: "подключение", import: "перенос клиентов", save: "сохранение", done: "готово", error: "ошибка" })[ph] || ph;
}

function migRenderStatus(box, m) {
  box.innerHTML = "";
  const running = !!m.running, ph = m.phase || "idle";
  const head = el("div", { style: "display:flex;align-items:center;gap:10px;margin-bottom:12px" }, [
    el("span", { class: "led" + (ph === "done" ? " on" : ph === "error" ? " off" : running ? " warn" : "") }),
    el("h3", { style: "margin:0;flex:1", text: "Статус: " + migPhaseLabel(ph) }),
    running ? el("span", { class: "pill warn", text: "идёт…" }) : null,
  ].filter(Boolean));
  box.append(head);

  if (m.total > 0 || running) {
    const pct = m.total ? Math.round((m.done / m.total) * 100) : (running ? 5 : 0);
    box.append(el("div", { class: "migbar" }, [el("div", { class: "migbar-fill", style: "width:" + pct + "%" })]));
    box.append(el("div", { class: "mut", style: "font-size:12px;margin:6px 0 14px", text: m.done + " / " + m.total + " клиентов" }));
  }

  const stat = el("div", { class: "migstats" }, [
    migStat("перенесено", m.imported || 0, "ok"),
    migStat("пропущено", m.skipped || 0, "warn"),
    migStat("ошибок", m.failed || 0, "err"),
  ]);
  box.append(stat);

  if (m.error) box.append(el("p", { class: "lockmsg", style: "color:#ff6b6b;margin-top:12px", text: m.error }));

  const log = el("div", { class: "miglog" });
  for (const e of (m.log || [])) {
    const c = e.kind === "ok" ? "#37d67a" : e.kind === "err" ? "#ff6b6b" : e.kind === "skip" ? "#e0a458" : "#8aa0b3";
    log.append(el("div", { class: "migline", style: "color:" + c }, [el("span", { text: e.msg })]));
  }
  box.append(el("h4", { text: "Журнал", style: "margin:18px 0 8px" }));
  box.append(log);
  log.scrollTop = log.scrollHeight;
}

function migStat(label, val, kind) {
  return el("div", { class: "migstat " + kind }, [
    el("div", { class: "migstat-n", text: String(val) }),
    el("div", { class: "migstat-l", text: label }),
  ]);
}

async function migPoll(force) {
  const box = $("migStatusBox");
  if (!box) { if (MIG_TIMER) { clearInterval(MIG_TIMER); MIG_TIMER = null; } return; }
  try {
    const r = await api("/migrate/status");
    const m = r.migrate || {};
    migRenderStatus(box, m);
    if (!m.running && (m.phase === "done" || m.phase === "error" || m.phase === "idle")) {
      if (MIG_TIMER) { clearInterval(MIG_TIMER); MIG_TIMER = null; }
      if (m.phase === "done") { toast("Миграция завершена: +" + (m.imported || 0)); refresh(); }
    } else if (!MIG_TIMER) {
      MIG_TIMER = setInterval(() => migPoll(false), 1200);
    }
  } catch (e) { /* тихо, панель могла перезапускаться */ }
}

async function viewMigrate(p) {
  if (MIG_TIMER) { clearInterval(MIG_TIMER); MIG_TIMER = null; }
  p.append(el("div", { class: "vhead" }, [
    el("div", {}, [
