    ]),
  ]));
  p.append(migSourceCard());
  const statusCard = el("div", { class: "card" }, [el("div", { id: "migStatusBox" }, [el("div", { class: "empty", text: "Заполни доступы и нажми «Начать перенос»." })])]);
  p.append(statusCard);
  migPoll(false);
}

