    if (!lines.length) { box.textContent = "журнал пуст"; return; }
    for (const line of lines.slice().reverse()) {
      const m = line.match(/^(\S+\s+\S+)?\s*(\S+)?\s*(.*)$/);
      const isErr = /error|fail|denied|401|500/i.test(line);
      box.append(el("div", { class: isErr ? "e" : "", html: line.replace(/^(\[?[\d\-T:\.]+\]?)/, '<span class="t">$1</span>') }));
    }
  } catch (e) { $("logbox").textContent = "ошибка: " + e.message; }
}

