/* ---------------- auth ---------------- */
function showApp() { $("login").classList.add("hidden"); $("app").classList.remove("hidden"); }
function showLogin() { $("app").classList.add("hidden"); $("login").classList.remove("hidden"); bootSequence(); }
function forceLogout() { TOKEN = ""; localStorage.removeItem(LS); showLogin(); }

function bootSequence() {
  const lines = ["init secure channel…", "probe /health…", "awaiting credentials"];
  const boot = $("boot"); if (!boot) return; boot.innerHTML = "";
  let i = 0;
  (function step() { if (i >= lines.length) return; boot.append(el("div", { text: lines[i++] })); setTimeout(step, 260); })();
}

async function loginWithCreds(username, password) {
  const res = await fetch(API + "/auth/login", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ username, password }),
  });
  let data = {};
  try { data = await res.json(); } catch {}
  if (!res.ok || !data.token) {
    throw new Error(res.status === 401 ? "неверный логин или пароль" : (data.error || "ошибка входа"));
  }
  await tryLogin(data.token);
}

async function tryLogin(token) {
  TOKEN = token;
  const st = await api("/status");
  localStorage.setItem(LS, token);
  STATUS = st;
  showApp();
  renderNav();
  const hash = location.hash.replace("#", "");
  if (NAV.some((n) => n.id === hash)) state.view = hash;
  await loadAll();
  render();
  startPolling();
}

/* ---------------- polling ---------------- */
let pollTimer = null;
function startPolling() {
  if (pollTimer) clearInterval(pollTimer);
  pollTimer = setInterval(async () => {
    try {
      await loadAll();
      if (state.view === "dash") render();
      else if (state.view === "clients") renderClientRows();
    } catch (_) {}
  }, 10000);
