    const h = location.hash.replace("#", "");
    if (NAV.some((n) => n.id === h) && h !== state.view) { state.view = h; renderNav(); render(); }
  });

  if (TOKEN) {
    tryLogin(TOKEN).catch(() => { forceLogout(); });
  } else {
    showLogin();
  }
}
document.addEventListener("DOMContentLoaded", init);

</script>
