class Handler(BaseHTTPRequestHandler):
    server_version = "H1CloudVPNAPI/1.0"

    def end_headers(self):
        self.send_header("Access-Control-Allow-Origin", "*")
        self.send_header("Access-Control-Allow-Headers", "authorization,x-api-key,content-type")
        self.send_header("Access-Control-Allow-Methods", "GET,POST,PUT,PATCH,DELETE,OPTIONS")
        super().end_headers()

    def log_message(self, fmt, *args):
        try:
            line = fmt % args
            # Не пишем секреты в logs.txt (?token=/?key= отдаётся через /logs).
            line = re.sub(r'([?&](?:token|key)=)[^&\s"]+', r'\1<redacted>', line)
            log_action("http", f"{self.client_address[0]} {line}")
        except Exception:
            pass

    def send_json(self, status, data):
        body = json.dumps(data, ensure_ascii=False, indent=2).encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", "application/json; charset=utf-8")
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def send_text(self, status, text, content_type="text/plain; charset=utf-8"):
        body = text.encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", content_type)
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def send_raw(self, status, body, content_type="application/json; charset=utf-8"):
        if isinstance(body, str):
            body = body.encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", content_type)
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def do_OPTIONS(self):
        self.send_response(204)
        self.end_headers()

    def do_GET(self):
        self.route("GET")

    def do_POST(self):
        self.route("POST")

    def do_PUT(self):
        self.route("PUT")

    def do_PATCH(self):
        self.route("PATCH")

    def do_DELETE(self):
        self.route("DELETE")

    def read_body(self):
        length = parse_int(self.headers.get("Content-Length", "0"), 0) or 0
        if length <= 0:
            return {}

        raw = self.rfile.read(length)
        ctype = self.headers.get("Content-Type", "")

        if "application/json" in ctype:
            try:
                data = json.loads(raw.decode("utf-8"))
                return data if isinstance(data, dict) else {}
            except Exception:
                return {}

        parsed = urllib.parse.parse_qs(raw.decode("utf-8", "ignore"))
        return {key: values[0] if values else "" for key, values in parsed.items()}

    def authorized(self, params):
        header = self.headers.get("Authorization", "")
        api_key = self.headers.get("X-API-Key", "")
        query_token = first_value(params, "token")

        if header == f"Bearer {API_TOKEN}":
            return True
        if api_key == API_TOKEN:
            return True
        if query_token == API_TOKEN:
            return True
        return False

    def route(self, method):
        parsed = urllib.parse.urlparse(self.path)
        path = parsed.path.strip("/")
        parts = [urllib.parse.unquote(p) for p in path.split("/") if p]
        params = urllib.parse.parse_qs(parsed.query)

        if parts and parts[0] == "api":
            parts = parts[1:]
            path = "/".join(parts)

        if method == "GET" and parts and parts[0] in ("panel", "panel.html"):
            self.send_text(200, embedded_panel_html(), "text/html; charset=utf-8")
            return

        # Публичная страница Mini App — открывается синей кнопкой «WebApp» без токена.
        # Модуль платный, поэтому вместо приложения отдаём заглушку с ценой.
        if method == "GET" and parts and parts[0] == "webapp":
            self.send_text(200, shopbot_webapp_locked_html(), "text/html; charset=utf-8")
            return

        # Общая подписка клиента (base64 всех его ссылок) — без токена, ключ = uuid.
        if method == "GET" and parts and parts[0] in ("sub", "subscription") and len(parts) >= 2:
            self.serve_subscription(urllib.parse.unquote(parts[1]))
            return

        if method == "GET" and path in ("", "health"):
            payload = {
                "ok": True,
                "service": "vpn-api",
                "api_port": API_PORT,
                "endpoints": [
                    "GET /clients",
                    "GET /status",
                    "GET/PATCH /node",
                    "GET/POST/DELETE /peers",
                    "GET/PATCH/DELETE /federation",
                    "GET /info?name=NAME",
                    "POST /create",
                    "PATCH /edit",
                    "PATCH /clients/NAME/ban",
                    "PATCH /clients/NAME/unban",
                    "PATCH /clients/NAME/reset-traffic",
                    "PATCH /clients/NAME/reset-devices",
                    "DELETE /clients/NAME",
                    "GET /stats",
                    "POST /server/restart",
                    "POST /server/transport",
                    "POST /server/reality",
                    "POST /server/cdn-ws",
                    "POST /server/cdn-xhttp",
                    "POST /server/egress",
                    "POST /server/domain",
                    "POST /server/sub-name",
                    "POST /server/panel-credentials",
                    "POST /server/update-settings",
                    "GET /auth/status",
                    "POST /auth/login",
                    "GET /panel",
                    "GET /keys",
                    "GET /logs",
                ],
                "auth": "Authorization: Bearer TOKEN or X-API-Key: TOKEN",
            }
            self.send_json(200, payload)
            return

        if method == "POST" and parts == ["nodes", "join"]:
            data = {}
            for key, values in params.items():
                data[key] = values[0] if values else ""
            data.update(self.read_body())
            self.join_node(data)
            return

        # Panel sign-in: exchange billing-provisioned username+password for the
        # node's api_token, which the SPA then uses as bearer for every call.
        if method == "GET" and parts == ["auth", "status"]:
            self.send_json(200, {"ok": True, "login_required": load_panel_auth() is not None})
            return

        if method == "POST" and parts == ["auth", "login"]:
            data = {}
            for key, values in params.items():
                data[key] = values[0] if values else ""
            data.update(self.read_body())
            username = (data.get("username") or "").strip()
            password = data.get("password") or ""
            if verify_panel_login(username, password):
                log_action("panel_login", username)
                self.send_json(200, {"ok": True, "token": API_TOKEN})
            else:
                log_action("panel_login_failed", username)
                self.send_json(401, {"ok": False, "error": "invalid_credentials"})
            return

        if not self.authorized(params):
            self.send_json(401, {"ok": False, "error": "unauthorized"})
            return

        body = self.read_body() if method in ("POST", "PUT", "PATCH", "DELETE") else {}
        merged = {}
        for key, values in params.items():
            merged[key] = values[0] if values else ""
        merged.update(body)
        # Прокси-ветки (fed/lproxy, bill) форвардят ТОЛЬКО тело запроса, без
        # query-параметров (в т.ч. ?token=), поэтому храним его отдельно.
        self._req_body = body

        try:
            self.dispatch(method, parts, path, merged)
        except Exception as exc:
            log_action("api_error", repr(exc))
            self.send_json(500, {"ok": False, "error": "internal_error"})

    def dispatch(self, method, parts, path, data):
        users = load_users(prune=True)

        if method == "GET" and parts and parts[0] in ("status", "system", "dashboard"):
            self.send_json(200, status_payload(users))
            return

        if parts and parts[0] == "node":
            if method == "GET":
                self.send_json(200, {"ok": True, "node_name": read_node_name()})
                return
            if method in ("POST", "PUT", "PATCH"):
                self.set_node_name(users, data)
                return

        if parts and parts[0] == "peers":
            if method == "GET":
                self.send_json(200, {"ok": True, "peers": load_peers()})
                return
            if method == "POST":
                self.save_peer(data)
                return
            if method == "DELETE" and len(parts) == 2:
                self.delete_peer(parts[1])
                return

        if parts and parts[0] == "nodes":
            if method == "GET":
                if len(parts) > 1 and parts[1] == "health":
                    self.send_json(200, {"ok": True, "nodes": nodes_with_health()})
                else:
                    self.send_json(200, {"ok": True, "nodes": load_nodes(), "peers": load_peers()})
                return

        # Федерация: реестр серверов, агрегация, прокси к API нод.
        if parts and parts[0] == "fed":
            sub = parts[1] if len(parts) > 1 else ""
            if sub == "registry":
                if method == "GET":
                    self.send_json(200, {"ok": True, "nodes": [fed_node_public(n) for n in load_fed_nodes()]})
                    return
                if method == "POST":
                    self.fed_add_node(data)
                    return
                if method == "DELETE" and len(parts) >= 3:
                    self.fed_delete_node(parts[2])
                    return
            if sub == "aggregate" and method == "GET":
                self.fed_aggregate()
                return
            if sub == "proxy" and len(parts) >= 3:
                self.fed_proxy(method, parts[2], parts[3:], data)
                return
            if sub == "link":
                if method == "GET":
                    self.send_json(200, {"ok": True, "links": load_fed_links(), "main": fed_is_main()})
                    return
                if method == "POST":
                    sid = str(first_value(data, "server_id", "id") or "").strip()
                    if not sid:
                        self.send_json(400, {"ok": False, "error": "server_id_required"})
                        return
                    if not linked_node_login(sid, force=True):
                        self.send_json(502, {"ok": False, "error": "node_login_failed"})
                        return
                    links = load_fed_links()
                    if sid not in links:
                        links.append(sid)
                        save_fed_links(links)
                    # Сообщаем подключаемой ноде, что она теперь привязана к ЭТОЙ панели
                    # (обратная ссылка «подключена к панели X» на её стороне).
                    try:
                        linked_node_request(sid, "POST", "/fed/attached",
                                            json.dumps({"id": self_server_id(), "name": self_billing_name()}).encode("utf-8"))
                    except Exception:
                        pass
                    log_action("api_fed_link", sid)
                    self.send_json(200, {"ok": True, "links": links})
                    return
                if method == "DELETE" and len(parts) >= 3:
                    sid = str(parts[2])
                    links = [x for x in load_fed_links() if x != sid]
                    save_fed_links(links)
                    try:
                        linked_node_request(sid, "DELETE", "/fed/attached/" + self_server_id())
                    except Exception:
                        pass
                    self.send_json(200, {"ok": True, "links": links})
                    return
            if sub == "attached":
                if method == "GET":
                    self.send_json(200, {"ok": True, "attached": load_fed_attached()})
                    return
                if method == "POST":
                    aid = str(first_value(data, "id", "server_id") or "").strip()
                    if not aid:
                        self.send_json(400, {"ok": False, "error": "id_required"})
                        return
                    lst = [x for x in load_fed_attached() if str(x.get("id")) != aid]
                    lst.append({"id": aid, "name": str(first_value(data, "name") or "").strip()})
                    save_fed_attached(lst)
                    self.send_json(200, {"ok": True, "attached": lst})
                    return
                if method == "DELETE" and len(parts) >= 3:
                    aid = str(parts[2])
                    lst = [x for x in load_fed_attached() if str(x.get("id")) != aid]
                    save_fed_attached(lst)
                    self.send_json(200, {"ok": True, "attached": lst})
                    return
            if sub == "origin":
                # Маркер «клиент {uuid} заведён с панели {name}» — ставит панель-источник
                # при создании реплики, снимает при удалении. Бейдж «с панели: {name}».
                if method == "GET":
                    self.send_json(200, {"ok": True, "origin": load_fed_origin()})
                    return
                if method == "POST":
                    u = str(first_value(data, "uuid", "id") or "").strip()
                    if not u:
                        self.send_json(400, {"ok": False, "error": "uuid_required"})
                        return
                    d = load_fed_origin()
                    d[u] = {"name": str(first_value(data, "name") or "").strip()}
                    save_fed_origin(d)
                    self.send_json(200, {"ok": True})
                    return
                if method == "DELETE" and len(parts) >= 3:
                    u = str(parts[2])
                    d = load_fed_origin()
                    d.pop(u, None)
                    save_fed_origin(d)
                    self.send_json(200, {"ok": True})
                    return
            if sub == "main":
                if method == "GET":
                    self.send_json(200, {"ok": True, "main": fed_is_main()})
                    return
                if method == "POST":
                    val = str(first_value(data, "main", "value") or "1").lower() in ("1", "true", "yes", "on")
                    try:
                        with open(FED_MAIN_FILE, "w", encoding="utf-8") as f:
                            f.write("1" if val else "0")
                    except Exception:
                        pass
                    self.send_json(200, {"ok": True, "main": val})
                    return
            if sub == "lagg" and method == "GET":
                import concurrent.futures as _cf
                import time as _t
                sids = load_fed_links()
                try:
                    _c, _d = billing_request("GET", "/servers")
                    for _s in (_d.get("servers") or []):
                        _LINKED_SERVERS[str(_s.get("id"))] = (_s, _t.time())
                except Exception:
                    pass

                def _lagg_one(sid):
                    sv = _billing_server(sid) or {}
                    entry = {"id": sid, "name": sv.get("name") or ("#" + str(sid)), "online": False, "inbounds": [], "clients": []}
                    code, ib = linked_node_json(sid, "GET", "/inbounds", timeout=8)
                    if code == 200:
                        entry["online"] = True
                        entry["inbounds"] = ib.get("inbounds") or []
                        code2, cl = linked_node_json(sid, "GET", "/clients", timeout=10)
                        if code2 == 200:
                            entry["clients"] = cl.get("clients") or []
                    return entry

                out = []
                if sids:
                    with _cf.ThreadPoolExecutor(max_workers=min(8, len(sids))) as ex:
                        futs = {ex.submit(_lagg_one, s): s for s in sids}
                        done, notdone = _cf.wait(futs, timeout=25)
                        for f in done:
                            try:
                                out.append(f.result())
                            except Exception:
                                s = futs[f]
                                out.append({"id": s, "name": "#" + str(s), "online": False, "inbounds": [], "clients": [], "error": "failed"})
                        for f in notdone:
                            s = futs[f]
                            f.cancel()
                            out.append({"id": s, "name": "#" + str(s), "online": False, "inbounds": [], "clients": [], "error": "timeout"})
                self.send_json(200, {"ok": True, "nodes": out})
                return
            if sub == "lproxy" and len(parts) >= 3:
                sid = str(parts[2])
                subpath = "/" + "/".join(parts[3:])
                try:
                    q = urllib.parse.urlparse(self.path).query
                    if q:
                        subpath += "?" + q
                except Exception:
                    pass
                raw = None
                _b = getattr(self, "_req_body", None)
                if method in ("POST", "PUT", "PATCH", "DELETE") and _b:
                    raw = json.dumps(_b, ensure_ascii=False).encode("utf-8")
                code, body, ctype = linked_node_request(sid, method, subpath, raw, timeout=25)
                self.send_raw(code or 502, body, ctype)
                return
            self.send_json(404, {"ok": False, "error": "fed_route_not_found"})
            return

        # ЛК/биллинг: авто-подтягивание всех серверов владельца + управление БС-клиентами.
        if parts and parts[0] == "bill":
            sub = parts[1] if len(parts) > 1 else ""
            if sub == "status" and method == "GET":
                url, key = billing_config()
                if not (url and key):
                    self.send_json(200, {"ok": True, "linked": False})
                    return
                code, me = billing_request("GET", "/me")
                self.send_json(200, {"ok": True, "linked": code == 200, "billing_url": url,
                                     "me": me if code == 200 else None,
                                     "self_server_id": self_server_id(),
                                     "self_name": (self_billing_name() if code == 200 else "")})
                return
            if sub == "servers" and method == "GET":
                code, d = billing_request("GET", "/servers")
                self.send_raw(code or 502, json.dumps(d, ensure_ascii=False), "application/json; charset=utf-8")
                return
            if sub == "server" and len(parts) >= 3:
                sid = parts[2]
                rest = "/".join(parts[3:])
                bpath = "/servers/" + sid + (("/" + rest) if rest else "")
                _b = getattr(self, "_req_body", None)
                payload = _b if (method in ("POST", "PUT", "PATCH", "DELETE") and _b) else None
                code, d = billing_request(method, bpath, payload)
                self.send_raw(code or 502, json.dumps(d, ensure_ascii=False), "application/json; charset=utf-8")
                return
            self.send_json(404, {"ok": False, "error": "bill_route_not_found"})
            return

        if parts and parts[0] in ("shopbot", "shop"):
            self.handle_shopbot(method, parts, data)
            return

        if parts and parts[0] in ("migrate", "migration"):
            self.handle_migrate(method, parts, data)
            return

        if parts and parts[0] in ("webdomains", "domains-web"):
            self.handle_webdomains(method, parts, data)
            return

        if parts and parts[0] == "backups":
            if method == "GET":
                self.send_json(200, {"ok": True, "backups": list_backups()})
                return
            if method == "POST":
                path = create_backup()
                self.send_json(201, {"ok": True, "backup": {"path": path, "name": os.path.basename(path)}})
                return

        if parts and parts[0] in ("traffic", "stats"):
            live = query_xray_stats()
            rows = []
            for user in users:
                name = user.get("name")
                payload = client_payload(user)
                lv = (live or {}).get(name) or {}
                up = lv.get("uplink")
                down = lv.get("downlink")
                rows.append({
                    "name": name,
                    "uuid": payload["uuid"],
                    "stored_used_bytes": payload["traffic_used_bytes"],
                    "stored_used_gb": payload["traffic_used_gb"],
                    "traffic_limit_bytes": payload["traffic_limit_bytes"],
                    "live_uplink_bytes": up,
                    "live_downlink_bytes": down,
                    "live_total_bytes": (int(up or 0) + int(down or 0)) if lv else None,
                })
            self.send_json(200, {
                "ok": True,
                "stats": {
                    "enabled": True,
                    "live_available": live is not None,
                    "stats_port": XRAY_STATS_PORT,
                    "note": "live counters reset on xray restart; stored_used_bytes is the stable total",
                },
                "clients": rows,
            })
            return

        if method in ("POST", "PUT", "PATCH") and parts and (
            parts[0] in ("restart", "restart-xray")
            or (parts[0] in ("server", "config") and len(parts) >= 2 and parts[1] in ("restart", "restart-xray", "xray-restart"))
        ):
            atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_restart {now_ts()}\n")
            log_action("api_restart", "manual")
            self.send_json(200, {"ok": True, "restart": "requested"})
            return

        if method in ("POST", "PUT", "PATCH") and parts and parts[0] in ("server", "config") and len(parts) >= 2 and parts[1] in ("cdn-xhttp", "xhttp-cdn", "relay"):
            self.configure_cdn_xhttp(users, data)
            return

        if method in ("POST", "PUT", "PATCH") and parts and parts[0] in ("server", "config") and len(parts) >= 2:
            sub = parts[1]
            if sub in ("transport", "xhttp"):
                self.configure_transport(users, data)
                return
            if sub in ("cdn-ws", "ws-cdn"):
                self.configure_cdn_ws(users, data)
                return
            if sub == "reality":
                self.configure_reality(users, data)
                return
            if sub == "egress":
                self.configure_egress(users, data)
                return
            if sub == "domain":
                self.configure_domain(users, data)
                return
            if sub in ("update-settings", "update"):
                self.configure_update_settings(users, data)
                return
            if sub in ("sub-name", "subscription-name", "subname"):
                self.configure_sub_name(users, data)
                return
            if sub in ("panel-credentials", "panel-login", "credentials"):
                self.configure_panel_credentials(users, data)
                return

        if parts and parts[0] == "inbounds":
            if method == "GET" and len(parts) == 1:
                self.list_inbounds()
                return
            if method == "POST" and len(parts) == 1:
                self.create_inbound(data)
                return
            if len(parts) >= 2:
                iid = parts[1]
                if len(parts) == 2 and method in ("PATCH", "PUT", "POST"):
                    self.update_inbound(iid, data)
                    return
                if len(parts) == 2 and method == "DELETE":
                    self.delete_inbound(iid)
                    return
                if len(parts) == 3 and parts[2] == "clients" and method == "POST":
                    self.add_inbound_client(iid, data)
                    return
                if len(parts) == 4 and parts[2] == "clients" and method == "DELETE":
                    self.remove_inbound_client(iid, urllib.parse.unquote(parts[3]))
                    return
            self.send_json(404, {"ok": False, "error": "not_found"})
            return

        if method == "GET" and parts and parts[0] == "reality" and len(parts) >= 2 and parts[1] == "scan":
            target = first_value(data, "target", "dest", "host")
            if not target:
                self.send_json(400, {"ok": False, "error": "no_target"})
                return
            self.send_json(200, {"ok": True, "scan": reality_scan(target)})
            return

        if method == "GET" and parts and parts[0] == "reality" and len(parts) >= 2 and parts[1] in ("targets", "suggest"):
            self.send_json(200, {"ok": True, "targets": REALITY_TARGET_SUGGESTIONS})
            return

        if method == "GET" and parts and parts[0] == "allocations":
            self.send_json(200, dict({"ok": True}, **list_allocations()))
            return

        if parts and parts[0] == "federation":
            if method == "GET":
                self.send_json(200, {"ok": True, "federation": federation_payload()})
                return
            if method in ("POST", "PUT", "PATCH"):
                self.set_federation(data)
                return
            if method == "DELETE":
                self.disable_federation()
                return

        if method == "GET" and parts and parts[0] in ("clients", "users") and len(parts) == 1:
            self.send_json(200, {"ok": True, "clients": [client_payload(u) for u in users]})
            return

        if method == "GET" and parts and parts[0] in ("keys",):
            write_keys(users)
            self.send_json(200, {"ok": True, "clients": [client_payload(u) for u in users]})
            return

        if method == "GET" and path == "key.txt":
            write_keys(users)
            try:
                with open(KEY_FILE, "r", encoding="utf-8") as f:
                    text = f.read()
            except Exception:
                text = "no keys\n"
            self.send_text(200, text)
            return

        if method == "GET" and parts and parts[0] == "logs":
            count = parse_int(first_value(data, "count"), 100) or 100
            count = max(1, min(count, 1000))
            try:
                with open(ACTION_LOG_FILE, "r", encoding="utf-8") as f:
                    lines = f.readlines()[-count:]
            except Exception:
                lines = []
            self.send_json(200, {"ok": True, "logs": [line.rstrip("\n") for line in lines]})
            return

        if method == "GET" and (
            (parts and parts[0] == "info")
            or (parts and parts[0] in ("clients", "users") and len(parts) == 2)
        ):
            name = parts[1] if len(parts) == 2 and parts[0] in ("clients", "users") else first_value(data, "name")
            for user in users:
                if user.get("name") == name:
                    self.send_json(200, {"ok": True, "client": client_payload(user)})
                    return
            self.send_json(404, {"ok": False, "error": "user_not_found"})
            return

        if method == "POST" and ((parts and parts[0] == "create") or (parts and parts[0] in ("clients", "users") and len(parts) == 1)):
            self.create_client(users, data)
            return

        if method in ("POST", "PUT", "PATCH") and parts and parts[0] in ("ban", "unban"):
            name = first_value(data, "name")
            if parts[0] == "ban":
                self.ban_client(users, name, data)
            else:
                self.unban_client(users, name)
            return

        if method in ("POST", "PUT", "PATCH") and parts and parts[0] in ("clients", "users") and len(parts) == 3 and parts[2] in ("ban", "unban"):
            if parts[2] == "ban":
                self.ban_client(users, parts[1], data)
            else:
                self.unban_client(users, parts[1])
            return

        if method in ("POST", "PUT", "PATCH") and parts and parts[0] in ("clients", "users") and len(parts) == 3 and parts[2] in ("reset-traffic", "reset-devices"):
            self.reset_client_limit(users, parts[1], parts[2])
            return

        if method in ("PUT", "PATCH", "POST") and (
            (parts and parts[0] == "edit")
            or (parts and parts[0] in ("clients", "users") and len(parts) == 2)
        ):
            name = parts[1] if len(parts) == 2 and parts[0] in ("clients", "users") else first_value(data, "name")
            self.edit_client(users, name, data)
            return

        if method in ("DELETE", "POST") and (
            (parts and parts[0] == "delete")
            or (parts and parts[0] in ("clients", "users") and len(parts) == 2)
        ):
            name = parts[1] if len(parts) == 2 and parts[0] in ("clients", "users") else first_value(data, "name")
            self.delete_client(users, name)
            return

        self.send_json(404, {"ok": False, "error": "not_found"})

    def join_node(self, data):
        token = strip_outer_quotes(first_value(data, "join_token", "token"))
        expected = read_join_token()
        if not expected or token != expected:
            self.send_json(401, {"ok": False, "error": "bad_join_token"})
            return

        display_name = strip_outer_quotes(first_value(data, "node_name", "display_name", "label", "name"))
        peer_name = strip_outer_quotes(first_value(data, "peer_name", "code"))
        sub_url = strip_outer_quotes(first_value(data, "sub_url", "subscription_url"))
        api_url = strip_outer_quotes(first_value(data, "api_url", "node_api_url"))

        if not validate_label(display_name):
            self.send_json(400, {"ok": False, "error": "bad_node_name"})
            return
        if not validate_name(peer_name):
            peer_name = slugify_label(display_name)
        if not validate_name(peer_name):
            self.send_json(400, {"ok": False, "error": "bad_peer_name"})
            return
        if not sub_url.startswith(("http://", "https://")):
            self.send_json(400, {"ok": False, "error": "bad_sub_url"})
            return

        now = now_ts()
        nodes = [node for node in load_nodes() if isinstance(node, dict) and node.get("name") != peer_name]
        nodes.append({
            "name": peer_name,
            "display_name": display_name,
            "sub_url": sub_url,
            "api_url": api_url,
            "joined_at": now,
            "last_seen_at": now,
        })
        save_nodes(nodes)

        peers = [peer for peer in load_peers() if peer.get("name") != peer_name]
        peers.append({"name": peer_name, "url": sub_url})
        save_peers(peers)

        log_action("node_join", f"{peer_name} {display_name} {sub_url}")
        self.send_json(200, {
            "ok": True,
            "node": nodes[-1],
            "upstream_url": public_api_url(),
            "api_token": API_TOKEN,
        })

    def set_node_name(self, users, data):
        global NODE_NAME

        value = str(first_value(data, "name", "node_name")).strip()
        if not validate_label(value):
            self.send_json(400, {"ok": False, "error": "bad_node_name"})
            return

        NODE_NAME = value
        atomic_text(NODE_NAME_FILE, value + "\n")
        write_keys(users)
        log_action("api_node_set", value)
        self.send_json(200, {"ok": True, "node_name": read_node_name()})

    def save_peer(self, data):
        name = strip_outer_quotes(first_value(data, "name"))
        url = strip_outer_quotes(first_value(data, "url"))

        if not validate_name(name):
            self.send_json(400, {"ok": False, "error": "bad_peer_name"})
            return
        if not url.startswith(("http://", "https://")):
            self.send_json(400, {"ok": False, "error": "bad_peer_url"})
            return

        peers = [peer for peer in load_peers() if peer.get("name") != name]
        peers.append({"name": name, "url": url})
        save_peers(peers)
        log_action("api_peer_save", name)
        self.send_json(200, {"ok": True, "peers": peers})

    def delete_peer(self, name):
        if not validate_name(name):
            self.send_json(400, {"ok": False, "error": "bad_peer_name"})
            return

        peers = load_peers()
        new_peers = [peer for peer in peers if peer.get("name") != name]
        if len(new_peers) == len(peers):
            self.send_json(404, {"ok": False, "error": "peer_not_found"})
            return

        save_peers(new_peers)
        log_action("api_peer_delete", name)
        self.send_json(200, {"ok": True, "peers": new_peers})

    def configure_cdn_xhttp(self, users, data):
        global TRANSPORT, XHTTP_PATH, XHTTP_METHOD
        global CDN_XHTTP_ENABLED, CDN_XHTTP_HOST, CDN_XHTTP_SNI, CDN_XHTTP_PORT, CDN_XHTTP_TAG, CDN_XHTTP_PUBLIC_PATH

        cdn_host = normalize_host(first_value(data, "cdn_host", "host", "address"))
        sni = normalize_host(first_value(data, "sni", "server_name")) or cdn_host
        port = parse_int(first_value(data, "cdn_port", "port"), 443) or 443
        tag = strip_outer_quotes(str(first_value(data, "tag", "tag_suffix") or "CDN")).strip() or "CDN"
        public_path = normalize_path_value(first_value(data, "public_path", "path", "cdn_path"), "/api/v1/sync/")
        backend_path = normalize_path_value(first_value(data, "backend_path", "origin_path", "xhttp_path"), "/api/v1/sync/")
        method = normalize_xhttp_method(first_value(data, "method", "xhttp_method"))
        alpn = normalize_xhttp_alpn_value(first_value(data, "alpn", "xhttp_alpn"))
        egress_link = strip_outer_quotes(str(first_value(data, "egress_link", "outbound_link", "upstream_link") or "").strip())

        if not cdn_host or not re.fullmatch(r"[A-Za-z0-9._-]+\.[A-Za-z0-9._-]+", cdn_host):
            self.send_json(400, {"ok": False, "error": "bad_cdn_host"})
            return
        if not sni or not re.fullmatch(r"[A-Za-z0-9._-]+\.[A-Za-z0-9._-]+", sni):
            self.send_json(400, {"ok": False, "error": "bad_sni"})
            return
        if port < 1 or port > 65535:
            self.send_json(400, {"ok": False, "error": "bad_port"})
            return
        if egress_link and not egress_link.startswith("vless://"):
            self.send_json(400, {"ok": False, "error": "bad_egress_link"})
            return

        atomic_text(TRANSPORT_FILE, "xhttp\n")
        atomic_text(XHTTP_PATH_FILE, backend_path + "\n")
        atomic_text(XHTTP_METHOD_FILE, method + "\n")
        atomic_text(XHTTP_ALPN_FILE, alpn + "\n")
        atomic_text(CDN_XHTTP_ENABLED_FILE, "1\n")
        atomic_text(CDN_XHTTP_HOST_FILE, cdn_host + "\n")
        atomic_text(CDN_XHTTP_SNI_FILE, sni + "\n")
        atomic_text(CDN_XHTTP_PORT_FILE, str(port) + "\n")
        atomic_text(CDN_XHTTP_TAG_FILE, tag + "\n")
        atomic_text(CDN_XHTTP_PUBLIC_PATH_FILE, public_path + "\n")
        TRANSPORT = "xhttp"
        XHTTP_PATH = backend_path
        XHTTP_METHOD = method
        CDN_XHTTP_ENABLED = True
        CDN_XHTTP_HOST = cdn_host
        CDN_XHTTP_SNI = sni
        CDN_XHTTP_PORT = str(port)
        CDN_XHTTP_TAG = tag
        CDN_XHTTP_PUBLIC_PATH = public_path
        if egress_link:
            atomic_text(EGRESS_XRAY_LINK_FILE, egress_link + "\n")
        clear_egress = str(first_value(data, "clear_egress", "egress_off")).lower() in ("1", "true", "yes", "on")
        if not egress_link and clear_egress:
            try:
                os.remove(EGRESS_XRAY_LINK_FILE)
            except FileNotFoundError:
                pass

        save_users(users)
        atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_cdn_xhttp {now_ts()}\n")
        log_action("api_cdn_xhttp", f"cdn={cdn_host} sni={sni} path={public_path} backend_path={backend_path} egress={'on' if egress_link else ('off' if clear_egress else 'unchanged')}")
        self.send_json(200, {
            "ok": True,
            "transport": "xhttp",
            "backend_path": backend_path,
            "cdn_xhttp": {
                "host": cdn_host,
                "sni": sni,
                "port": port,
                "tag": tag,
                "public_path": public_path,
            },
            "egress": {
                "mode": "xray" if egress_link or read_first_line(EGRESS_XRAY_LINK_FILE) else "direct",
                "configured": bool(egress_link or read_first_line(EGRESS_XRAY_LINK_FILE)),
            },
            "restart": "requested",
        })

    def configure_transport(self, users, data):
        global TRANSPORT, XHTTP_PATH, XHTTP_METHOD
        raw = str(first_value(data, "mode", "transport")).strip().lower()
        if raw in ("xhttp", "on", "enable", "enabled"):
            mode = "xhttp"
        elif raw in ("ws", "off", "disable", "disabled", "websocket"):
            mode = "ws"
        else:
            self.send_json(400, {"ok": False, "error": "bad_mode"})
            return

        force = str(first_value(data, "force")).lower() in ("1", "true", "yes", "on")
        if mode == "ws" and not force:
            if enabled_from_file("mws_enabled.txt"):
                self.send_json(409, {"ok": False, "error": "mws_enabled_requires_xhttp"})
                return
            if CDN_XHTTP_ENABLED:
                self.send_json(409, {"ok": False, "error": "cdn_xhttp_requires_xhttp"})
                return

        # A JSON null or a missing key both mean "leave this param untouched".
        # first_value returns "" for a missing key and None for an explicit null;
        # only a non-empty string counts as a real supplied value. Validate every
        # supplied value BEFORE writing anything so the operation is all-or-nothing.
        def supplied(*names):
            v = first_value(data, *names)
            return v.strip() if isinstance(v, str) and v.strip() != "" else None

        path_value = supplied("xhttp_path", "path")
        method_value = supplied("method", "xhttp_method")
        alpn_value = supplied("alpn", "xhttp_alpn")

        new_path = normalize_path_value(path_value) if path_value is not None else None
        new_method = None
        if method_value is not None:
            new_method = method_value.upper()
            if new_method not in ("GET", "POST", "PUT"):
                self.send_json(400, {"ok": False, "error": "bad_method"})
                return
        new_alpn = normalize_xhttp_alpn_value(alpn_value) if alpn_value is not None else None

        changed = [f"mode={mode}"]
        if new_path is not None:
            atomic_text(XHTTP_PATH_FILE, new_path + "\n")
            XHTTP_PATH = new_path
            changed.append(f"path={new_path}")
        if new_method is not None:
            atomic_text(XHTTP_METHOD_FILE, new_method + "\n")
            XHTTP_METHOD = new_method
            changed.append(f"method={new_method}")
        if new_alpn is not None:
            atomic_text(XHTTP_ALPN_FILE, new_alpn + "\n")
            changed.append(f"alpn={new_alpn}")

        atomic_text(TRANSPORT_FILE, mode + "\n")
        TRANSPORT = mode
        atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_transport {now_ts()}\n")
        atomic_text(SUB_RESTART_REQUEST_FILE, f"api_transport {now_ts()}\n")
        log_action("api_transport", " ".join(changed))
        self.send_json(200, {
            "ok": True,
            "transport": {
                "mode": mode,
                "xhttp_path": XHTTP_PATH,
                "xhttp_uplink_method": XHTTP_METHOD,
            },
            "restart": "requested",
        })

    def configure_cdn_ws(self, users, data):
        global CDN_WS_ENABLED, CDN_WS_HOST, CDN_WS_SNI, CDN_WS_PORT, CDN_WS_TAG, CDN_WS_PATH
        disable = str(first_value(data, "off", "disable")).lower() in ("1", "true", "yes", "on")
        enabled_field = first_value(data, "enabled")
        if enabled_field != "" and str(enabled_field).lower() in ("0", "false", "no", "off"):
            disable = True

        if disable:
            atomic_text(CDN_WS_ENABLED_FILE, "0\n")
            CDN_WS_ENABLED = False
            atomic_text(SUB_RESTART_REQUEST_FILE, f"api_cdn_ws_off {now_ts()}\n")
            log_action("api_cdn_ws_off", "")
            self.send_json(200, {"ok": True, "cdn_ws": {"enabled": False}, "restart": "requested"})
            return

        host = normalize_host(first_value(data, "host", "cdn_host", "address"))
        sni = normalize_host(first_value(data, "sni", "server_name")) or host
        port = parse_int(first_value(data, "port", "cdn_port"), 443) or 443
        tag = strip_outer_quotes(str(first_value(data, "tag", "tag_suffix") or "CDN")).strip() or "CDN"
        # WS path keeps a leading slash but NO trailing slash (unlike the xhttp normalizer).
        raw_path = strip_outer_quotes(str(first_value(data, "path", "cdn_path") or "").strip())
        if not raw_path:
            path = "/xray"
        else:
            if not raw_path.startswith("/"):
                raw_path = "/" + raw_path
            path = raw_path.rstrip("/") or "/xray"

        if not host or not re.fullmatch(r"[A-Za-z0-9._-]+\.[A-Za-z0-9._-]+", host):
            self.send_json(400, {"ok": False, "error": "bad_cdn_host"})
            return
        if not re.fullmatch(r"[A-Za-z0-9._-]+\.[A-Za-z0-9._-]+", sni):
            self.send_json(400, {"ok": False, "error": "bad_sni"})
            return
        if port < 1 or port > 65535:
            self.send_json(400, {"ok": False, "error": "bad_port"})
            return

        atomic_text(CDN_WS_ENABLED_FILE, "1\n")
        atomic_text(CDN_WS_HOST_FILE, host + "\n")
        atomic_text(CDN_WS_SNI_FILE, sni + "\n")
        atomic_text(CDN_WS_PORT_FILE, str(port) + "\n")
        atomic_text(CDN_WS_TAG_FILE, tag + "\n")
        atomic_text(CDN_WS_PATH_FILE, path + "\n")
        CDN_WS_ENABLED = True
        CDN_WS_HOST = host
        CDN_WS_SNI = sni
        CDN_WS_PORT = str(port)
        CDN_WS_TAG = tag
        CDN_WS_PATH = path
        atomic_text(SUB_RESTART_REQUEST_FILE, f"api_cdn_ws {now_ts()}\n")
        log_action("api_cdn_ws", f"host={host} sni={sni} port={port} path={path}")
        self.send_json(200, {
            "ok": True,
            "cdn_ws": {"enabled": True, "host": host, "sni": sni, "port": port, "tag_suffix": tag, "path": path},
            "restart": "requested",
        })

    def configure_reality(self, users, data):
        global REALITY_ENABLED, REALITY_PORT, PUBLIC_REALITY_PORT, REALITY_SNI, REALITY_DEST, REALITY_PUBLIC_KEY, REALITY_SHORT_ID
        disable = str(first_value(data, "off", "disable")).lower() in ("1", "true", "yes", "on")
        enabled_field = first_value(data, "enabled")
        if enabled_field != "" and str(enabled_field).lower() in ("0", "false", "no", "off"):
            disable = True

        if disable:
            atomic_text(REALITY_ENABLED_FILE, "0\n")
            for path in (REALITY_PORT_FILE, REALITY_PUBLIC_PORT_FILE):
                try:
                    os.remove(path)
                except FileNotFoundError:
                    pass
            REALITY_ENABLED = False
            atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_reality_off {now_ts()}\n")
            atomic_text(SUB_RESTART_REQUEST_FILE, f"api_reality_off {now_ts()}\n")
            log_action("api_reality_off", "")
            self.send_json(200, {"ok": True, "reality": {"enabled": False}, "restart": "requested"})
            return

        existing_port = read_first_line(REALITY_PORT_FILE)
        port = parse_int(first_value(data, "port", "local_port"), parse_int(existing_port, None))
        if port is None or port < 1 or port > 65535:
            self.send_json(400, {"ok": False, "error": "bad_port"})
            return
        conflicts = {XRAY_PORT, API_PORT}
        try:
            conflicts.add(int(SUB_PORT))
        except (TypeError, ValueError):
            pass
        if port in conflicts:
            self.send_json(409, {"ok": False, "error": "port_conflict"})
            return
        public_port = parse_int(first_value(data, "public_port"), port) or port
        sni = normalize_host(first_value(data, "sni")) or REALITY_SNI or "proxy11.h1guro.ovh"
        if not re.fullmatch(r"[A-Za-z0-9.-]+\.[A-Za-z0-9.-]+", sni):
            self.send_json(400, {"ok": False, "error": "bad_sni"})
            return
        dest = strip_outer_quotes(str(first_value(data, "dest") or "").strip()) or (REALITY_DEST or f"{sni}:443")
        if ":" not in dest:
            dest = f"{dest}:443"

        # Only-if-absent keygen (never rotate live keys). bash ensure_reality_files
        # would also do this on restart; we do it here to return keys immediately.
        if not (read_first_line(REALITY_PRIVATE_KEY_FILE) and read_first_line(REALITY_PUBLIC_KEY_FILE)):
            priv, pub = reality_x25519()
            if not priv or not pub:
                self.send_json(500, {"ok": False, "error": "keygen_failed"})
                return
            atomic_text(REALITY_PRIVATE_KEY_FILE, priv + "\n")
            atomic_text(REALITY_PUBLIC_KEY_FILE, pub + "\n")
            for path in (REALITY_PRIVATE_KEY_FILE, REALITY_PUBLIC_KEY_FILE):
                try:
                    os.chmod(path, 0o600)
                except Exception:
                    pass
        if not read_first_line(REALITY_SHORT_ID_FILE):
            atomic_text(REALITY_SHORT_ID_FILE, secrets.token_hex(8) + "\n")

        atomic_text(REALITY_PORT_FILE, str(port) + "\n")
        atomic_text(REALITY_PUBLIC_PORT_FILE, str(public_port) + "\n")
        atomic_text(REALITY_SNI_FILE, sni + "\n")
        atomic_text(REALITY_DEST_FILE, dest + "\n")
        atomic_text(REALITY_ENABLED_FILE, "1\n")
        REALITY_ENABLED = True
        REALITY_PORT = port
        PUBLIC_REALITY_PORT = str(public_port)
        REALITY_SNI = sni
        REALITY_DEST = dest
        REALITY_PUBLIC_KEY = read_first_line(REALITY_PUBLIC_KEY_FILE)
        REALITY_SHORT_ID = read_first_line(REALITY_SHORT_ID_FILE)
        atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_reality {now_ts()}\n")
        atomic_text(SUB_RESTART_REQUEST_FILE, f"api_reality {now_ts()}\n")
        log_action("api_reality", f"port={port} public_port={public_port} sni={sni} dest={dest}")
        self.send_json(200, {
            "ok": True,
            "reality": {
                "enabled": True,
                "local_port": port,
                "public_port": public_port,
                "sni": sni,
                "dest": dest,
                "public_key": REALITY_PUBLIC_KEY,
                "short_id": REALITY_SHORT_ID,
            },
            "restart": "requested",
        })

    def configure_egress(self, users, data):
        link = strip_outer_quotes(str(first_value(data, "egress_link", "link", "outbound_link", "upstream_link") or "").strip())
        clear = str(first_value(data, "clear", "off", "egress_off")).lower() in ("1", "true", "yes", "on")

        if not link and clear:
            try:
                os.remove(EGRESS_XRAY_LINK_FILE)
            except FileNotFoundError:
                pass
            atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_egress_off {now_ts()}\n")
            log_action("api_egress_off", "")
            self.send_json(200, {"ok": True, "egress": {"mode": "direct", "configured": False}, "restart": "requested"})
            return

        if not link:
            self.send_json(400, {"ok": False, "error": "no_egress_link"})
            return
        if not link.startswith("vless://"):
            self.send_json(400, {"ok": False, "error": "bad_egress_link"})
            return
        try:
            direct_outbound_from_link(link)
        except Exception:
            self.send_json(400, {"ok": False, "error": "unparseable_egress_link"})
            return

        atomic_text(EGRESS_XRAY_LINK_FILE, link + "\n")
        atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_egress {now_ts()}\n")
        log_action("api_egress", "link set")
        self.send_json(200, {"ok": True, "egress": {"mode": "xray", "configured": True}, "restart": "requested"})

    def configure_domain(self, users, data):
        global REALITY_PUBLIC_HOST
        raw = strip_outer_quotes(str(first_value(data, "domain", "host") or "").strip())
        # accept full URLs / host:port and reduce to bare host
        raw = re.sub(r"^[a-zA-Z]+://", "", raw).split("/")[0].split(":")[0].strip().strip(".")
        if not raw or not re.fullmatch(r"[A-Za-z0-9.-]+\.[A-Za-z0-9.-]+", raw):
            self.send_json(400, {"ok": False, "error": "bad_domain"})
            return
        atomic_text(DOMAIN_FILE, raw + "\n")
        REALITY_PUBLIC_HOST = raw
        atomic_text(SUB_RESTART_REQUEST_FILE, f"api_domain {now_ts()}\n")
        log_action("api_domain", raw)
        self.send_json(200, {"ok": True, "domain": raw, "restart": "requested"})

    def handle_migrate(self, method, parts, data):
        sub = parts[1] if len(parts) > 1 else ""
        if method == "GET" and sub in ("", "status"):
            st = dict(MIGRATE_STATE)
            st["log"] = list(st.get("log") or [])[-120:]
            self.send_json(200, {"ok": True, "migrate": st})
            return
        if method == "POST" and sub == "probe":
            try:
                self.send_json(200, migrate_probe(data))
            except Exception as exc:
                self.send_json(502, {"ok": False, "error": str(exc)})
            return
        if method == "POST" and sub in ("start", "run"):
            with _MIGRATE_LOCK:
                if MIGRATE_STATE.get("running"):
                    self.send_json(409, {"ok": False, "error": "миграция уже идёт"})
                    return
                MIGRATE_STATE.clear()
                MIGRATE_STATE.update({"running": True, "phase": "fetch", "log": [], "done": 0, "total": 0,
                                      "imported": 0, "skipped": 0, "failed": 0, "result": None, "error": None,
                                      "source": str(data.get("source") or "")})
            log_action("migrate_start", str(data.get("source") or "") + " " + str(data.get("url") or ""))
            _threading.Thread(target=_migrate_worker, args=(dict(data),), daemon=True).start()
            self.send_json(202, {"ok": True, "message": "миграция запущена"})
            return
        self.send_json(404, {"ok": False, "error": "migrate_route_not_found"})

    def handle_shopbot(self, method, parts, data):
        sub = parts[1] if len(parts) > 1 else ""

        if method == "GET" and sub in ("", "status"):
            self.send_json(200, {"ok": True, "shopbot": shopbot_status()})
            return

        if method == "GET" and sub == "logs":
            self.send_json(200, {"ok": True, "logs": shopbot_logs()})
            return

        if method == "POST" and sub == "install":
            ok, out = shopbot_install()
            log_action("shopbot_install", "ok" if ok else "fail")
            self.send_json(200 if ok else 500, {
                "ok": ok,
                "log": out,
                "message": "бот установлен" if ok else "установка не удалась",
                "shopbot": shopbot_status(),
            })
            return

        if method in ("POST", "PATCH") and sub in ("", "config"):
            cfg = load_shopbot_cfg()
            for key in ("bot_token", "admin_ids", "cryptobot_token", "shop_name", "support_url", "channel_url"):
                if key in data:
                    cfg[key] = str(data.get(key) or "").strip()
            if "referral_percent" in data:
                cfg["referral_percent"] = max(0, min(100, parse_int(data.get("referral_percent"), 0)))
            if "stars_per_rub" in data:
                try:
                    cfg["stars_per_rub"] = max(0.01, float(data.get("stars_per_rub") or 0.7))
                except Exception:
                    pass
            if "autostart" in data:
                cfg["autostart"] = bool(data.get("autostart"))
            if isinstance(data.get("topup_amounts"), list):
                cfg["topup_amounts"] = [parse_int(x, 0) for x in data["topup_amounts"] if parse_int(x, 0) > 0]
            if isinstance(data.get("trial"), dict):
                t = data["trial"]
                cfg["trial"] = {
                    "enabled": bool(t.get("enabled", True)),
                    "days": parse_int(t.get("days"), 3),
                    "traffic_gb": parse_int(t.get("traffic_gb"), 0),
                    "devices": parse_int(t.get("devices"), 1),
                }
            if isinstance(data.get("plans"), list):
                plans = []
                for p in data["plans"]:
                    if not isinstance(p, dict):
                        continue
                    pid = str(p.get("id") or "").strip()
                    title = str(p.get("title") or "").strip()
                    if not pid or not title:
                        continue
                    plans.append({
                        "id": pid, "title": title,
                        "days": parse_int(p.get("days"), 30),
                        "traffic_gb": parse_int(p.get("traffic_gb"), 0),
                        "devices": parse_int(p.get("devices"), 0),
                        "price_rub": parse_int(p.get("price_rub"), 0),
                        "price_stars": parse_int(p.get("price_stars"), 0),
                    })
                if plans:
                    cfg["plans"] = plans
            save_shopbot_cfg(cfg)
            # живой процесс перечитывает конфиг только на рестарте — перепишем файлы,
            # чтобы после ручного рестарта подхватились новые значения
            if shopbot_installed():
                try:
                    shopbot_write_config(cfg)
                except Exception:
                    pass
            log_action("shopbot_config", "updated")
            self.send_json(200, {"ok": True, "shopbot": shopbot_status()})
            return

        if method == "POST" and sub in ("start", "restart"):
            if sub == "restart":
                shopbot_stop()
            ok, msg = shopbot_start()
            log_action("shopbot_" + sub, "ok" if ok else "fail")
            self.send_json(200 if ok else 400, {
                "ok": ok, "message": msg, "logs": shopbot_logs(60), "shopbot": shopbot_status(),
            })
            return

        if method == "POST" and sub == "stop":
            ok = shopbot_stop()
            log_action("shopbot_stop", "ok" if ok else "fail")
            self.send_json(200, {"ok": ok, "message": "бот остановлен" if ok else "не удалось остановить",
                                 "shopbot": shopbot_status()})
            return

        # Платные модули. Включает ТОЛЬКО разработчик командой /h1unlock в самом
        # боте (его tg id зашит) — владелец ноды через панель разблокировать не может.
        if sub == "webapp":
            if shopbot_license().get("webapp"):
                self.send_json(200, {"ok": True, "licensed": True, "url": "/webapp"})
                return
            self.send_json(402, {
                "ok": False,
                "error": "webapp_not_licensed",
                "message": SHOPBOT_WEBAPP_MSG,
                "contact": SHOPBOT_DEV_CONTACT,
                "price": SHOPBOT_WEBAPP_PRICE,
            })
            return

        if sub in ("admin", "admin-panel"):
            if shopbot_license().get("admin_panel"):
                self.send_json(200, {"ok": True, "licensed": True})
                return
            self.send_json(402, {
                "ok": False,
                "error": "admin_panel_not_licensed",
                "message": SHOPBOT_ADMIN_MSG,
                "contact": SHOPBOT_DEV_CONTACT,
                "price": SHOPBOT_ADMIN_PRICE,
            })
            return

        self.send_json(404, {"ok": False, "error": "not_found"})

    def handle_webdomains(self, method, parts, data):
        """Домены панели/подписки. Привязка идёт через биллинг (тот держит
        токен host-агента), нода лишь хранит список и применяет активный домен."""
        global REALITY_PUBLIC_HOST
        url, key = billing_config()
        try:
            my_ip = read_first_line(PUBLIC_IP_FILE).strip()
        except Exception:
            my_ip = ""
        if method == "GET":
            self.send_json(200, {"ok": True, "linked": bool(url and key),
                                 "domains": load_web_domains(), "api_port": API_PORT,
                                 "public_ip": my_ip,
                                 "sub_domain": read_first_line(DOMAIN_FILE).strip(),
                                 "panel_domain": read_first_line(PANEL_DOMAIN_FILE).strip()})
            return
        if not (url and key):
            self.send_json(400, {"ok": False, "error": "billing_not_linked"})
            return
        sid = self_server_id()
        if not sid:
            self.send_json(502, {"ok": False, "error": "self_server_unresolved"})
            return
        if method == "DELETE" and len(parts) >= 2:
            domain = urllib.parse.unquote(parts[1]).strip().lower()
            code, d = billing_request("POST", "/servers/" + sid + "/webdomain",
                                      {"action": "delete", "domain": domain}, timeout=40)
            if code != 200 and not (isinstance(d, dict) and d.get("ok")):
                self.send_json(code or 502, {"ok": False,
                    "error": (d.get("error") if isinstance(d, dict) else "agent_failed")})
                return
            lst = [x for x in load_web_domains() if str(x.get("domain")) != domain]
            save_web_domains(lst)
            if read_first_line(PANEL_DOMAIN_FILE).strip().lower() == domain:
                atomic_text(PANEL_DOMAIN_FILE, "")
            log_action("webdomain_delete", domain)
            self.send_json(200, {"ok": True, "domains": lst})
            return
        if method in ("POST", "PUT"):
            raw = strip_outer_quotes(str(first_value(data, "domain", "host") or "").strip())
            raw = re.sub(r"^[a-zA-Z]+://", "", raw).split("/")[0].split(":")[0].strip().strip(".").lower()
            if not raw or not re.fullmatch(r"[a-z0-9.-]+\.[a-z0-9.-]+", raw):
                self.send_json(400, {"ok": False, "error": "bad_domain"})
                return
            purpose = str(first_value(data, "purpose") or "both").strip().lower()
            if purpose not in ("panel", "sub", "both"):
                purpose = "both"
            ssl_on = _wd_bool(data.get("ssl", data.get("ssl_enabled")), True)
            force = _wd_bool(data.get("force_https"), False)
            payload = {"action": "create", "domain": raw, "ssl": ssl_on,
                       "force_https": force or ssl_on, "target_port": API_PORT, "purpose": purpose}
            code, d = billing_request("POST", "/servers/" + sid + "/webdomain", payload, timeout=150)
            if code != 200 or (isinstance(d, dict) and d.get("ok") is False):
                self.send_json(code or 502, {"ok": False,
                    "error": (d.get("error") if isinstance(d, dict) else "agent_failed")})
                return
            ssl_status = str((d or {}).get("ssl_status") or ("active" if ssl_on else "not_issued"))
            entry = {"domain": raw, "purpose": purpose, "ssl": ssl_on, "force_https": force,
                     "ssl_status": ssl_status, "ssl_error": str((d or {}).get("ssl_error") or ""),
                     "ts": now_ts()}
            lst = [x for x in load_web_domains() if str(x.get("domain")) != raw]
            lst.append(entry)
            save_web_domains(lst)
            # web_domains.json — источник истины для схемы ссылок (https+домен). НЕ трогаем
            # DOMAIN_FILE (это host xray-конфигов). panel_domain.txt — только для показа.
            if ssl_status == "active" and purpose in ("panel", "both"):
                atomic_text(PANEL_DOMAIN_FILE, raw + "\n")
            log_action("webdomain_add", raw + " ssl=" + ssl_status)
            self.send_json(200, {"ok": True, "domain": entry, "domains": lst})
            return
        self.send_json(404, {"ok": False, "error": "not_found"})

    def configure_update_settings(self, users, data):
        url_value = strip_outer_quotes(str(first_value(data, "url", "update_url") or "").strip())
        auto_value = first_value(data, "auto", "auto_update")
        changed = []
        if url_value != "":
            # Адрес обновлений зафиксирован — менять его нельзя (get_update_url
            # всё равно берёт FORCED_UPDATE_URL, так что молча «сохранять» вредно).
            log_action("api_update_url_denied", url_value[:120])
            self.send_json(403, {
                "ok": False,
                "error": "update_url_locked",
                "message": "Источник обновлений зафиксирован провайдером и не может быть изменён.",
            })
            return
        if auto_value != "":
            auto_on = str(auto_value).lower() in ("1", "true", "yes", "on", "enable", "enabled")
            atomic_text(AUTO_UPDATE_FILE, "1\n" if auto_on else "0\n")
            changed.append(f"auto={'1' if auto_on else '0'}")
        else:
            self.send_json(400, {"ok": False, "error": "nothing_to_update"})
            return
        log_action("api_update_settings", " ".join(changed))
        self.send_json(200, {
            "ok": True,
            "update": {
                "url": FORCED_UPDATE_URL,
                "url_locked": True,
                "auto": enabled_from_file(AUTO_UPDATE_FILE),
            },
        })

    def configure_sub_name(self, users, data):
        global SUB_NAME
        clear = str(first_value(data, "clear", "off")).lower() in ("1", "true", "yes", "on")
        name = strip_outer_quotes(str(first_value(data, "name", "title") or "").strip())
        if clear or not name:
            try:
                os.remove(SUB_NAME_FILE)
            except FileNotFoundError:
                pass
            SUB_NAME = ""
            atomic_text(SUB_RESTART_REQUEST_FILE, f"api_sub_name_clear {now_ts()}\n")
            log_action("api_sub_name_clear", "")
            self.send_json(200, {"ok": True, "subscription": {"name": ""}, "restart": "requested"})
            return
        name = re.sub(r"[\r\n\t]+", " ", name)[:64].strip()
        atomic_text(SUB_NAME_FILE, name + "\n")
        SUB_NAME = name
        atomic_text(SUB_RESTART_REQUEST_FILE, f"api_sub_name {now_ts()}\n")
        log_action("api_sub_name", name)
        self.send_json(200, {"ok": True, "subscription": {"name": name}, "restart": "requested"})

    def configure_panel_credentials(self, users, data):
        # Billing provisions the panel login. No xray/sub restart needed — creds
        # are checked live on /auth/login. If password is omitted we mint one and
        # return it once so billing can display it to the customer.
        clear = str(first_value(data, "clear", "off")).lower() in ("1", "true", "yes", "on")
        if clear:
            try:
                os.remove(PANEL_AUTH_FILE)
            except FileNotFoundError:
                pass
            log_action("panel_credentials_clear", "")
            self.send_json(200, {"ok": True, "credentials": {"set": False}})
            return
        username = strip_outer_quotes(str(first_value(data, "username", "login") or "").strip())
        if not username:
            self.send_json(400, {"ok": False, "error": "username_required"})
            return
        if len(username) > 64 or not re.match(r"^[A-Za-z0-9._@+-]+$", username):
            self.send_json(400, {"ok": False, "error": "bad_username"})
            return
        password = str(first_value(data, "password", "pass") or "")
        generated = False
        if not password:
            password = secrets.token_urlsafe(12)
            generated = True
        if len(password) < 6 or len(password) > 128:
            self.send_json(400, {"ok": False, "error": "bad_password"})
            return
        set_panel_credentials(username, password)
        log_action("panel_credentials_set", username)
        resp = {"ok": True, "credentials": {"set": True, "username": username}}
        if generated:
            resp["credentials"]["password"] = password
        self.send_json(200, resp)

    # ---- custom inbounds (3x-ui style) ----
    def _reserved_ports(self, exclude_id=None):
        if _panel_mode_active():
            used = {API_PORT}
        else:
            used = {XRAY_PORT, API_PORT}
            try:
                used.add(int(SUB_PORT))
            except (TypeError, ValueError):
                pass
            if REALITY_ENABLED:
                try:
                    used.add(int(REALITY_PORT))
                except (TypeError, ValueError):
                    pass
        for ib in load_custom_inbounds():
            if ib.get("id") == exclude_id:
                continue
            try:
                used.add(int(ib.get("port")))
            except (TypeError, ValueError):
                pass
        if wg_available():
            try:
                used.add(int(wg_port()))
            except (TypeError, ValueError):
                pass
        return used

    def _gen_client(self, proto, data):
        email = strip_outer_quotes(str(first_value(data, "email", "name") or "").strip()) or ("user-" + secrets.token_hex(3))
        if proto in ("vless", "vmess"):
            cid = strip_outer_quotes(str(first_value(data, "id", "uuid") or "").strip())
            if cid:
                try:
                    cid = str(uuid.UUID(cid))
                except Exception:
                    return None, "bad_uuid"
            else:
                cid = str(uuid.uuid4())
            client = {"id": cid, "email": email}
            flow = strip_outer_quotes(str(first_value(data, "flow") or "").strip())
            if flow:
                client["flow"] = flow
            return client, None
        if proto == "trojan":
            pwd = strip_outer_quotes(str(first_value(data, "password") or "").strip()) or secrets.token_urlsafe(12)
            return {"password": pwd, "email": email}, None
        if proto == "shadowsocks":
            pwd = strip_outer_quotes(str(first_value(data, "password") or "").strip()) or secrets.token_urlsafe(16)
            return {"password": pwd, "email": email}, None
        if proto in ("socks", "http"):
            noauth = str(first_value(data, "noauth", "no_auth") or "").strip().lower() in ("1", "true", "yes", "on")
            if noauth:
                return None, None
            user = strip_outer_quotes(str(first_value(data, "user", "username") or "").strip()) or email
            pwd = strip_outer_quotes(str(first_value(data, "password", "pass") or "").strip()) or secrets.token_urlsafe(10)
            return {"user": user, "pass": pwd, "email": user}, None
        return None, "bad_protocol"

    def serve_subscription(self, ident):
        target = None
        for u in load_users(prune=True):
            if u.get("banned") or u.get("disabled"):
                continue
            if str(u.get("uuid")) == ident or u.get("name") == ident:
                target = u
                break
        if target is None:
            self.send_text(404, "not found\n")
            return
        links = [l for l in user_all_links(target) if l]
        # Единая подписка: если это ГЛАВНАЯ панель (есть подключённые ноды) и запрос НЕ
        # scope=local — доклеиваем ссылки того же клиента со всех подключённых локаций.
        try:
            if not _sub_scope_local(self.path) and load_fed_links():
                fed = fetch_fed_sub_links(target)
                if fed:
                    links = _merge_sub_links(links, fed)
        except Exception:
            pass
        ua = self.headers.get("User-Agent", "")
        accept = self.headers.get("Accept", "")
        if "text/html" in accept and "mozilla" in ua.lower():
            self.send_text(200, render_sub_info_page(target, links, self.headers.get("Host", "")), "text/html; charset=utf-8")
            return
        blob = "\n".join(links)
        import base64 as _b
        payload = _b.b64encode(blob.encode("utf-8")).decode("ascii")
        self.send_text(200, payload, "text/plain; charset=utf-8")

    def list_inbounds(self):
        items = [custom_inbound_payload(s) for s in load_custom_inbounds()]
        wg = wg_inbound_payload()
        if wg:
            items.insert(0, wg)
        bs = bs_main_inbound_payload()
        if bs:
            items.insert(0, bs)
        self.send_json(200, {"ok": True, "inbounds": items})

    def fed_add_node(self, data):
        name = strip_outer_quotes(str(first_value(data, "name") or "").strip())
        url = strip_outer_quotes(str(first_value(data, "url", "api_url") or "").strip()).rstrip("/")
        token = strip_outer_quotes(str(first_value(data, "token", "api_token") or "").strip())
        if not name or not url or not token:
            self.send_json(400, {"ok": False, "error": "name_url_token_required"})
            return
        if not url.startswith(("http://", "https://")):
            self.send_json(400, {"ok": False, "error": "bad_url"})
            return
        node = {"id": "fn_" + secrets.token_hex(5), "name": name[:40], "url": url, "token": token}
        code, body = fed_node_json(node, "GET", "/status", timeout=10)
        if code != 200 or not isinstance(body, dict) or body.get("ok") is False:
            self.send_json(502, {"ok": False, "error": "node_check_failed_http_%s" % code})
            return
        nodes = load_fed_nodes()
        if any(n.get("url") == url for n in nodes):
            self.send_json(409, {"ok": False, "error": "node_exists"})
            return
        nodes.append(node)
        save_fed_nodes(nodes)
        log_action("api_fed_add", "%s %s" % (node["id"], url))
        self.send_json(200, {"ok": True, "node": fed_node_public(node)})

    def fed_delete_node(self, node_id):
        nodes = load_fed_nodes()
        new = [n for n in nodes if n.get("id") != node_id]
        if len(new) == len(nodes):
            self.send_json(404, {"ok": False, "error": "node_not_found"})
            return
        save_fed_nodes(new)
        log_action("api_fed_del", node_id)
        self.send_json(200, {"ok": True, "deleted": node_id})

    def fed_aggregate(self):
        out = []
        for node in load_fed_nodes():
            entry = dict(fed_node_public(node), online=False, clients=[], inbounds=[], counts={})
            code, st = fed_node_json(node, "GET", "/status", timeout=8)
            if code == 200 and isinstance(st, dict):
                entry["online"] = True
                entry["counts"] = st.get("clients") or {}
                entry["node_name"] = st.get("node_name") or node.get("name")
            code2, ib = fed_node_json(node, "GET", "/inbounds", timeout=8)
            if code2 == 200 and isinstance(ib, dict):
                entry["inbounds"] = ib.get("inbounds") or []
            code3, cl = fed_node_json(node, "GET", "/clients", timeout=12)
            if code3 == 200 and isinstance(cl, dict):
                entry["clients"] = cl.get("clients") or []
            out.append(entry)
        self.send_json(200, {"ok": True, "nodes": out})

    def fed_proxy(self, method, node_id, rest, data):
        node = next((n for n in load_fed_nodes() if n.get("id") == node_id), None)
        if not node:
            self.send_json(404, {"ok": False, "error": "node_not_found"})
            return
        subpath = "/" + "/".join(rest)
        try:
            q = urllib.parse.urlparse(self.path).query
        except Exception:
            q = ""
        if q:
            subpath += "?" + q
        raw_body = None
        if method in ("POST", "PUT", "PATCH", "DELETE") and data:
            raw_body = json.dumps(data, ensure_ascii=False).encode("utf-8")
        code, body, ctype = fed_node_request(node, method, subpath, raw_body, timeout=20)
        self.send_raw(code, body, ctype)

    def create_inbound(self, data):
        proto = str(first_value(data, "protocol") or "").strip().lower()
        if proto == "wireguard":
            self.create_wg_inbound(data)
            return
        if proto not in ("vless", "vmess", "trojan", "shadowsocks", "socks", "http", "dokodemo-door"):
            self.send_json(400, {"ok": False, "error": "bad_protocol"})
            return
        port = parse_int(first_value(data, "port"), None)
        if port is None or port < 1 or port > 65535:
            self.send_json(400, {"ok": False, "error": "bad_port"})
            return
        if port in self._reserved_ports():
            self.send_json(409, {"ok": False, "error": "port_conflict"})
            return
        # socks/http/dokodemo — простые tcp-протоколы без транспорта/tls.
        simple_proto = proto in ("socks", "http", "dokodemo-door")
        network = str(first_value(data, "network") or "tcp").strip().lower()
        if simple_proto:
            network = "tcp"
        if network not in ("tcp", "ws", "grpc", "xhttp", "httpupgrade"):
            self.send_json(400, {"ok": False, "error": "bad_network"})
            return
        security = str(first_value(data, "security") or "none").strip().lower()
        if simple_proto:
            security = "none"
        if security not in ("none", "tls", "reality"):
            self.send_json(400, {"ok": False, "error": "bad_security"})
            return
        if proto == "dokodemo-door":
            target_addr = strip_outer_quotes(str(first_value(data, "target_address", "address") or "").strip())
            target_port = parse_int(first_value(data, "target_port"), None)
            if not target_addr or target_port is None or target_port < 1 or target_port > 65535:
                self.send_json(400, {"ok": False, "error": "bad_target"})
                return

        stream = data.get("stream") if isinstance(data.get("stream"), dict) else {}
        if security == "reality" and not (stream.get("private_key") or stream.get("privateKey")):
            priv, pub = reality_x25519()
            if not priv:
                self.send_json(500, {"ok": False, "error": "keygen_failed"})
                return
            stream["private_key"] = priv
            stream["public_key"] = pub
            stream.setdefault("short_id", secrets.token_hex(8))
            stream.setdefault("dest", (stream.get("sni") or "www.microsoft.com") + ":443")

        spec = {
            "id": "ib_" + secrets.token_hex(5),
            "tag": strip_outer_quotes(str(first_value(data, "tag") or "").strip()) or f"custom-{proto}-{port}",
            "enabled": True,
            "protocol": proto,
            "port": port,
            "listen": "0.0.0.0",
            "network": network,
            "security": security,
            "stream": stream,
            "clients": [],
        }
        if proto == "shadowsocks":
            spec["method"] = str(first_value(data, "method") or "aes-256-gcm").strip()
        if proto == "dokodemo-door":
            spec["target_address"] = target_addr
            spec["target_port"] = target_port
            spec["target_network"] = str(first_value(data, "target_network") or "tcp,udp").strip()

        # Клиентов при создании инбаунда НЕ заводим — их создают только во вкладке «Клиенты»
        # (там же выбирают, в какие инбаунды завести). Инбаунд создаётся пустым.
        spec["clients"] = []

        with _INBOUND_LOCK:
            if port in self._reserved_ports():
                self.send_json(409, {"ok": False, "error": "port_conflict"})
                return
            items = load_custom_inbounds()
            items.append(spec)
            save_custom_inbounds(items)
        atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_inbound_create {now_ts()}\n")
        log_action("api_inbound_create", f"{proto}:{port} {spec['id']}")
        self.send_json(200, {"ok": True, "inbound": custom_inbound_payload(spec), "restart": "requested"})

    def create_wg_inbound(self, data):
        # WireGuard-сервер живёт на ХОСТЕ (host-агент, wg0), не в контейнере.
        # Юзер выбирает ОБЫЧНУЮ свободную аллокацию сервера как публичный UDP-порт;
        # host-агент DNAT'ит этот порт на wg0. Клиентов заводят во вкладке «Клиенты».
        import os as _os
        port = parse_int(first_value(data, "port"), None)
        if port is None or port < 1 or port > 65535:
            self.send_json(400, {"ok": False, "error": "bad_port"})
            return
        # порт должен быть свободной аллокацией этого сервера (как у обычных инбаундов)
        alloc = list_allocations()
        try:
            with _INBOUND_LOCK:
                if port in self._reserved_ports() or port not in (alloc.get("available") or []):
                    self.send_json(409, {"ok": False, "error": "port_conflict"})
                    return
                d = _node_data_dir()
                _os.makedirs(d, exist_ok=True)
                with open(_os.path.join(d, "wg_enabled.txt"), "w", encoding="utf-8") as f:
                    f.write("1")
                wg_set_port(port)
        except Exception:
            self.send_json(500, {"ok": False, "error": "wg_enable_failed"})
            return
        # Пере-провижн уже существующих WG-клиентов: teardown стёр их пиры/.conf,
        # а флаг wg остался — просим агент пересоздать пир против (нового) порта.
        try:
            for u in load_users(prune=False):
                if u.get("wg") and not u.get("banned") and not u.get("disabled"):
                    wg_request("add", str(u.get("uuid", "")), u.get("name"))
        except Exception:
            pass
        payload = wg_inbound_payload()
        if not payload:
            self.send_json(503, {"ok": False, "error": "wireguard_unavailable"})
            return
        log_action("api_inbound_create", "wireguard __wg__ :%d" % port)
        self.send_json(200, {"ok": True, "inbound": payload, "restart": "not_needed"})

    def delete_wg_inbound(self):
        # Удаление WG-инбаунда = выключить WG на ноде: хост-агент снимет DNAT и
        # уберёт всех пиров, порт-аллокация освободится. Клиенты остаются в списке,
        # но их WG-подключения перестанут работать (флаг wg висит, но обход снят).
        if not wg_available():
            self.send_json(404, {"ok": False, "error": "inbound_not_found"})
            return
        wg_teardown()
        log_action("api_inbound_delete", "wireguard __wg__")
        self.send_json(200, {"ok": True, "deleted": WG_INBOUND_ID, "restart": "not_needed"})

    def rename_bs_inbound(self, data):
        # БС-инбаунд — системный (реальный xray-инбаунд обхода), но имя-ярлык в панели
        # можно менять: храним override в файле, сам xray-тег и обход не трогаем.
        import os as _os
        tag = strip_outer_quotes(str(first_value(data, "tag", "name") or "").strip())
        if not tag:
            self.send_json(400, {"ok": False, "error": "bad_name"})
            return
        tag = tag[:60]
        if bs_main_inbound_payload() is None:
            self.send_json(404, {"ok": False, "error": "inbound_not_found"})
            return
        try:
            with open(_os.path.join(_node_data_dir(), "bs_inbound_name.txt"), "w", encoding="utf-8") as f:
                f.write(tag)
        except Exception:
            self.send_json(500, {"ok": False, "error": "save_failed"})
            return
        log_action("api_inbound_update", "bs rename")
        self.send_json(200, {"ok": True, "inbound": bs_main_inbound_payload(), "restart": "not_needed"})

    def update_inbound(self, iid, data):
        if iid == BS_MAIN_INBOUND_ID:
            self.rename_bs_inbound(data)
            return
        items = load_custom_inbounds()
        target = next((s for s in items if s.get("id") == iid), None)
        if target is None:
            self.send_json(404, {"ok": False, "error": "inbound_not_found"})
            return
        if first_value(data, "enabled") != "":
            target["enabled"] = str(first_value(data, "enabled")).lower() in ("1", "true", "yes", "on")
        new_port = parse_int(first_value(data, "port"), None)
        if new_port is not None:
            if new_port < 1 or new_port > 65535:
                self.send_json(400, {"ok": False, "error": "bad_port"})
                return
            if new_port in self._reserved_ports(exclude_id=iid):
                self.send_json(409, {"ok": False, "error": "port_conflict"})
                return
            target["port"] = new_port
        tag = strip_outer_quotes(str(first_value(data, "tag") or "").strip())
        if tag:
            target["tag"] = tag
        if isinstance(data.get("stream"), dict):
            merged = target.get("stream") if isinstance(target.get("stream"), dict) else {}
            merged.update(data["stream"])
            target["stream"] = merged
        save_custom_inbounds(items)
        atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_inbound_update {now_ts()}\n")
        log_action("api_inbound_update", iid)
        self.send_json(200, {"ok": True, "inbound": custom_inbound_payload(target), "restart": "requested"})

    def delete_inbound(self, iid):
        if iid == WG_INBOUND_ID:
            self.delete_wg_inbound()
            return
        items = load_custom_inbounds()
        new_items = [s for s in items if s.get("id") != iid]
        if len(new_items) == len(items):
            self.send_json(404, {"ok": False, "error": "inbound_not_found"})
            return
        save_custom_inbounds(new_items)
        atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_inbound_delete {now_ts()}\n")
        log_action("api_inbound_delete", iid)
        self.send_json(200, {"ok": True, "deleted": iid, "restart": "requested"})

    def add_inbound_client(self, iid, data):
        items = load_custom_inbounds()
        target = next((s for s in items if s.get("id") == iid), None)
        if target is None:
            self.send_json(404, {"ok": False, "error": "inbound_not_found"})
            return
        client, err = self._gen_client(str(target.get("protocol")), data)
        if err:
            self.send_json(400, {"ok": False, "error": err})
            return
        clients = target.get("clients") if isinstance(target.get("clients"), list) else []
        label = client.get("email")
        if any(isinstance(c, dict) and c.get("email") == label for c in clients):
            self.send_json(409, {"ok": False, "error": "client_exists"})
            return
        clients.append(client)
        target["clients"] = clients
        save_custom_inbounds(items)
        atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_inbound_client_add {now_ts()}\n")
        log_action("api_inbound_client_add", f"{iid} {label}")
        self.send_json(200, {"ok": True, "inbound": custom_inbound_payload(target), "restart": "requested"})

    def remove_inbound_client(self, iid, email):
        items = load_custom_inbounds()
        target = next((s for s in items if s.get("id") == iid), None)
        if target is None:
            self.send_json(404, {"ok": False, "error": "inbound_not_found"})
            return
        clients = target.get("clients") if isinstance(target.get("clients"), list) else []
        new_clients = [c for c in clients if not (isinstance(c, dict) and c.get("email") == email)]
        if len(new_clients) == len(clients):
            self.send_json(404, {"ok": False, "error": "client_not_found"})
            return
        target["clients"] = new_clients
        save_custom_inbounds(items)
        atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_inbound_client_del {now_ts()}\n")
        log_action("api_inbound_client_del", f"{iid} {email}")
        self.send_json(200, {"ok": True, "inbound": custom_inbound_payload(target), "restart": "requested"})

    def set_federation(self, data):
        api_url = strip_outer_quotes(first_value(data, "api_url", "url", "upstream_url")).rstrip("/")
        token = strip_outer_quotes(first_value(data, "token", "api_token", "upstream_token"))

        if not api_url.startswith(("http://", "https://")):
            self.send_json(400, {"ok": False, "error": "bad_upstream_url"})
            return
        if not token:
            self.send_json(400, {"ok": False, "error": "bad_upstream_token"})
            return

        atomic_text(UPSTREAM_API_URL_FILE, api_url + "\n")
        atomic_text(UPSTREAM_API_TOKEN_FILE, token + "\n")
        try:
            os.chmod(UPSTREAM_API_TOKEN_FILE, 0o600)
        except Exception:
            pass
        log_action("api_federation_set", api_url)
        self.send_json(200, {"ok": True, "federation": federation_payload()})

    def disable_federation(self):
        for path in (UPSTREAM_API_URL_FILE, UPSTREAM_API_TOKEN_FILE):
            try:
                os.remove(path)
            except FileNotFoundError:
                pass
            except Exception:
                pass
        log_action("api_federation_off", "")
        self.send_json(200, {"ok": True, "federation": federation_payload()})

    def create_client(self, users, data):
        name = str(first_value(data, "name")).strip()
        days = parse_int(first_value(data, "days"), None)
        try:
            traffic_limit = parse_limit_bytes(first_value(data, "traffic_limit_gb", "traffic_gb", "gb", "limit_gb"))
            device_limit = parse_device_limit_value(first_value(data, "device_limit", "devices", "device_count", "max_devices"))
        except ValueError as exc:
            self.send_json(400, {"ok": False, "error": str(exc)})
            return

        if not validate_name(name):
            self.send_json(400, {"ok": False, "error": "bad_name"})
            return
        if days is None or days <= 0:
            self.send_json(400, {"ok": False, "error": "bad_days"})
            return

        requested_uuid = str(first_value(data, "uuid", "client_id")).strip()
        if requested_uuid:
            try:
                client_uuid = str(uuid.UUID(requested_uuid))
            except Exception:
                self.send_json(400, {"ok": False, "error": "bad_uuid"})
                return
        else:
            client_uuid = str(uuid.uuid4())

        if upstream_enabled():
            payload = {"name": name, "days": days}
            if requested_uuid:
                payload["uuid"] = client_uuid
            if traffic_limit:
                payload["traffic_limit_gb"] = gb_from_bytes(traffic_limit)
            if device_limit:
                payload["device_limit"] = device_limit
            try:
                upstream_request("POST", "/clients", payload)
                synced = sync_users_from_upstream()
                user = find_user_by_name(synced, name)
                log_action("api_client_create_upstream", f"{name} days={days}")
                self.send_json(201, {"ok": True, "proxied": True, "client": client_payload(user) if user else None})
            except Exception as exc:
                log_action("api_upstream_create_failed", f"{name} {exc}")
                self.send_json(502, {"ok": False, "error": str(exc)})
            return

        if any(user.get("name") == name for user in users):
            self.send_json(409, {"ok": False, "error": "user_already_exists"})
            return
        if any(str(user.get("uuid")) == client_uuid for user in users):
            self.send_json(409, {"ok": False, "error": "uuid_already_exists"})
            return

        current = now_ts()
        user = {
            "name": name,
            "uuid": client_uuid,
            "created_at": current,
            "expires_at": current + days * 86400,
            "banned": False,
        }
        # Выбор каналов при создании: если поле channels пришло — клиент живёт ТОЛЬКО на них
        # (пустой список = ни одного логического канала, только кастомные инбаунды ниже).
        if data.get("channels") is not None:
            user["channels"] = [c for c in _parse_str_list(data.get("channels")) if c in ("main", "reality", "bs", "wscdn")]
        wg_on = (data.get("wg") is True) or str(data.get("wg")).lower() in ("1", "true", "yes", "on")
        if wg_on and wg_available():
            user["wg"] = True
        if traffic_limit:
            user["traffic_limit_bytes"] = traffic_limit
            user["traffic_reset_pending"] = True
        if device_limit:
            user["device_limit"] = device_limit
        users.append(user)
        save_users(users)

        # WireGuard: заявку host-агенту (пир на хосте) + короткое ожидание готового .conf.
        if user.get("wg"):
            wg_request("add", client_uuid, name)
            wg_wait_conf(client_uuid)

        # Кастомные инбаунды: заводим ЭТОГО ЖЕ клиента (тот же uuid, email=name) в выбранные.
        inbound_ids = _parse_str_list(data.get("inbound_ids") or data.get("inbounds"))
        added_inbounds = []
        if inbound_ids:
            items = load_custom_inbounds()
            dirty = False
            for spec in items:
                if str(spec.get("id")) not in inbound_ids:
                    continue
                proto = str(spec.get("protocol") or "vless")
                clients = spec.get("clients") if isinstance(spec.get("clients"), list) else []
                if any(isinstance(c, dict) and c.get("email") == name for c in clients):
                    continue
                client, err = self._gen_client(proto, {"email": name, "id": client_uuid})
                if err or not client:
                    continue
                clients.append(client)
                spec["clients"] = clients
                added_inbounds.append(spec.get("id"))
                dirty = True
            if dirty:
                save_custom_inbounds(items)
                atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_client_create_inbounds {now_ts()}\n")

        log_action("api_client_create", f"{name} days={days} ch={user.get('channels')} inb={added_inbounds}")
        self.send_json(201, {"ok": True, "client": client_payload(user), "inbounds": added_inbounds})

    def edit_client(self, users, name, data):
        if not validate_name(name):
            self.send_json(400, {"ok": False, "error": "bad_name"})
            return

        if upstream_enabled():
            payload = {}
            for key in ("new_name", "days", "set_days", "expires_at", "traffic_limit_gb", "traffic_gb", "gb", "limit_gb", "device_limit", "devices", "device_count", "max_devices"):
                value = first_value(data, key)
                if value != "":
                    payload[key] = value
            if not payload:
                self.send_json(400, {"ok": False, "error": "nothing_to_edit"})
                return
            try:
                upstream_request("PATCH", "/clients/" + urllib.parse.quote(name, safe=""), payload)
                synced = sync_users_from_upstream()
                target_name = str(payload.get("new_name") or name)
                target = find_user_by_name(synced, target_name)
                log_action("api_client_edit_upstream", f"{name} {payload}")
                self.send_json(200, {"ok": True, "proxied": True, "client": client_payload(target) if target else None})
            except Exception as exc:
                log_action("api_upstream_edit_failed", f"{name} {exc}")
                self.send_json(502, {"ok": False, "error": str(exc)})
            return

        target = None
        for user in users:
            if user.get("name") == name:
                target = user
                break

        if target is None:
            self.send_json(404, {"ok": False, "error": "user_not_found"})
            return

        changed = []
        new_name = str(first_value(data, "new_name")).strip()
        if new_name:
            if not validate_name(new_name):
                self.send_json(400, {"ok": False, "error": "bad_new_name"})
                return
            if any(user.get("name") == new_name and user is not target for user in users):
                self.send_json(409, {"ok": False, "error": "user_already_exists"})
                return
            target["name"] = new_name
            changed.append(f"name={new_name}")

        days = parse_int(first_value(data, "days"), None)
        if days is not None:
            if days <= 0:
                self.send_json(400, {"ok": False, "error": "bad_days"})
                return
            base = max(now_ts(), int(target.get("expires_at", now_ts())))
            target["expires_at"] = base + days * 86400
            changed.append(f"days=+{days}")

        set_days = parse_int(first_value(data, "set_days"), None)
        if set_days is not None:
            if set_days <= 0:
                self.send_json(400, {"ok": False, "error": "bad_set_days"})
                return
            target["expires_at"] = now_ts() + set_days * 86400
            changed.append(f"set_days={set_days}")

        expires_at = parse_int(first_value(data, "expires_at"), None)
        if expires_at is not None:
            if expires_at <= now_ts():
                self.send_json(400, {"ok": False, "error": "bad_expires_at"})
                return
            target["expires_at"] = expires_at
            changed.append(f"expires_at={expires_at}")

        traffic_value = first_value(data, "traffic_limit_gb", "traffic_gb", "gb", "limit_gb")
        if traffic_value != "":
            try:
                traffic_limit = parse_limit_bytes(traffic_value)
            except ValueError as exc:
                self.send_json(400, {"ok": False, "error": str(exc)})
                return
            # Сброс счётчика/квотного бана — ТОЛЬКО если лимит реально изменился. Иначе любое
            # сохранение (переименование/продление) обнуляло бы трафик: фронт всегда шлёт текущий
            # лимит в теле PATCH, а бэкенд не мог отличить «не менялось» от «поставили тот же».
            if traffic_limit != int(target.get("traffic_limit_bytes", 0) or 0):
                target["traffic_limit_bytes"] = traffic_limit
                target["traffic_reset_pending"] = True
                target.pop("quota_exceeded_at", None)
                changed.append(f"traffic_limit_gb={gb_from_bytes(traffic_limit)}")

        device_value = first_value(data, "device_limit", "devices", "device_count", "max_devices")
        if device_value != "":
            try:
                device_limit = parse_device_limit_value(device_value)
            except ValueError as exc:
                self.send_json(400, {"ok": False, "error": str(exc)})
                return
            target["device_limit"] = device_limit
            changed.append(f"device_limit={device_limit}")

        # Смена каналов (логических): main/reality/bs/wscdn — влияет только на генерацию ссылок.
        if data.get("channels") is not None:
            target["channels"] = [c for c in _parse_str_list(data.get("channels")) if c in ("main", "reality", "bs", "wscdn")]
            changed.append(f"channels={target['channels']}")

        # WireGuard вкл/выкл
        client_uuid = str(target.get("uuid", ""))
        if data.get("wg") is not None:
            wg_on = (data.get("wg") is True) or str(data.get("wg")).lower() in ("1", "true", "yes", "on")
            had = bool(target.get("wg"))
            if wg_on and not had and wg_available():
                target["wg"] = True
                wg_request("add", client_uuid, target.get("name"))
                wg_wait_conf(client_uuid)
                changed.append("wg=on")
            elif not wg_on and had:
                target["wg"] = False
                wg_request("del", client_uuid, target.get("name"))
                changed.append("wg=off")

        # Членство в кастомных инбаундах + перенос email при переименовании.
        final_name = target.get("name")
        inbound_dirty = False
        custom = load_custom_inbounds()
        if new_name and new_name != name:
            for spec in custom:
                for c in (spec.get("clients") or []):
                    if isinstance(c, dict) and c.get("email") == name:
                        c["email"] = final_name
                        inbound_dirty = True
        raw_inb = data.get("inbound_ids") if data.get("inbound_ids") is not None else data.get("inbounds")
        if raw_inb is not None:
            desired = set(_parse_str_list(raw_inb))
            for spec in custom:
                sid = str(spec.get("id"))
                proto = str(spec.get("protocol") or "vless")
                if proto in ("socks", "http", "dokodemo-door"):
                    continue
                clients = spec.get("clients") if isinstance(spec.get("clients"), list) else []
                has = any(isinstance(c, dict) and c.get("email") == final_name for c in clients)
                if sid in desired and not has:
                    client, err = self._gen_client(proto, {"email": final_name, "id": client_uuid})
                    if not err and client:
                        clients.append(client)
                        spec["clients"] = clients
                        inbound_dirty = True
                elif sid not in desired and has:
                    spec["clients"] = [c for c in clients if not (isinstance(c, dict) and c.get("email") == final_name)]
                    inbound_dirty = True
            changed.append(f"inbounds={sorted(desired)}")
        if inbound_dirty:
            save_custom_inbounds(custom)
            atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_client_edit_inbounds {now_ts()}\n")

        if not changed:
            self.send_json(400, {"ok": False, "error": "nothing_to_edit"})
            return

        save_users(users)
        log_action("api_client_edit", f"{name} {' '.join(changed)}")
        self.send_json(200, {"ok": True, "client": client_payload(target)})

    def ban_client(self, users, name, data):
        if not validate_name(name):
            self.send_json(400, {"ok": False, "error": "bad_name"})
            return

        if upstream_enabled():
            reason = str(first_value(data, "reason", "ban_reason")).strip()
            try:
                upstream_request("PATCH", "/clients/" + urllib.parse.quote(name, safe="") + "/ban", {"reason": reason})
                synced = sync_users_from_upstream()
                target = find_user_by_name(synced, name)
                log_action("api_client_ban_upstream", f"{name} {reason}")
                self.send_json(200, {"ok": True, "proxied": True, "client": client_payload(target) if target else None})
            except Exception as exc:
                log_action("api_upstream_ban_failed", f"{name} {exc}")
                self.send_json(502, {"ok": False, "error": str(exc)})
            return

        target = None
        for user in users:
            if user.get("name") == name:
                target = user
                break

        if target is None:
            self.send_json(404, {"ok": False, "error": "user_not_found"})
            return

        reason = str(first_value(data, "reason", "ban_reason")).strip()
        target["banned"] = True
        target["banned_at"] = now_ts()
        target["ban_reason"] = reason
        save_users(users)
        log_action("api_client_ban", f"{name} {reason}")
        self.send_json(200, {"ok": True, "client": client_payload(target)})

    def unban_client(self, users, name):
        if not validate_name(name):
            self.send_json(400, {"ok": False, "error": "bad_name"})
            return

        if upstream_enabled():
            try:
                upstream_request("PATCH", "/clients/" + urllib.parse.quote(name, safe="") + "/unban", {})
                synced = sync_users_from_upstream()
                target = find_user_by_name(synced, name)
                log_action("api_client_unban_upstream", name)
                self.send_json(200, {"ok": True, "proxied": True, "client": client_payload(target) if target else None})
            except Exception as exc:
                log_action("api_upstream_unban_failed", f"{name} {exc}")
                self.send_json(502, {"ok": False, "error": str(exc)})
            return

        target = None
        for user in users:
            if user.get("name") == name:
                target = user
                break

        if target is None:
            self.send_json(404, {"ok": False, "error": "user_not_found"})
            return

        target["banned"] = False
        target.pop("disabled", None)
        target.pop("banned_at", None)
        target.pop("ban_reason", None)
        save_users(users)
        log_action("api_client_unban", name)
        self.send_json(200, {"ok": True, "client": client_payload(target)})

    def delete_client(self, users, name):
        if not validate_name(name):
            self.send_json(400, {"ok": False, "error": "bad_name"})
            return

        if upstream_enabled():
            try:
                upstream_request("DELETE", "/clients/" + urllib.parse.quote(name, safe=""))
                sync_users_from_upstream()
                log_action("api_client_delete_upstream", name)
                self.send_json(200, {"ok": True, "proxied": True, "deleted": name})
            except Exception as exc:
                log_action("api_upstream_delete_failed", f"{name} {exc}")
                self.send_json(502, {"ok": False, "error": str(exc)})
            return

        new_users = [user for user in users if user.get("name") != name]
        if len(new_users) == len(users):
            self.send_json(404, {"ok": False, "error": "user_not_found"})
            return

        removed = [user for user in users if user.get("name") == name]
        removed_ids = [str(user.get("uuid", "")) for user in removed]
        save_users(new_users)
        # Освобождаем WG-пиры на хосте + убираем членство в кастомных инбаундах.
        for u in removed:
            if u.get("wg"):
                wg_request("del", str(u.get("uuid", "")), name)
        try:
            citems = load_custom_inbounds()
            cdirty = False
            for spec in citems:
                cl = spec.get("clients") if isinstance(spec.get("clients"), list) else []
                nc = [c for c in cl if not (isinstance(c, dict) and c.get("email") == name)]
                if len(nc) != len(cl):
                    spec["clients"] = nc
                    cdirty = True
            if cdirty:
                save_custom_inbounds(citems)
                atomic_text(XRAY_RESTART_REQUEST_FILE, f"api_client_delete_inbounds {now_ts()}\n")
        except Exception:
            pass
        if removed_ids:
            devices = load_devices()
            traffic = load_traffic()
            for client_id in removed_ids:
                devices.pop(client_id, None)
                traffic.pop(client_id, None)
            save_devices(devices)
            save_traffic(traffic)
        log_action("api_client_delete", name)
        self.send_json(200, {"ok": True, "deleted": name})

    def reset_client_limit(self, users, name, kind):
        if not validate_name(name):
            self.send_json(400, {"ok": False, "error": "bad_name"})
            return

        target = None
        for user in users:
            if user.get("name") == name:
                target = user
                break
        if target is None:
            self.send_json(404, {"ok": False, "error": "user_not_found"})
            return

        client_id = str(target.get("uuid", ""))
        if kind == "reset-traffic":
            traffic = load_traffic()
            row = traffic.get(client_id, {})
            if not isinstance(row, dict):
                row = {}
            traffic[client_id] = {
                "used_bytes": 0,
                "last_counter_bytes": int(row.get("last_counter_bytes", 0) or 0),
                "reset_pending": True,
                "updated_at": now_ts(),
            }
            save_traffic(traffic)
            target["traffic_reset_pending"] = True
            target.pop("quota_exceeded_at", None)
            save_users(users)
            log_action("api_client_reset_traffic", name)
        else:
            devices = load_devices()
            devices.pop(client_id, None)
            save_devices(devices)
            log_action("api_client_reset_devices", name)

        self.send_json(200, {"ok": True, "client": client_payload(target)})


class ReuseServer(ThreadingHTTPServer):
    allow_reuse_address = True


log_action("api_start", f"0.0.0.0:{API_PORT}")
try:
    server = ReuseServer(("0.0.0.0", API_PORT), Handler)
except OSError as exc:
    if exc.errno == 98:
        sys.stderr.write(
            f"port {API_PORT} is already in use.\n"
            "on Pterodactyl: используй порт, который реально выделен этому серверу\n"
            "(Configuration -> Allocations в панели). docker-proxy от wings уже сидит\n"
            "на не-выделенных портах внутри netns, поэтому bind() падает.\n"
        )
    else:
        sys.stderr.write(f"api bind failed on port {API_PORT}: {exc}\n")
    sys.exit(1)
server.serve_forever()
PY

    API_PID="$!"
    echo "$API_PID" > "$API_PID_FILE"
    echo "$API_BIND_PORT" > "$API_PORT_FILE"

    sleep 1

    if kill -0 "$API_PID" >/dev/null 2>&1; then
        echo "api started: 0.0.0.0:$API_BIND_PORT (http)"
        echo "url: http://$(read_public_ip):$API_BIND_PORT"
        echo "token: $TOKEN"
        echo "auth: Authorization: Bearer $TOKEN"
        log_action "api_start" "0.0.0.0:$API_BIND_PORT pid=$API_PID"
        auto_router_register &
        return 0
    fi

    echo "api failed to start"
    rm -f "$API_PID_FILE" "$API_PORT_FILE" >/dev/null 2>&1
    API_PID=""
    return 0
}

cmd_api() {
    local ACTION="${1:-}"
    local RESTART_PORT

    if validate_port "$ACTION"; then
        start_api_process "$ACTION"
        return 0
    fi

    case "$ACTION" in
        start|run)
            start_api_process "${2:-}"
            ;;
        stop)
            stop_api_process
            echo "api stopped"
            ;;
        restart)
            RESTART_PORT="${2:-}"
            if [ -z "$RESTART_PORT" ] && [ -f "$API_PORT_FILE" ]; then
                RESTART_PORT="$(cat "$API_PORT_FILE" 2>/dev/null)"
            fi
            stop_api_process keep
            start_api_process "$RESTART_PORT"
            ;;
        status)
            if api_is_running; then
                RUNNING_PORT="$(cat "$API_PORT_FILE" 2>/dev/null)"
                echo "api running: 0.0.0.0:${RUNNING_PORT:-unknown} (http)"
                echo "pid: $API_PID"
            else
                echo "api stopped"
            fi
            ;;
        token)
            echo "$(get_api_token)"
            ;;
        create)
            cmd_add "${2:-}" "${3:-}"
            ;;
        info)
            cmd_info "${2:-}"
            ;;
        edit|renew)
            cmd_renew "${2:-}" "${3:-}"
            ;;
        delete|del|remove)
            cmd_del "${2:-}"
            ;;
        ban)
            shift
            cmd_ban "$@"
            ;;
        unban)
            cmd_unban "${2:-}"
            ;;
        help|"")
            print_line
            echo "VPN API commands"
            print_line
            echo "vpn api PORT                 start API on 0.0.0.0:PORT"
            echo "vpn api start PORT           start API"
            echo "vpn api stop                 stop API"
            echo "vpn api restart [PORT]       restart API"
            echo "vpn api status               show status"
            echo "vpn api token                show token"
            echo "vpn api ban NAME [REASON]    disable client"
            echo "vpn api unban NAME           enable client"
            print_line
            echo "HTTP examples:"
            echo "GET    /clients"
            echo "GET    /info?name=NAME"
            echo "POST   /create {\"name\":\"test\",\"days\":30}"
            echo "PATCH  /edit {\"name\":\"test\",\"days\":15}"
            echo "PATCH  /clients/test/ban {\"reason\":\"chargeback\"}"
            echo "PATCH  /clients/test/unban"
            echo "DELETE /clients/test"
            echo "GET    /keys"
            echo "GET    /logs"
            echo "auth header: Authorization: Bearer TOKEN"
            print_line
            ;;
        *)
            echo "unknown api command: $ACTION"
            echo "type: vpn api help"
            ;;
    esac

    return 0
}

sub_is_running() {
    PID="${SUB_PID:-}"

    if [ -z "$PID" ] && [ -f "$SUB_PID_FILE" ]; then
        PID="$(cat "$SUB_PID_FILE" 2>/dev/null)"
    fi

    if [ -n "$PID" ] && kill -0 "$PID" >/dev/null 2>&1; then
        SUB_PID="$PID"
        return 0
    fi

    return 1
}

stop_sub_process() {
    KEEP_PORT="${1:-}"
    PID="${SUB_PID:-}"

    if [ -z "$PID" ] && [ -f "$SUB_PID_FILE" ]; then
        PID="$(cat "$SUB_PID_FILE" 2>/dev/null)"
    fi

    if [ -n "$PID" ] && kill -0 "$PID" >/dev/null 2>&1; then
        kill "$PID" >/dev/null 2>&1
        wait "$PID" 2>/dev/null
        log_action "sub_stop" "pid=$PID"
    fi

    SUB_PID=""
    rm -f "$SUB_PID_FILE" >/dev/null 2>&1
    if [ "$KEEP_PORT" != "keep" ]; then
        rm -f "$SUB_PORT_FILE" >/dev/null 2>&1
    fi
    return 0
}

