def sub_inbound_client_link(spec, client, host):
    # Компактный сериализатор ссылки клиента кастомного инбаунда для подписки
    # (порт-протоколы socks/http/dokodemo сюда не попадают — их отсекает sub_custom_links).
    proto = str(spec.get("protocol", "")).lower()
    port = spec.get("port")
    network = str(spec.get("network") or "tcp").lower()
    security = str(spec.get("security") or "none").lower()
    stream = spec.get("stream") if isinstance(spec.get("stream"), dict) else {}
    _email = str(client.get("email") or "").strip()
    _tag = str(spec.get("tag") or "").strip() or proto
    label = client_remark(_email or _tag, _tag if _email else "")
    params = {"type": network, "security": security}
    if network == "ws":
        params["path"] = stream.get("path") or "/"
        if stream.get("host"):
            params["host"] = stream["host"]
    elif network == "grpc":
        params["serviceName"] = stream.get("serviceName") or stream.get("service_name") or ""
    elif network in ("xhttp", "httpupgrade"):
        params["path"] = stream.get("path") or "/"
        if stream.get("host"):
            params["host"] = stream["host"]
        if network == "xhttp":
            params["mode"] = stream.get("mode") or "auto"
    if security == "tls":
        if stream.get("sni"):
            params["sni"] = stream["sni"]
        params["fp"] = stream.get("fp") or "chrome"
        if stream.get("alpn"):
            params["alpn"] = stream["alpn"]
    elif security == "reality":
        params["sni"] = stream.get("sni") or ""
        params["fp"] = stream.get("fp") or "chrome"
        params["pbk"] = stream.get("public_key") or stream.get("publicKey") or ""
        params["sid"] = stream.get("short_id") or stream.get("shortId") or ""
        params["spx"] = stream.get("spx") or "/"

    def _qs(extra=None):
        merged = dict(params)
        if extra:
            merged.update(extra)
        return urllib.parse.urlencode({k: v for k, v in merged.items() if v not in ("", None)})

    frag = urllib.parse.quote(label, safe="")
    if proto == "vless":
        flow = client.get("flow") or ""
        query = _qs({"encryption": "none", "flow": flow} if flow else {"encryption": "none"})
        return f"vless://{client.get('id','')}@{host}:{port}?{query}#{frag}"
    if proto == "trojan":
        return f"trojan://{client.get('password','')}@{host}:{port}?{_qs()}#{frag}"
    if proto == "vmess":
        body = {
            "v": "2", "ps": label, "add": host, "port": str(port), "id": client.get("id", ""),
            "aid": "0", "scy": "auto", "net": network, "type": "none",
            "host": stream.get("host", "") if network in ("ws", "xhttp", "httpupgrade") else "",
            "path": stream.get("path", "") if network in ("ws", "xhttp", "httpupgrade") else (stream.get("serviceName", "") if network == "grpc" else ""),
            "tls": "tls" if security == "tls" else "",
            "sni": stream.get("sni", "") if security == "tls" else "",
        }
        return f"vmess://{_sub_b64_json(body)}"
    if proto == "shadowsocks":
        method = spec.get("method") or client.get("method") or "aes-256-gcm"
        password = spec.get("password") or client.get("password") or ""
        userinfo = _sub_b64(f"{method}:{password}".encode("utf-8"))
        return f"ss://{userinfo}@{host}:{port}#{frag}"
    return ""


def sub_custom_links(name):
    out = []
    try:
        host = read_domain()
        for spec in _sub_load_custom_inbounds():
            if not isinstance(spec, dict) or not spec.get("enabled", True):
                continue
            if str(spec.get("protocol") or "").lower() in ("socks", "http", "dokodemo-door"):
                continue
            for c in (spec.get("clients") or []):
                if isinstance(c, dict) and c.get("email") == name:
                    link = sub_inbound_client_link(spec, c, host)
                    if link:
                        out.append(link)
    except Exception:
        pass
    return out


def make_links(user):
    # В подписку кладём ТОЛЬКО выбранные каналы + кастомные инбаунды, где заведён клиент.
    # remark каждой ссылки = «имя · способ».
    name = str(user.get("name", ""))
    client_id = str(user.get("uuid", ""))
    domain = read_domain()
    reality_host = REALITY_PUBLIC_HOST or domain
    reality_public_key = read_first(REALITY_PUBLIC_KEY_FILE)
    reality_short_id = read_first(REALITY_SHORT_ID_FILE)
    reality_sni = read_first(REALITY_SNI_FILE, "proxy11.h1guro.ovh")
    reality_public_port = read_first(REALITY_PUBLIC_PORT_FILE, "443")
    links = []
    if user_wants_channel(user, "main"):
        main_tag = urllib.parse.quote(client_remark(name, CHANNEL_LABELS["main"]), safe="")
        if TRANSPORT == "xhttp":
            security = "tls" if str(WS_PUBLIC_PORT) == "443" else "none"
            links.append(build_xhttp_vless(client_id, domain, WS_PUBLIC_PORT, XHTTP_PATH, domain, client_remark(name, CHANNEL_LABELS["main"]), security=security, sni=domain, method=XHTTP_METHOD))
        elif str(WS_PUBLIC_PORT) == "443":
            links.append(
                f"vless://{client_id}@{domain}:{WS_PUBLIC_PORT}"
                f"?type=ws&security=tls&sni={domain}&host={domain}&path=%2Fxray&encryption=none#{main_tag}"
            )
        else:
            links.append(
                f"vless://{client_id}@{domain}:{WS_PUBLIC_PORT}"
                f"?type=ws&security=none&host={domain}&path=%2Fxray&encryption=none#{main_tag}"
            )
    if CDN_WS_ENABLED and CDN_WS_HOST and user_wants_channel(user, "wscdn"):
        cdn_tag = urllib.parse.quote(client_remark(name, CHANNEL_LABELS["wscdn"]), safe="")
        links.append(
            f"vless://{client_id}@{CDN_WS_HOST}:{CDN_WS_PORT}"
            f"?security=tls&sni={CDN_WS_SNI}&type=ws&path={urllib.parse.quote(CDN_WS_PATH, safe='')}"
            f"&host={CDN_WS_SNI}&encryption=none#{cdn_tag}"
        )
    if CDN_XHTTP_ENABLED and CDN_XHTTP_HOST and user_wants_channel(user, "bs"):
        cdn_tag = client_remark(name, CHANNEL_LABELS["bs"])
        links.append(build_xhttp_vless(client_id, CDN_XHTTP_HOST, CDN_XHTTP_PORT, CDN_XHTTP_PUBLIC_PATH, CDN_XHTTP_SNI, cdn_tag, security="tls", sni=CDN_XHTTP_SNI, method=XHTTP_METHOD))
    if REALITY_ENABLED and user_wants_channel(user, "reality"):
        reality_tag = urllib.parse.quote(client_remark(name, CHANNEL_LABELS["reality"]), safe="")
        reality_flow = os.environ.get("REALITY_FLOW", "xtls-rprx-vision")
        flow_q = f"&flow={reality_flow}" if reality_flow else ""
        reality_spx = urllib.parse.quote(os.environ.get("REALITY_SPX") or "/", safe="")
        links.append(
            f"vless://{client_id}@{reality_host}:{reality_public_port}"
            f"?type=tcp&security=reality&pbk={reality_public_key}&fp={os.environ.get('REALITY_FP') or 'chrome'}"
            f"&sni={reality_sni}&sid={reality_short_id}&spx={reality_spx}"
            f"{flow_q}&encryption=none#{reality_tag}"
        )
    links.extend(sub_custom_links(name))
    return links


def current_subscription_url(identifier, request_host="", include_name=True):
    quoted = urllib.parse.quote(identifier, safe="")
    router_base = (os.environ.get("ROUTER_SUB_BASE", "") or "").strip().rstrip("/")
    if request_host:
        url = f"http://{request_host}/sub/{quoted}"
    elif router_base:
        url = f"{router_base}/{quoted}"
    else:
        url = f"http://{read_domain()}:{SUB_PORT}/sub/{quoted}"
    if include_name and SUB_NAME:
        url += "#" + urllib.parse.quote(SUB_NAME, safe="")
    return url


def link_name(parsed, params):
    fragment = urllib.parse.unquote(parsed.fragment or "")
    return fragment or parsed.hostname or "proxy"


def yaml_quote(value):
    return json.dumps(str(value), ensure_ascii=False)


def clash_proxy_from_link(link):
    parsed = urllib.parse.urlparse(link)
    params = urllib.parse.parse_qs(parsed.query)
    query = {key: values[0] if values else "" for key, values in params.items()}
    name = link_name(parsed, query)
    port = parsed.port or 443
    host = parsed.hostname or ""
    uuid = parsed.username or ""
    security = query.get("security", "none")
    network = query.get("type", "tcp")
    lines = [
        f"  - name: {yaml_quote(name)}",
        "    type: vless",
        f"    server: {yaml_quote(host)}",
        f"    port: {port}",
        f"    uuid: {yaml_quote(uuid)}",
        "    udp: true",
        f"    tls: {'true' if security in ('tls', 'reality') else 'false'}",
        f"    network: {yaml_quote(network)}",
    ]
    if query.get("flow"):
        lines.append(f"    flow: {yaml_quote(query.get('flow'))}")
    if query.get("sni"):
        lines.append(f"    servername: {yaml_quote(query.get('sni'))}")
    if network == "ws":
        lines.append("    ws-opts:")
        lines.append(f"      path: {yaml_quote(urllib.parse.unquote(query.get('path', '/')))}")
        if query.get("host"):
            lines.append("      headers:")
            lines.append(f"        Host: {yaml_quote(query.get('host'))}")
    if security == "reality":
        lines.append("    reality-opts:")
        lines.append(f"      public-key: {yaml_quote(query.get('pbk', ''))}")
        lines.append(f"      short-id: {yaml_quote(query.get('sid', ''))}")
        lines.append(f"    client-fingerprint: {yaml_quote(query.get('fp', 'chrome'))}")
    return "\n".join(lines)


def render_clash_config(links):
    names = [link_name(urllib.parse.urlparse(link), {}) for link in links]
    proxies = "\n".join(clash_proxy_from_link(link) for link in links)
    name_rows = "\n".join(f"      - {yaml_quote(name)}" for name in names)
    return (
        "mixed-port: 7890\n"
        "allow-lan: false\n"
        "mode: rule\n"
        "log-level: warning\n"
        "proxies:\n"
        f"{proxies}\n"
        "proxy-groups:\n"
        "  - name: H1Cloud\n"
        "    type: select\n"
        "    proxies:\n"
        f"{name_rows}\n"
        "rules:\n"
        "  - MATCH,H1Cloud\n"
    )


def sing_box_outbound_from_link(link):
    parsed = urllib.parse.urlparse(link)
    params = urllib.parse.parse_qs(parsed.query)
    query = {key: values[0] if values else "" for key, values in params.items()}
    outbound = {
        "type": "vless",
        "tag": link_name(parsed, query),
        "server": parsed.hostname or "",
        "server_port": parsed.port or 443,
        "uuid": parsed.username or "",
        "packet_encoding": "xudp",
    }
    network = query.get("type", "tcp")
    security = query.get("security", "none")
    if query.get("flow"):
        outbound["flow"] = query.get("flow")
    if network == "ws":
        outbound["transport"] = {
            "type": "ws",
            "path": urllib.parse.unquote(query.get("path", "/")),
            "headers": {"Host": query.get("host", parsed.hostname or "")},
        }
    if security in ("tls", "reality"):
        outbound["tls"] = {
            "enabled": True,
            "server_name": query.get("sni", parsed.hostname or ""),
            "utls": {"enabled": True, "fingerprint": query.get("fp", "chrome")},
        }
    if security == "reality":
        outbound.setdefault("tls", {"enabled": True})
        outbound["tls"]["reality"] = {
            "enabled": True,
            "public_key": query.get("pbk", ""),
            "short_id": query.get("sid", ""),
        }
    return outbound


def render_sing_box_config(links):
    outbounds = [sing_box_outbound_from_link(link) for link in links]
    outbounds.append({"type": "direct", "tag": "direct"})
    return json.dumps({
        "log": {"level": "warn"},
        "inbounds": [{
            "type": "mixed",
            "tag": "mixed-in",
            "listen": "127.0.0.1",
            "listen_port": 2080,
        }],
        "outbounds": outbounds,
        "route": {"final": outbounds[0]["tag"] if outbounds else "direct"},
    }, ensure_ascii=False, indent=2)


SUB_QR_LIB_B64 = os.environ.get("SUB_QR_B64", "")
SUB_PAGE_TEMPLATE_B64 = os.environ.get("SUB_PAGE_B64", "")


def _sub_usage(uuid):
    used = 0
    try:
        import os as _os
        tf = _os.path.join(_os.path.dirname(USERS_FILE), "traffic.json")
        with open(tf, "r", encoding="utf-8") as f:
            used = int((json.load(f).get(uuid, {}) or {}).get("used_bytes", 0) or 0)
    except Exception:
        used = 0
    last = 0
    try:
        for row in (load_devices().get(uuid, []) or []):
            if isinstance(row, dict):
                last = max(last, int(row.get("last_seen", 0) or 0))
    except Exception:
        pass
    return used, last


def _sub_config_badges(link):
    try:
        p = urllib.parse.urlparse(link)
        q = urllib.parse.parse_qs(p.query)
        proto = (p.scheme or "vless").upper()
        typ = (q.get("type", ["tcp"])[0] or "tcp").upper()
        sec = (q.get("security", ["none"])[0] or "none")
        badges = [{"t": proto, "cls": "proto"}, {"t": typ, "cls": "net"}]
        if sec and sec != "none":
            badges.append({"t": sec.upper(), "cls": "sec"})
        tag = urllib.parse.unquote(p.fragment or "") or (p.hostname or "")
        return badges, tag
    except Exception:
        return [{"t": "VLESS", "cls": "proto"}], ""


def render_client_page(user, links, request_host=""):
    identifier = str(user.get("uuid", ""))
    base_url = current_subscription_url(identifier, request_host, include_name=False)
    used, last_online = _sub_usage(identifier)
    limit = int(user.get("traffic_limit_bytes", 0) or 0)
    expires_at = int(user.get("expires_at", 0) or 0)
    expires_show = 0 if (expires_at > 0 and expires_at - int(time.time()) > 315360000) else expires_at
    if limit <= 0:
        status, kind = "Неограниченно", "on"
    elif used >= limit:
        status, kind = "Лимит исчерпан", "bad"
    else:
        status, kind = "Активна", "on"
    configs = []
    for link in links:
        badges, tag = _sub_config_badges(link)
        configs.append({"link": link, "badges": badges, "tag": tag})
    data = {
        "id": identifier,
        "email": str(user.get("name", "") or "—"),
        "status": status,
        "status_kind": kind,
        "used_bytes": used,
        "limit_bytes": limit,
        "last_online": last_online,
        "expires_at": expires_show,
        "node": SUB_NAME or NODE_NAME or "",
        "links": {"sub": base_url, "json": base_url + "/json", "clash": base_url + "/clash"},
        "configs": configs,
    }
    template = base64.b64decode(SUB_PAGE_TEMPLATE_B64).decode("utf-8")
    qrlib = base64.b64decode(SUB_QR_LIB_B64).decode("utf-8")
    payload = json.dumps(data, ensure_ascii=False).replace("</", "<\\/")
    return template.replace("/*__QRLIB__*/", qrlib).replace("__SUB_DATA__", payload)


class Handler(BaseHTTPRequestHandler):
    server_version = "H1CloudVPNSub/1.0"

    def end_headers(self):
        self.send_header("Access-Control-Allow-Origin", "*")
        self.send_header("Access-Control-Allow-Headers", "authorization,content-type")
        self.send_header("Access-Control-Allow-Methods", "GET,OPTIONS")
        if SUB_NAME:
            encoded_name = base64.b64encode(SUB_NAME.encode("utf-8")).decode("ascii")
            self.send_header("profile-title", "base64:" + encoded_name)
            self.send_header("Profile-Title", "base64:" + encoded_name)
        super().end_headers()

    def log_message(self, fmt, *args):
        return

    def send_text(self, status, text, content_type="text/plain; charset=utf-8"):
        body = text.encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", content_type)
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def send_json(self, status, data):
        self.send_text(status, json.dumps(data, ensure_ascii=False, indent=2), "application/json; charset=utf-8")

    def do_OPTIONS(self):
        self.send_response(204)
        self.end_headers()

    def do_GET(self):
        parsed = urllib.parse.urlparse(self.path)
        parts = [urllib.parse.unquote(p) for p in parsed.path.strip("/").split("/") if p]
        params = urllib.parse.parse_qs(parsed.query)

        if not parts or parts[0] == "health":
            self.send_json(200, {"ok": True, "service": "vpn-sub", "port": SUB_PORT})
            return

        if parts[0] == "sub":
            if len(parts) < 2:
                self.send_json(400, {"ok": False, "error": "uuid_required"})
                return
            identifier = parts[1]
            mode = parts[2] if len(parts) > 2 else "base64"
        else:
            identifier = parts[0]
            mode = parts[1] if len(parts) > 1 else "base64"

        user = find_user(identifier)
        if not user:
            try:
                sync_upstream_now(force=True)
            except Exception:
                pass
            user = find_user(identifier)

        if not user:
            self.send_json(404, {"ok": False, "error": "user_not_found"})
            return

        token = ""
        auth = self.headers.get("Authorization", "")
        if auth.startswith("Bearer "):
            token = auth.split(" ", 1)[1].strip()
        if not token:
            token = params.get("token", [""])[0]

        # New public subscription format: /sub/<client_uuid>.
        # Legacy /sub/<name>?token=... remains supported for old links.
        matched_uuid = str(user.get("uuid", "")) == identifier
        legacy_token = read_token()
        if not matched_uuid and (not legacy_token or token != legacy_token):
            self.send_json(401, {"ok": False, "error": "unauthorized"})
            return

        ok_device, device_error = register_device(user, self.headers, params, self.client_address[0])
        if not ok_device:
            self.send_json(403, device_error)
            return

        scope = params.get("scope", ["all"])[0]
        local_links = make_links(user)
        peer_links = [] if scope == "local" or mode == "local" else fetch_peer_links(user)
        links = merge_links(local_links, peer_links)
        raw = "\n".join(links) + "\n"

        if mode in ("raw", "local"):
            self.send_text(200, raw)
            return

        if mode in ("clash", "clash-meta", "yaml", "yml"):
            self.send_text(200, render_clash_config(links), "text/yaml; charset=utf-8")
            return

        if mode in ("sing-box", "singbox"):
            self.send_text(200, render_sing_box_config(links), "application/json; charset=utf-8")
            return

        if mode in ("page", "client", "cabinet", "qr"):
            self.send_text(200, render_client_page(user, links, self.headers.get("Host", "")), "text/html; charset=utf-8")
            return

        if mode == "json":
            expires_at = int(user.get("expires_at", 0))
            reality_links = [link for link in local_links if "security=reality" in link]
            ws_links = [link for link in local_links if "type=ws" in link and "security=reality" not in link]
            xhttp_links = [link for link in local_links if "type=xhttp" in link]
            cdn_ws_links = [link for link in local_links if CDN_WS_ENABLED and CDN_WS_HOST and f"@{CDN_WS_HOST}:" in link]
            cdn_xhttp_links = [link for link in local_links if CDN_XHTTP_ENABLED and CDN_XHTTP_HOST and f"@{CDN_XHTTP_HOST}:" in link]
            self.send_json(200, {
                "ok": True,
                "name": user.get("name"),
                "subscription_name": SUB_NAME,
                "expires_at": expires_at,
                "expires": datetime.datetime.fromtimestamp(expires_at).strftime("%Y-%m-%d %H:%M"),
                "links": {
                    "local": local_links,
                    "peers": peer_links,
                    "all": links,
                    **({"ws": ws_links[0]} if ws_links else {}),
                    **({"xhttp": xhttp_links[0]} if xhttp_links else {}),
                    **({"ws_cdn": cdn_ws_links[0]} if cdn_ws_links else {}),
                    **({"xhttp_cdn": cdn_xhttp_links[0]} if cdn_xhttp_links else {}),
                    **({"reality": reality_links[0]} if reality_links else {}),
                },
            })
            return

        ua = self.headers.get("User-Agent", "")
        accept = self.headers.get("Accept", "")
        if "text/html" in accept and "mozilla" in ua.lower():
            self.send_text(200, render_client_page(user, links, self.headers.get("Host", "")), "text/html; charset=utf-8")
            return
        encoded = base64.b64encode(raw.encode("utf-8")).decode("ascii")
        self.send_text(200, encoded + "\n")


class ReuseServer(ThreadingHTTPServer):
    allow_reuse_address = True


try:
    server = ReuseServer(("0.0.0.0", SUB_PORT), Handler)
except OSError as exc:
    if exc.errno == 98:
        sys.stderr.write(
            f"port {SUB_PORT} is already in use.\n"
            "on Pterodactyl используй только порт, который выделен серверу в панели.\n"
        )
    else:
        sys.stderr.write(f"sub bind failed on port {SUB_PORT}: {exc}\n")
    sys.exit(1)
server.serve_forever()
