        echo "subscription: running port=$(saved_sub_port)"
    else
        echo "subscription: stopped saved_port=$(saved_sub_port)"
    fi
    print_line
    cmd_ports
    return 0
}

sync_external_user_changes() {
    read_users_snapshot
    CURRENT_USERS_STATE="$USERS_SNAPSHOT"

    if [ -z "$USERS_STATE" ]; then
        USERS_STATE="$CURRENT_USERS_STATE"
        return 0
    fi

    if [ "$CURRENT_USERS_STATE" != "$USERS_STATE" ]; then
        restart_xray >/dev/null 2>&1
        sync_keys_file >/dev/null 2>&1
        remember_users_state
        echo "users synced from api"
    fi

    return 0
}

keep_api_alive() {
    local SAVED_PORT
    if [ -n "$API_PID" ] && ! kill -0 "$API_PID" >/dev/null 2>&1; then
        SAVED_PORT="$(cat "$API_PORT_FILE" 2>/dev/null)"
        API_PID=""
        if validate_port "$SAVED_PORT"; then
            echo "api stopped, trying to restart..."
            start_api_process "$SAVED_PORT" >/dev/null 2>&1
        fi
    fi

    return 0
}

keep_sub_alive() {
    local SAVED_PORT
    if [ -n "$SUB_PID" ] && ! kill -0 "$SUB_PID" >/dev/null 2>&1; then
        SAVED_PORT="$(cat "$SUB_PORT_FILE" 2>/dev/null)"
        SUB_PID=""
        if validate_port "$SAVED_PORT"; then
            echo "subscription stopped, trying to restart..."
            start_sub_process "$SAVED_PORT" >/dev/null 2>&1
        fi
    fi

    return 0
}

restart_api_if_running() {
    local SAVED_PORT
    if api_is_running; then
        SAVED_PORT="$(cat "$API_PORT_FILE" 2>/dev/null)"
        stop_api_process keep
        if validate_port "$SAVED_PORT"; then
            start_api_process "$SAVED_PORT" >/dev/null 2>&1
        fi
    fi
    return 0
}

restart_sub_if_running() {
    local SAVED_PORT
    if sub_is_running; then
        SAVED_PORT="$(cat "$SUB_PORT_FILE" 2>/dev/null)"
        stop_sub_process keep
        if validate_port "$SAVED_PORT"; then
            start_sub_process "$SAVED_PORT" >/dev/null 2>&1
        fi
    fi
    return 0
}

handle_cmd() {
    LINE="$1"

    if [ -z "$LINE" ]; then
        return 0
    fi

    set -- $LINE

    if [ "${1:-}" = "vpn" ]; then
        shift
    fi

    case "${1:-}" in
        help|"")
            cmd_help
            ;;
        add)
            cmd_add "${2:-}" "${3:-}" "${4:-}" "${5:-}"
            ;;
        del|delete|remove)
            cmd_del "${2:-}"
            ;;
        ban|block|disable)
            shift
            cmd_ban "$@"
            ;;
        unban|unblock|enable)
            cmd_unban "${2:-}"
            ;;
        list|users)
            cmd_list
            ;;
        info)
            cmd_info "${2:-}"
            ;;
        status)
            cmd_status
            ;;
        link)
            make_link "${2:-}" || true
            ;;
        limit|limits|quota)
            cmd_limit "${2:-}" "${3:-}" "${4:-}" "${5:-}"
            ;;
        keys)
            cmd_keys
            ;;
        logs)
            cmd_logs "${2:-}"
            ;;
        node)
            shift
            cmd_node "$*"
            ;;
        tag|tags|label|labels)
            shift
            cmd_tag "$@"
            ;;
        cdn|ws-cdn|manual)
            shift
            cmd_cdn "$@"
            ;;
        xhttp)
            shift
            cmd_xhttp "$@"
            ;;
        mws|mwscdn)
            shift
            cmd_mws "$@"
            ;;
        egress|relay|outbound)
            shift
            cmd_egress "$@"
            ;;
        transport)
            shift
            cmd_transport "$@"
            ;;
        join-token)
            cmd_join_token
            ;;
        join)
            cmd_join "${2:-}" "${3:-}" "${4:-}"
            ;;
        peer|peers)
            shift
            cmd_peer "$@"
            ;;
        federation|fed)
            shift
            cmd_federation "$@"
            ;;
        backup|backups)
            cmd_backup "${2:-}" "${3:-}"
            ;;
        stats|traffic)
            cmd_stats
            ;;
        update|upgrade)
            cmd_update "${2:-}" "${3:-}"
            ;;
        version|ver)
            cmd_version
            ;;
        doctor|diag|diagnose)
            cmd_doctor "${2:-}"
            ;;
        renew)
            cmd_renew "${2:-}" "${3:-}"
            ;;
        domain)
            cmd_domain "${2:-}"
            ;;
        ports)
            cmd_ports
            ;;
        reality)
            cmd_reality "${2:-}" "${3:-}" "${4:-}" "${5:-}"
            ;;
        api)
            cmd_api "${2:-}" "${3:-}" "${4:-}"
            ;;
        sub|subscription)
            shift
            cmd_sub "$@"
            ;;
        router)
            cmd_router "${2:-}" "${3:-}" "${4:-}" "${5:-}"
            ;;
        restart)
            restart_xray || true
            ;;
        stop|exit|quit)
            echo "stopping..."
            stop_api_process keep
            stop_sub_process keep
            stop_xray_process
            exit 0
            ;;
        *)
            echo "unknown command: ${1:-}"
            echo "type: vpn help"
            ;;
    esac

    return 0
}

check_expired_loop_tick() {
    read_users_snapshot
    BEFORE="$USERS_SNAPSHOT"
    prune_expired >/dev/null 2>&1
    read_users_snapshot
    AFTER="$USERS_SNAPSHOT"

    if [ "$BEFORE" != "$AFTER" ]; then
        restart_xray >/dev/null 2>&1
        sync_keys_file >/dev/null 2>&1
        remember_users_state
        log_action "expired_cleanup" "users pruned"
        echo "expired users cleaned"
    fi

    return 0
}

keep_xray_alive() {
    if [ -z "$XRAY_PID" ]; then
        echo "xray is not running, trying to start..."
        restart_xray >/dev/null 2>&1
        return 0
    fi

    if ! kill -0 "$XRAY_PID" >/dev/null 2>&1; then
        echo "xray stopped, trying to restart..."
        restart_xray >/dev/null 2>&1
    fi

    return 0
}

handle_xray_restart_request() {
    if [ ! -f "$XRAY_RESTART_REQUEST_FILE" ]; then
        return 0
    fi

    REQUEST_REASON="$(head -n 1 "$XRAY_RESTART_REQUEST_FILE" 2>/dev/null)"
    rm -f "$XRAY_RESTART_REQUEST_FILE" >/dev/null 2>&1
    echo "xray restart requested: ${REQUEST_REASON:-api}"
    restart_xray >/dev/null 2>&1
    sync_keys_file >/dev/null 2>&1
    return 0
}

# Мост для панели: API-процесс не может перезапустить subscription-сервер сам
# (тот держит свой снимок argv). Панель пишет этот файл-маркер, а серверный цикл
# перезапускает sub, чтобы новые ссылки (транспорт/reality/cdn-ws/имя) применились.
handle_sub_restart_request() {
    if [ ! -f "$SUB_RESTART_REQUEST_FILE" ]; then
        return 0
    fi

    REQUEST_REASON="$(head -n 1 "$SUB_RESTART_REQUEST_FILE" 2>/dev/null)"
    rm -f "$SUB_RESTART_REQUEST_FILE" >/dev/null 2>&1
    echo "subscription restart requested: ${REQUEST_REASON:-api}"
    sync_keys_file >/dev/null 2>&1
    restart_sub_if_running >/dev/null 2>&1
    restart_api_if_running >/dev/null 2>&1
    return 0
}

# Биллинг после оплаты LTE/обхода кладёт h1link-токен в PENDING_BS_LINK_FILE.
# Нода сама применяет его (apply_link_token настраивает CDN-XHTTP + рестарт xray),
# так что клиенту НЕ нужно вручную набирать "vpn update / vpn link" в консоли —
# инбаунд обхода появляется в веб-панели автоматически (как в 3x-ui).
handle_pending_bs_link_request() {
    if [ ! -f "$PENDING_BS_LINK_FILE" ]; then
        return 0
    fi
    LINK_TOKEN="$(head -n 1 "$PENDING_BS_LINK_FILE" 2>/dev/null | tr -d '[:space:]')"
    rm -f "$PENDING_BS_LINK_FILE" >/dev/null 2>&1
    case "$LINK_TOKEN" in
        h1link.*)
            echo "auto-applying LTE/CDN link from billing..."
            apply_link_token "$LINK_TOKEN" >/dev/null 2>&1 \
                && echo "LTE/CDN link applied" \
                || echo "LTE/CDN link apply failed"
            ;;
        *) ;;
    esac
    return 0
}

cleanup() {
    stop_api_process keep
    stop_sub_process keep
    stop_xray_process
    exit 0
}

# Создаёт стартовый скрипт для авто-перезапуска панелью, если его ещё нет.
# Нужен, чтобы Pterodactyl поднимал сервер сам после рестарта.
ensure_autorestart_file() {
    if [ -f "$AUTORESTART_FILE" ]; then
        return 0
    fi
    cat > "$AUTORESTART_FILE" <<'EOF'
#!/bin/bash
cd /home/container
export PATH="/home/container/.local/bin:$PATH"
bash start.sh
EOF
    chmod +x "$AUTORESTART_FILE" >/dev/null 2>&1
    return 0
}

start_server() {
    SERVER_MODE=1

    ensure_autorestart_file

    init_files
    if [ "$?" -ne 0 ]; then
        echo "init failed, console will stay alive"
        while true; do
            sleep 60
        done
    fi

    ensure_domain
    if [ "$?" -ne 0 ]; then
        echo "domain setup failed, console will stay alive"
        while true; do
            sleep 60
        done
    fi

    sync_upstream_tick norestart >/dev/null 2>&1

    build_config
    if [ "$?" -ne 0 ]; then
        echo "config build failed, console will stay alive"
        while true; do
            sleep 60
        done
    fi

    sync_keys_file >/dev/null 2>&1
    remember_users_state

    echo "H1Cloud VLESS — запуск сервисов..."

    start_xray_process
    if [ "$?" -ne 0 ]; then
        echo "xray start failed, console will stay alive"
    fi

    AUTO_API_PORT="$(auto_api_port)"
    if validate_port "$AUTO_API_PORT"; then
        start_api_process "$AUTO_API_PORT" >/dev/null 2>&1
    else
        echo "api autostart skipped: cannot choose port"
    fi

    if is_panel_mode; then
        echo "subscription server skipped (panel mode)"
    else
        AUTO_SUB_PORT="$(auto_sub_port)"
        if validate_port "$AUTO_SUB_PORT"; then
            start_sub_process "$AUTO_SUB_PORT" >/dev/null 2>&1
        else
            echo "subscription autostart skipped: cannot choose port"
        fi
    fi

    H1_PANEL_IP="$(read_public_ip 2>/dev/null)"
    [ -z "$H1_PANEL_IP" ] && H1_PANEL_IP="$(read_domain 2>/dev/null)"
    H1_PANEL_PORT="$(cat "$API_PORT_FILE" 2>/dev/null)"
    print_line
    echo "   H1CLOUD  VLESS  PANEL"
    echo "   Панель написал @welwesov"
    print_line
    if [ -n "$H1_PANEL_PORT" ]; then
        echo "   Панель :  http://${H1_PANEL_IP}:${H1_PANEL_PORT}/panel"
    else
        echo "   Панель :  запускается..."
    fi
    echo "   Вход   :  логин и пароль из личного кабинета H1Cloud"
    echo "   Нода   :  $(get_node_name)"
    echo "   Домен  :  $(read_domain)"
    if is_reality_enabled; then
        echo "   Reality:  ВКЛ (sni $(get_reality_sni))"
    else
        echo "   Reality:  выкл"
    fi
    print_line
    echo "   H1Cloud · https://t.me/h1cloudbot"
    echo "   Панель написал @welwesov"
    print_line

    LAST_CHECK=0
    LAST_FEDERATION_SYNC=0
    LAST_LIMIT_CHECK=0

    while true; do
        # Block here in the kernel until a command is typed OR POLL_INTERVAL
        # seconds pass. While blocked the process uses ~0% CPU. A typed line is
        # returned instantly (the timeout is only the max idle wait), so longer
        # POLL_INTERVAL does NOT make commands feel slower.
        LINE=""
        if IFS= read -r -t "$POLL_INTERVAL" LINE; then
            # Консоль только читает ввод, чтобы не жечь CPU. Команды убраны —
            # всё управление через веб-панель.
            if [ -n "$LINE" ]; then
                echo "   Управление сервером — только через веб-панель:"
                echo "   http://${H1_PANEL_IP}:${H1_PANEL_PORT}/panel"
            fi
        else
            # read failed. bash returns >128 when the -t timeout actually
            # elapsed (we already idled POLL_INTERVAL seconds — no throttling
            # needed). It returns <=128 (usually 1) on EOF / non-interactive
            # stdin, where read comes back INSTANTLY; without a sleep there this
            # loop spins flat out and pins the CPU (the 200% bug). Sleep the
            # same interval so an EOF stdin idles just as cheaply as a TTY.
            if [ "$?" -le 128 ]; then
                sleep "$POLL_INTERVAL"
            fi
        fi

        sync_external_user_changes

        printf -v NOW '%(%s)T' -1
        if [ $((NOW - LAST_CHECK)) -ge "$CHECK_INTERVAL" ]; then
            check_expired_loop_tick
            LAST_CHECK="$NOW"
        fi

        if [ $((NOW - LAST_FEDERATION_SYNC)) -ge "$FEDERATION_SYNC_INTERVAL" ]; then
            sync_upstream_tick
            LAST_FEDERATION_SYNC="$NOW"
        fi

        if [ $((NOW - LAST_LIMIT_CHECK)) -ge "$LIMIT_CHECK_INTERVAL" ]; then
            enforce_traffic_limits
            LAST_LIMIT_CHECK="$NOW"
        fi

        auto_update_tick
        handle_pending_bs_link_request
        handle_xray_restart_request
        handle_sub_restart_request
        keep_xray_alive
        keep_api_alive
        keep_sub_alive
    done
}

trap cleanup INT TERM

if [ "${1:-}" = "vpn" ]; then
    shift
    init_files
    if [ "$?" -ne 0 ]; then
        exit 0
    fi

    ensure_domain >/dev/null 2>&1
    build_config >/dev/null 2>&1
    sync_keys_file >/dev/null 2>&1
    remember_users_state
    handle_cmd "vpn $*"
    exit 0
else
    start_server
fi
